diffs.replacement:
{
  "name": "Re-Assess - פדגוגיה בעידן ה-AI",
  "description": "עוזר פדגוגי אינטראקטיבי המלווה מרצים בעיצוב מחדש של דרכי הערכה ומטלות בעידן הבינה המלאכותית."
}

export enum BloomLevel {
  Remember = 'זכירה',
  Understand = 'הבנה',
  Apply = 'יישום',
  Analyze = 'אנליזה',
  Evaluate = 'הערכה',
  Create = 'יצירה'
}

export interface BloomAnalysis {
  level: BloomLevel;
  description: string;
  isLowOrder: boolean;
}

export interface Skill {
  name: string;
  bloomLevel: BloomLevel;
  reasoning: string;
}

export interface RedesignStep {
  currentSkills: Skill[];
  suggestedSkills: Skill[];
  suggestedMethods: AssessmentMethod[];
  revisedAssignment: string;
}

export interface AssessmentMethod {
  skillName: string;
  method: string;
  type: 'FaceToFace' | 'AIEnabled';
  explanation: string;
}

export type AppMode = 'HOME' | 'TEST_AI' | 'REDESIGN';

import { GoogleGenAI, Type } from "@google/genai";
import { BloomLevel, Skill, AssessmentMethod } from "../types";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const testAiAssignment = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `ענה על המטלה הבאה כסטודנט מצטיין:\n\n${assignmentText}`,
    config: {
      temperature: 0.7,
    }
  });
  return response.text;
};

export const analyzeBloomTaxonomy = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נתח את המטלה הבאה לפי הטקסונומיה של בלום. זהה את המיומנויות הנדרשות והצע מיומנויות נוספות שכדאי להוסיף כדי להפוך את המטלה למורכבת ומשמעותית יותר.

    המטלה: ${assignmentText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          currentSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          },
          suggestedSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          }
        },
        required: ["currentSkills", "suggestedSkills"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateAssessmentStrategies = async (skills: Skill[]) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `עבור רשימת המיומנויות הבאה, הצע שיטת הערכה לכל אחת.
    שים לב לכלל הפדגוגי:
    1. מיומנויות מסדר חשיבה נמוך (זכירה, הבנה, יישום) - יש להציע הערכה פנים-אל-פנים (מבחן בעל פה, פרזנטציה, עבודה בכיתה) כדי למנוע שימוש ב-AI ולוודא הבנה אמיתית.
    2. מיומנויות מסדר חשיבה גבוה (אנליזה, הערכה, יצירה) - ניתן להציע שילוב של AI בתהליך הלמידה.

    המיומנויות: ${JSON.stringify(skills)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            skillName: { type: Type.STRING },
            method: { type: Type.STRING },
            type: { type: Type.STRING, enum: ['FaceToFace', 'AIEnabled'] },
            explanation: { type: Type.STRING }
          },
          required: ["skillName", "method", "type", "explanation"]
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const rephraseAssignment = async (originalText: string, targetSkills: Skill[]) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נסח מחדש את המטלה המקורית כך שתכלול ותדגיש את המיומנויות החדשות שנבחרו. שמור על רמה אקדמית גבוהה והנחיות ברורות.
    מטלה מקורית: ${originalText}
    מיומנויות יעד: ${JSON.stringify(targetSkills)}`,
  });
  return response.text;
};

import React from 'react';

interface LayoutProps {
  children: React.ReactNode;
  title: string;
  onBack?: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, title, onBack }) => {
  return (
    <div className="min-h-screen flex flex-col items-center p-4 md:p-8">
      <header className="w-full max-w-4xl mb-8 flex items-center justify-between">
        <div className="flex items-center gap-4">
          {onBack && (
