            <button 
              onClick={() => window.print()}
              className="flex-1 border border-indigo-600 text-indigo-600 py-3 rounded-lg font-bold hover:bg-indigo-50 transition-colors"
            >
              הדפסה / שמירה כ-PDF
            </button>
            <button 
              onClick={resetToHome}
              className="flex-1 bg-indigo-600 text-white py-3 rounded-lg font-bold hover:bg-indigo-700 transition-colors"
            >
              חזרה לדף הבית
            </button>
          </div>
        </div>
      )}
    </div>
  );

  return (
    <Layout 
      title={mode === 'HOME' ? 'Re-Assess' : mode === 'TEST_AI' ? 'בדיקה מול AI' : 'עיצוב מחדש'} 
      onBack={mode !== 'HOME' ? resetToHome : undefined}
    >
      <style>{`
        @media print {
          .no-print { display: none !important; }
        }
      `}</style>
      {mode === 'HOME' && renderHome()}
      {mode === 'TEST_AI' && renderTestAi()}
      {mode === 'REDESIGN' && renderRedesign()}

      {loading && (
        <div className="fixed inset-0 bg-black/20 backdrop-blur-sm flex items-center justify-center z-50">
          <div className="bg-white p-8 rounded-2xl shadow-2xl flex flex-col items-center gap-4 border-2 border-indigo-100">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-bold text-indigo-900">העוזר הפדגוגי מעבד נתונים ומנסח משימה...</p>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

export enum BloomLevel {
  Remember = 'זכירה',
  Understand = 'הבנה',
  Apply = 'יישום',
  Analyze = 'אנליזה',
  Evaluate = 'הערכה',
  Create = 'יצירה'
}

export interface BloomAnalysis {
  level: BloomLevel;
  description: string;
  isLowOrder: boolean;
}

export interface Skill {
  name: string;
  bloomLevel: BloomLevel;
  reasoning: string;
}

export interface RedesignStep {
  currentSkills: Skill[];
  suggestedSkills: Skill[];
  suggestedMethods: AssessmentMethod[];
  revisedAssignment: string;
}

export interface AssessmentMethod {
  skills: string[]; // Multiple skills covered by one method
  method: string;
  type: 'FaceToFace' | 'AIEnabled';
  explanation: string;
}

export type AppMode = 'HOME' | 'TEST_AI' | 'REDESIGN';

import { GoogleGenAI, Type } from "@google/genai";
import { BloomLevel, Skill, AssessmentMethod } from "../types";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const testAiAssignment = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `ענה על המטלה הבאה כסטודנט מצטיין:\n\n${assignmentText}`,
    config: {
      temperature: 0.7,
    }
  });
  return response.text;
};

export const analyzeBloomTaxonomy = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נתח את המטלה הבאה לפי הטקסונומיה של בלום. 
    עליך לזהות את המיומנויות הנדרשות במשימה הנוכחית ולהציע הרחבות.

    כלל פדגוגי מחייב: למידה משמעותית היא היררכית. הניתוח חייב לכלול תמיד את רמות ה"זכירה" (Remember) וה"הבנה" (Understand) כבסיס הידע הכרחי למטלה, אלא אם כן באופן מובהק ונדיר המטלה אינה דורשת שום בסיס ידע או הבנה של חומר. 

    אנא זהה מיומנויות אלו גם אם אינן מוצהרות מפורשות במטלה המקורית, שכן הן התנאי המקדים לביצועה.

    המטלה: ${assignmentText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          currentSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          },
          suggestedSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          }
        },
        required: ["currentSkills", "suggestedSkills"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateAssessmentStrategies = async (skills: Skill[]) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `עבור רשימת המיומנויות הבאה, בנה תוכנית הערכה מובנית ויעילה.

    כללים מחייבים:
    1. סדר: הצג את שיטות ההערכה לפי הסדר של הטקסונומיה של בלום (מהרמה הנמוכה "זכירה" ועד הרמה הגבוהה ביותר שנבחרה).
    2. איחוד: במידה וניתן לאחד מספר מיומנויות תחת אותה שיטת הערכה (למשל: שיחה פנים אל פנים שמכסה גם "זכירה" וגם "הבנה"), אגד אותן תחת סעיף אחד. המטרה היא מערך הערכה פשוט וקל לביצוע.
    3. כלל פדגוגי AI:
       - מיומנויות מסדר חשיבה נמוך (זכירה, הבנה, יישום) - חובה להציע הערכה פנים-אל-פנים.
       - מיומנויות מסדר חשיבה גבוה (אנליזה, הערכה, יצירה) - ניתן לשלב AI בתהליך.

    המיומנויות שנבחרו: ${JSON.stringify(skills)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            skills: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "שמות המיומנויות שהשיטה הזו בודקת"
            },
            method: { type: Type.STRING },
            type: { type: Type.STRING, enum: ['FaceToFace', 'AIEnabled'] },
            explanation: { type: Type.STRING }
          },
          required: ["skills", "method", "type", "explanation"]
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const rephraseAssignment = async (originalText: string, targetSkills: Skill[], strategies: AssessmentMethod[]) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נסח מחדש את המטלה המקורית כך שתהיה מטלה אקדמית שלמה, מורכבת וברורה לסטודנט.

    המטלה החדשה חייבת לשלב בתוכה באופן אינטגרלי ומפורש את שיטות ההערכה שנבחרו. 
    המטרה היא שהסטודנט יראה מסלול למידה והערכה אחד, שבו חלק מהשלבים מתבצעים מול AI וחלק מול המרצה (פנים אל פנים).

    עקוב אחר סדר הפעולות בתוכנית ההערכה.

    מטלה מקורית: ${originalText}
    מיומנויות שנבחרו: ${JSON.stringify(targetSkills)}
    שיטות הערכה וביצוע מאוגדות: ${JSON.stringify(strategies)}`,
  });
  return response.text;
};

export const askFollowUpQuestion = async (
  context: { originalText: string, revisedTask: string, strategies: AssessmentMethod[] },
  question: string,
  history: { role: 'user' | 'model', text: string }[]
) => {
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `אתה עוזר פדגוגי מומחה. המרצה בנה איתך מערך הערכה חדש הכולל מטלה מעודכנת ושיטות הערכה מאוגדות. 
      ענה על שאלות המרצה, הצע שיפורים פדגוגיים, או עדכן את המטלה במידת הצורך לפי בקשותיו. שמור על טון מקצועי ומסייע.
      הקשר נוכחי:
      מטלה מקורית: ${context.originalText}
      מטלה מעודכנת: ${context.revisedTask}
      שיטות הערכה: ${JSON.stringify(context.strategies)}`,
    }
  });

  const response = await chat.sendMessage({ message: question });
  return response.text;
};

import React, { useState, useRef, useEffect } from 'react';
import Layout from './components/Layout';
import { AppMode, BloomLevel, Skill, AssessmentMethod } from './types';
import { 
  testAiAssignment, 
  analyzeBloomTaxonomy, 
  generateAssessmentStrategies, 
  rephraseAssignment,
  askFollowUpQuestion
} from './services/geminiService';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('HOME');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);

  // State for AI Test
  const [assignmentText, setAssignmentText] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [lecturerFeedback, setLecturerFeedback] = useState('');
  const [score, setScore] = useState<number | null>(null);

  // State for Redesign
  const [bloomAnalysis, setBloomAnalysis] = useState<{currentSkills: Skill[], suggestedSkills: Skill[]} | null>(null);
  const [selectedSkills, setSelectedSkills] = useState<Skill[]>([]);
  const [strategies, setStrategies] = useState<AssessmentMethod[]>([]);
  const [revisedTask, setRevisedTask] = useState('');

  // State for Follow-up Chat
  const [followUpQuestion, setFollowUpQuestion] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const handleTestAi = async () => {
    if (!assignmentText.trim()) return;
    setLoading(true);
    try {
      const res = await testAiAssignment(assignmentText);
      setAiResponse(res || 'לא התקבלה תשובה');
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בבדיקת המטלה');
    } finally {
      setLoading(false);
    }
  };

  const startRedesign = async (initialText?: string) => {
    const textToAnalyze = initialText || assignmentText;
    if (!textToAnalyze.trim()) {
      alert('אנא הזן את הנחיית המטלה');
      return;
    }

    setBloomAnalysis(null);
    setStrategies([]);
    setRevisedTask('');
    setChatHistory([]);

    setAssignmentText(textToAnalyze);
    setMode('REDESIGN');
    setLoading(true);
    try {
      const analysis = await analyzeBloomTaxonomy(textToAnalyze);
      setBloomAnalysis(analysis);
      setSelectedSkills(analysis.currentSkills);
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בניתוח המטלה. וודא שהמטלה ברורה ומפורטת מספיק.');
    } finally {
      setLoading(false);
    }
  };

  const handleSkillToggle = (skill: Skill) => {
    setSelectedSkills(prev => 
      prev.some(s => s.name === skill.name)
        ? prev.filter(s => s.name !== skill.name)
        : [...prev, skill]
    );
  };

  const handleProposeStrategies = async () => {
    if (selectedSkills.length === 0) {
      alert('אנא בחר לפחות מיומנות אחת להערכה');
      return;
    }
    setLoading(true);
    try {
      const strategiesRes = await generateAssessmentStrategies(selectedSkills);
      setStrategies(strategiesRes);
      const rephrased = await rephraseAssignment(assignmentText, selectedSkills, strategiesRes);
      setRevisedTask(rephrased);
      setStep(3);
    } catch (error) {
      console.error(error);
      alert('שגיאה בהצעת אסטרטגיות');
    } finally {
      setLoading(false);
    }
  };

  const handleFollowUp = async () => {
    if (!followUpQuestion.trim()) return;
    const q = followUpQuestion;
    setFollowUpQuestion('');
    setChatHistory(prev => [...prev, { role: 'user', text: q }]);

    setLoading(true);
    try {
      const response = await askFollowUpQuestion(
        { originalText: assignmentText, revisedTask, strategies },
        q,
        chatHistory
      );
      setChatHistory(prev => [...prev, { role: 'model', text: response || '' }]);
    } catch (error) {
      console.error(error);
      alert('שגיאה בתקשורת עם העוזר הפדגוגי');
    } finally {
      setLoading(false);
    }
  };

  const resetToHome = () => {
    setMode('HOME');
    setStep(1);
    setAssignmentText('');
    setAiResponse('');
    setLecturerFeedback('');
    setScore(null);
    setBloomAnalysis(null);
    setSelectedSkills([]);
    setStrategies([]);
    setRevisedTask('');
    setChatHistory([]);
  };

  const renderHome = () => (
    <div className="flex flex-col items-center gap-8 py-12">
      <div className="text-center space-y-4">
        <h2 className="text-4xl font-bold text-gray-800">איך המטלה שלך נראית בעידן ה-AI?</h2>
        <p className="text-xl text-gray-600 max-w-2xl">
          הצטרפו לתהליך עיצוב מחדש של דרכי הערכה אקדמיות. וודאו שהסטודנטים שלכם באמת לומדים ומפגינים הבנה עמוקה.
        </p>
      </div>
      <div className="grid md:grid-cols-2 gap-6 w-full max-w-3xl">
        <button 
          onClick={() => { setMode('TEST_AI'); setStep(1); }}
          className="bg-white border-2 border-indigo-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-indigo-400 transition-all text-right group"
        >
          <div className="bg-indigo-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
            </svg>
          </div>
          <h3 className="text-2xl font-bold text-gray-800 mb-2">בדוק מול ה-AI</h3>
          <p className="text-gray-600">ראה כיצד הבינה המלאכותית פותרת את המטלה הקיימת שלך כיום.</p>
        </button>

        <button 
          onClick={() => { setMode('REDESIGN'); setStep(1); }}
          className="bg-white border-2 border-green-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-green-400 transition-all text-right group"
        >
          <div className="bg-green-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-green-600 group-hover:text-white transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
            </svg>
          </div>
          <h3 className="text-2xl font-bold text-gray-800 mb-2">עיצוב משימה מחדש</h3>
          <p className="text-gray-600">נתח את המיומנויות במטלה ושדרג אותן לפי הטקסונומיה של בלום.</p>
        </button>
      </div>
    </div>
  );

  const renderTestAi = () => (
    <div className="space-y-6">
      {step === 1 ? (
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <label className="block text-lg font-semibold mb-3">העתק לכאן את הנחיית המטלה המקורית:</label>
          <textarea 
            value={assignmentText}
            onChange={(e) => setAssignmentText(e.target.value)}
            className="w-full h-48 p-4 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
            placeholder="למשל: כתוב חיבור של 500 מילים על הגורמים למהפכה התעשייתית..."
          />
          <button 
            onClick={handleTestAi}
            disabled={loading || !assignmentText}
            className="mt-4 w-full bg-indigo-600 text-white py-3 rounded-lg font-bold hover:bg-indigo-700 disabled:bg-gray-400 transition-colors"
          >
            {loading ? 'הבינה המלאכותית כותבת תשובה...' : 'בדוק כיצד ה-AI עונה'}
          </button>
        </div>
      ) : (
        <div className="space-y-6">
          <div className="bg-blue-50 p-6 rounded-xl border border-blue-200">
            <h3 className="font-bold text-blue-900 mb-2">תשובת הבינה המלאכותית:</h3>
            <div className="text-gray-800 whitespace-pre-wrap leading-relaxed">{aiResponse}</div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
            <h3 className="font-bold text-gray-800 mb-4 text-xl">הערכת המרצה לתשובה</h3>
            <div className="space-y-4">
              <div>
                <label className="block mb-2 font-medium">ציון (0-100):</label>
                <input 
                  type="number" 
                  value={score || ''} 
                  onChange={(e) => setScore(Number(e.target.value))}
                  className="w-24 p-2 border rounded"
                />
              </div>
              <div>
                <label className="block mb-2 font-medium">מה ה-AI עשתה טוב? מה פחות?</label>
                <textarea 
                  value={lecturerFeedback}
                  onChange={(e) => setLecturerFeedback(e.target.value)}
                  className="w-full p-3 border rounded h-32"
                  placeholder="למשל: התשובה רהוטה אך חסרה ניתוח ביקורתי של המקורות..."
                />
              </div>
              <div className="flex gap-4 pt-4 border-t">
                <button 
                  onClick={() => startRedesign()}
                  className="flex-1 bg-green-600 text-white py-3 rounded-lg font-bold hover:bg-green-700 transition-colors"
                >
                  עבור לעיצוב המשימה מחדש
                </button>
                <button 
                  onClick={resetToHome}
                  className="px-6 border border-gray-300 py-3 rounded-lg font-bold hover:bg-gray-50 transition-colors"
                >
                  סיום
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  const renderRedesign = () => (
    <div className="space-y-6">
      {step === 1 && (
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <label className="block text-lg font-semibold mb-3">הזן את המשימה לעיצוב מחדש:</label>
          <textarea 
            value={assignmentText}
            onChange={(e) => setAssignmentText(e.target.value)}
            className="w-full h-48 p-4 border rounded-lg focus:ring-2 focus:ring-green-500 outline-none resize-none"
            placeholder="המטלה המקורית שלך..."
          />
          <button 
            onClick={() => startRedesign()}
            disabled={loading || !assignmentText}
            className="mt-4 w-full bg-green-600 text-white py-3 rounded-lg font-bold hover:bg-green-700 disabled:bg-gray-400 transition-colors"
          >
            {loading ? 'מנתח מיומנויות...' : 'נתח מיומנויות בטקסונומיית בלום'}
          </button>
        </div>
      )}

      {step === 2 && bloomAnalysis && (
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
            <h3 className="text-xl font-bold mb-4">ניתוח המטלה הנוכחית (טקסונומיית בלום)</h3>

            <div className="space-y-4">
              <h4 className="font-bold text-indigo-700 flex items-center gap-2">
                <span className="w-3 h-3 bg-indigo-600 rounded-full"></span>
                מיומנויות קיימות ובסיס ידע:
              </h4>
              <div className="grid gap-3">
                {bloomAnalysis.currentSkills.map((skill, idx) => (
                  <div key={idx} className="flex items-start gap-3 p-4 bg-indigo-50 rounded-lg border border-indigo-100 hover:bg-indigo-100 transition-colors">
                    <input 
                      type="checkbox" 
                      checked={selectedSkills.some(s => s.name === skill.name)}
                      onChange={() => handleSkillToggle(skill)}
                      className="mt-1 w-5 h-5 rounded cursor-pointer"
                    />
                    <div className="flex-1 cursor-pointer" onClick={() => handleSkillToggle(skill)}>
                      <div className="flex items-center gap-2">
                        <span className="font-bold">{skill.name}</span>
                        <span className="text-xs bg-indigo-600 text-white px-2 py-0.5 rounded-full font-semibold">{skill.bloomLevel}</span>
                      </div>
                      <p className="text-sm text-gray-700 mt-1">{skill.reasoning}</p>
                    </div>
                  </div>
                ))}
              </div>

              <h4 className="font-bold text-green-700 mt-6 flex items-center gap-2">
                <span className="w-3 h-3 bg-green-600 rounded-full"></span>
                מיומנויות מסדר חשיבה גבוה (שדרוג מוצע):
              </h4>
              <div className="grid gap-3">
                {bloomAnalysis.suggestedSkills.map((skill, idx) => (
                  <div key={idx} className="flex items-start gap-3 p-4 bg-green-50 rounded-lg border border-green-100 hover:bg-green-100 transition-colors">
                    <input 
                      type="checkbox" 
                      checked={selectedSkills.some(s => s.name === skill.name)}
                      onChange={() => handleSkillToggle(skill)}
                      className="mt-1 w-5 h-5 rounded cursor-pointer"
                    />
                    <div className="flex-1 cursor-pointer" onClick={() => handleSkillToggle(skill)}>
                      <div className="flex items-center gap-2">
                        <span className="font-bold">{skill.name}</span>
                        <span className="text-xs bg-green-600 text-white px-2 py-0.5 rounded-full font-semibold">{skill.bloomLevel}</span>
                      </div>
                      <p className="text-sm text-gray-700 mt-1">{skill.reasoning}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <button 
              onClick={handleProposeStrategies}
              disabled={loading || selectedSkills.length === 0}
              className="mt-8 w-full bg-indigo-600 text-white py-4 rounded-lg font-bold hover:bg-indigo-700 disabled:bg-gray-400 transition-colors shadow-lg"
            >
              {loading ? 'יוצר תוכנית הערכה משולבת...' : 'המשך לעיצוב תוכנית ההערכה והמטלה'}
            </button>
          </div>
        </div>
      )}

      {step === 3 && strategies.length > 0 && (
        <div className="space-y-8 pb-20 animate-fade-in">
          <div className="bg-indigo-900 text-white p-8 rounded-2xl shadow-xl">
            <h3 className="text-2xl font-bold mb-4">מערך ההערכה המשולב</h3>
            <p className="opacity-80 mb-6">התוכנית מוצגת לפי סדר ההיררכיה הפדגוגית של בלום. מיומנויות דומות אוחדו לשיטות הערכה יעילות.</p>

            <div className="space-y-4">
              {strategies.map((strat, idx) => (
                <div key={idx} className={`p-5 rounded-xl border-l-8 shadow-sm transition-all ${
                  strat.type === 'FaceToFace' 
                  ? 'bg-white text-gray-800 border-red-500' 
                  : 'bg-indigo-800 text-white border-blue-400'
                }`}>
                  <div className="flex justify-between items-start mb-2">
                    <div className="flex flex-wrap gap-2">
                      {strat.skills.map((s, i) => (
                         <h4 key={i} className="font-bold text-lg bg-gray-100 px-2 rounded text-gray-900">{s}</h4>
                      ))}
                    </div>
                    <span className={`text-xs px-2 py-1 rounded font-bold uppercase ${
                      strat.type === 'FaceToFace' ? 'bg-red-100 text-red-800' : 'bg-blue-100 text-blue-800'
                    }`}>
                      {strat.type === 'FaceToFace' ? 'פנים-אל-פנים' : 'שילוב AI מותר'}
                    </span>
                  </div>
                  <div className="font-semibold mb-1 text-indigo-600 underline">שיטת הערכה: {strat.method}</div>
                  <p className="text-sm opacity-90 leading-relaxed">{strat.explanation}</p>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-white p-8 rounded-xl shadow-md border-t-8 border-indigo-600">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2 text-indigo-900">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
              נוסח המטלה המעודכן לסטודנטים
            </h3>
            <div className="bg-gray-50 p-6 rounded-lg border border-indigo-100 text-gray-800 whitespace-pre-wrap leading-relaxed font-serif text-lg italic shadow-inner">
              {revisedTask}
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
            <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
              </svg>
              שיפורים ושאלות נוספות
            </h3>

            <div className="max-h-96 overflow-y-auto mb-4 space-y-4 p-4 bg-gray-50 rounded-lg border">
              {chatHistory.length === 0 && (
                <p className="text-gray-400 text-center italic">המטלה לא מושלמת? בקש מהעוזר הפדגוגי לשנות סעיפים, להוסיף דרישות או להסביר את ההיגיון שמאחורי שיטות ההערכה.</p>
              )}
              {chatHistory.map((msg, i) => (
                <div key={i} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}>
                  <div className={`max-w-[80%] p-3 rounded-2xl ${
                    msg.role === 'user' 
                    ? 'bg-indigo-100 text-indigo-900 rounded-tr-none' 
                    : 'bg-green-100 text-green-900 rounded-tl-none'
                  }`}>
                    <p className="text-sm whitespace-pre-wrap">{msg.text}</p>
                  </div>
                </div>
              ))}
              <div ref={chatEndRef} />
            </div>

            <div className="flex gap-2">
              <input 
                type="text" 
                value={followUpQuestion}
                onChange={(e) => setFollowUpQuestion(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleFollowUp()}
                placeholder="למשל: 'שנה את המטלה כך שנוכל להשתמש ב-AI גם בשלב המחקר...'"
                className="flex-1 p-3 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              />
              <button 
                onClick={handleFollowUp}
                disabled={loading || !followUpQuestion.trim()}
                className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-bold hover:bg-indigo-700 disabled:bg-gray-400 transition-colors"
              >
                שלח
              </button>
            </div>
          </div>

          <div className="mt-6 flex gap-4 no-print">
            <button 
              onClick={() => window.print()}
              className="flex-1 border border-indigo-600 text-indigo-600 py-3 rounded-lg font-bold hover:bg-indigo-50 transition-colors"
            >
              הדפסה / שמירה כ-PDF
            </button>
            <button 
              onClick={resetToHome}
              className="flex-1 bg-indigo-600 text-white py-3 rounded-lg font-bold hover:bg-indigo-700 transition-colors"
            >
              חזרה לדף הבית
            </button>
          </div>
        </div>
      )}
    </div>
  );

  return (
    <Layout 
      title={mode === 'HOME' ? 'Re-Assess' : mode === 'TEST_AI' ? 'בדיקה מול AI' : 'עיצוב מחדש'} 
      onBack={mode !== 'HOME' ? resetToHome : undefined}
    >
      <style>{`
        @media print {
          .no-print { display: none !important; }
        }
        .animate-fade-in {
          animation: fadeIn 0.5s ease-out forwards;
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
      {mode === 'HOME' && renderHome()}
      {mode === 'TEST_AI' && renderTestAi()}
      {mode === 'REDESIGN' && renderRedesign()}

      {loading && (
        <div className="fixed inset-0 bg-black/20 backdrop-blur-sm flex items-center justify-center z-50">
          <div className="bg-white p-8 rounded-2xl shadow-2xl flex flex-col items-center gap-4 border-2 border-indigo-100">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-bold text-indigo-900">העוזר הפדגוגי מעבד נתונים ומנסח משימה...</p>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

export enum BloomLevel {
  Remember = 'זכירה',
  Understand = 'הבנה',
  Apply = 'יישום',
  Analyze = 'אנליזה',
  Evaluate = 'הערכה',
  Create = 'יצירה'
}

export interface Skill {
  name: string;
  bloomLevel: BloomLevel;
  reasoning: string;
}

export interface AssessmentMethod {
  skills: string[];
  method: string; // The AI's initial suggestion
  type: 'FaceToFace' | 'AIEnabled';
  explanation: string;
  // User selections
  userSelectedCategory?: 'FaceToFace' | 'Submission';
  userSelectedMethod?: string;
}

export type AppMode = 'HOME' | 'TEST_AI' | 'REDESIGN';

import { GoogleGenAI, Type } from "@google/genai";
import { BloomLevel, Skill, AssessmentMethod } from "../types";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const testAiAssignment = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `ענה על המטלה הבאה כסטודנט מצטיין:\n\n${assignmentText}`,
    config: {
      temperature: 0.7,
    }
  });
  return response.text;
};

export const analyzeBloomTaxonomy = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נתח את המטלה הבאה לפי הטקסונומיה של בלום. 
    עליך לזהות את המיומנויות הנדרשות במשימה הנוכחית ולהציע הרחבות.

    כלל פדגוגי מחייב: למידה משמעותית היא היררכית. הניתוח חייב לכלול תמיד את רמות ה"זכירה" (Remember) וה"הבנה" (Understand) כבסיס הידע הכרחי למטלה, אלא אם כן באופן מובהק ונדיר המטלה אינה דורשת שום בסיס ידע או הבנה של חומר. 

    אנא זהה מיומנויות אלו גם אם אינן מוצהרות מפורשות במטלה המקורית.

    המטלה: ${assignmentText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          currentSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          },
          suggestedSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          }
        },
        required: ["currentSkills", "suggestedSkills"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateAssessmentStrategies = async (skills: Skill[]) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `עבור רשימת המיומנויות הבאה, אגד אותן לקבוצות הערכה לוגיות לפי סדר הטקסונומיה של בלום.

    המטרה: ליצור 2-3 "גושי הערכה" שכל אחד מהם בודק מספר מיומנויות קשורות.
    לכל גוש, הצע האם הוא מתאים יותר להערכה "פנים אל פנים" או להערכה כ"משימת הגשה".

    המיומנויות שנבחרו: ${JSON.stringify(skills)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            skills: { type: Type.ARRAY, items: { type: Type.STRING } },
            method: { type: Type.STRING, description: "הצעה ראשונית לשיטת הערכה" },
            type: { type: Type.STRING, enum: ['FaceToFace', 'AIEnabled'] },
            explanation: { type: Type.STRING, description: "למה הארגון הזה נכון פדגוגית" }
          },
          required: ["skills", "method", "type", "explanation"]
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const rephraseAssignment = async (originalText: string, targetSkills: Skill[], strategies: AssessmentMethod[]) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נסח מחדש את המטלה המקורית למטלה אקדמית שלמה וברורה לסטודנט.

    המטלה חייבת לשלב בתוכה באופן אינטגרלי את הבחירות הספציפיות של המרצה לכל חלק:
    ${strategies.map(s => `- עבור המיומנויות [${s.skills.join(', ')}]: המרצה בחר בשיטת "${s.userSelectedMethod}" (קטגוריה: ${s.userSelectedCategory === 'FaceToFace' ? 'פנים אל פנים' : 'משימת הגשה'}).`).join('\n')}

    המטלה צריכה להיראות כמו הנחיה אחת רציפה ומקצועית הכוללת את כל שלבי הביצוע והערכה.
    בסוף המטלה, הוסף פסקה קצרה של "המלצות פדגוגיות למרצה" המבוססות על הבחירות שנעשו.

    מטלה מקורית: ${originalText}`,
  });
  return response.text;
};

export const askFollowUpQuestion = async (
  context: { originalText: string, revisedTask: string, strategies: AssessmentMethod[] },
  question: string,
  history: { role: 'user' | 'model', text: string }[]
) => {
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `אתה עוזר פדגוגי מומחה. המרצה עיצב איתך מטלה הכוללת בחירות הערכה ספציפיות. 
      ענה על שאלותיו, הצע שיפורים, ושמור על טון מקצועי.`,
    }
  });

  const response = await chat.sendMessage({ message: question });
  return response.text;
};

import React, { useState, useRef, useEffect } from 'react';
import Layout from './components/Layout';
import { AppMode, BloomLevel, Skill, AssessmentMethod } from './types';
import { 
  testAiAssignment, 
  analyzeBloomTaxonomy, 
  generateAssessmentStrategies, 
  rephraseAssignment,
  askFollowUpQuestion
} from './services/geminiService';

const ASSESSMENT_OPTIONS = {
  FaceToFace: [
    'מבחן בכיתה',
    'בחינה קולית',
    'פרזנטציה בכיתה',
    'עבודה בכיתה'
  ],
  Submission: [
    'סימולציה עם בינה מלאכותית',
    'כתיבה ביחד עם בינה מלאכותית'
  ]
};

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('HOME');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);

  // State for AI Test
  const [assignmentText, setAssignmentText] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [lecturerFeedback, setLecturerFeedback] = useState('');
  const [score, setScore] = useState<number | null>(null);

  // State for Redesign
  const [bloomAnalysis, setBloomAnalysis] = useState<{currentSkills: Skill[], suggestedSkills: Skill[]} | null>(null);
  const [selectedSkills, setSelectedSkills] = useState<Skill[]>([]);
  const [strategies, setStrategies] = useState<AssessmentMethod[]>([]);
  const [revisedTask, setRevisedTask] = useState('');

  // State for Follow-up Chat
  const [followUpQuestion, setFollowUpQuestion] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const handleTestAi = async () => {
    if (!assignmentText.trim()) return;
    setLoading(true);
    try {
      const res = await testAiAssignment(assignmentText);
      setAiResponse(res || 'לא התקבלה תשובה');
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בבדיקת המטלה');
    } finally {
      setLoading(false);
    }
  };

  const startRedesign = async (initialText?: string) => {
    const textToAnalyze = initialText || assignmentText;
    if (!textToAnalyze.trim()) {
      alert('אנא הזן את הנחיית המטלה');
      return;
    }

    setBloomAnalysis(null);
    setStrategies([]);
    setRevisedTask('');
    setChatHistory([]);

    setAssignmentText(textToAnalyze);
    setMode('REDESIGN');
    setLoading(true);
    try {
      const analysis = await analyzeBloomTaxonomy(textToAnalyze);
      setBloomAnalysis(analysis);
      setSelectedSkills(analysis.currentSkills);
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בניתוח המטלה.');
    } finally {
      setLoading(false);
    }
  };

  const handleSkillToggle = (skill: Skill) => {
    setSelectedSkills(prev => 
      prev.some(s => s.name === skill.name)
        ? prev.filter(s => s.name !== skill.name)
        : [...prev, skill]
    );
  };

  const handleGetInitialStrategies = async () => {
    if (selectedSkills.length === 0) {
      alert('אנא בחר לפחות מיומנות אחת');
      return;
    }
    setLoading(true);
    try {
      const res = await generateAssessmentStrategies(selectedSkills);
      // Initialize strategies with default user selections based on AI suggestion
      const initialized = res.map((s: AssessmentMethod) => ({
        ...s,
        userSelectedCategory: s.type === 'FaceToFace' ? 'FaceToFace' : 'Submission',
        userSelectedMethod: '' // Force user to pick
      }));
      setStrategies(initialized);
      setStep(3);
    } catch (error) {
      console.error(error);
      alert('שגיאה ביצירת אסטרטגיות');
    } finally {
      setLoading(false);
    }
  };

  const updateStrategySelection = (index: number, category: 'FaceToFace' | 'Submission', method?: string) => {
    const newStrategies = [...strategies];
    newStrategies[index] = {
      ...newStrategies[index],
      userSelectedCategory: category,
      userSelectedMethod: method || ''
    };
    setStrategies(newStrategies);
  };

  const handleFinalRephrase = async () => {
    const allSelected = strategies.every(s => s.userSelectedMethod);
    if (!allSelected) {
      alert('אנא בחר שיטת הערכה לכל אחד מהחלקים');
      return;
    }

    setLoading(true);
    try {
      const rephrased = await rephraseAssignment(assignmentText, selectedSkills, strategies);
      setRevisedTask(rephrased);
      setStep(4);
    } catch (error) {
      console.error(error);
      alert('שגיאה בניסוח המטלה');
    } finally {
      setLoading(false);
    }
  };

  const handleFollowUp = async () => {
    if (!followUpQuestion.trim()) return;
    const q = followUpQuestion;
    setFollowUpQuestion('');
    setChatHistory(prev => [...prev, { role: 'user', text: q }]);

    setLoading(true);
    try {
      const response = await askFollowUpQuestion(
        { originalText: assignmentText, revisedTask, strategies },
        q,
        chatHistory
      );
      setChatHistory(prev => [...prev, { role: 'model', text: response || '' }]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const resetToHome = () => {
    setMode('HOME');
    setStep(1);
    setAssignmentText('');
    setAiResponse('');
    setLecturerFeedback('');
    setScore(null);
    setBloomAnalysis(null);
    setSelectedSkills([]);
    setStrategies([]);
    setRevisedTask('');
    setChatHistory([]);
  };

  const renderHome = () => (
    <div className="flex flex-col items-center gap-8 py-12">
      <div className="text-center space-y-4">
        <h2 className="text-4xl font-bold text-gray-800">איך המטלה שלך נראית בעידן ה-AI?</h2>
        <p className="text-xl text-gray-600 max-w-2xl">
          הצטרפו לתהליך עיצוב מחדש של דרכי הערכה אקדמיות. וודאו שהסטודנטים שלכם באמת לומדים ומפגינים הבנה עמוקה.
        </p>
      </div>
      <div className="grid md:grid-cols-2 gap-6 w-full max-w-3xl">
        <button 
          onClick={() => { setMode('TEST_AI'); setStep(1); }}
          className="bg-white border-2 border-indigo-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-indigo-400 transition-all text-right group"
        >
          <div className="bg-indigo-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
            </svg>
          </div>
          <h3 className="text-2xl font-bold text-gray-800 mb-2">בדוק מול ה-AI</h3>
          <p className="text-gray-600">ראה כיצד הבינה המלאכותית פותרת את המטלה הקיימת שלך כיום.</p>
        </button>

        <button 
          onClick={() => { setMode('REDESIGN'); setStep(1); }}
          className="bg-white border-2 border-green-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-green-400 transition-all text-right group"
        >
          <div className="bg-green-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-green-600 group-hover:text-white transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
            </svg>
          </div>
          <h3 className="text-2xl font-bold text-gray-800 mb-2">עיצוב משימה מחדש</h3>
          <p className="text-gray-600">נתח את המיומנויות במטלה ושדרג אותן לפי הטקסונומיה של בלום.</p>
        </button>
      </div>
    </div>
  );

  const renderRedesign = () => (
    <div className="space-y-6">
      {step === 1 && (
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <label className="block text-lg font-semibold mb-3">הזן את המשימה לעיצוב מחדש:</label>
          <textarea 
            value={assignmentText}
            onChange={(e) => setAssignmentText(e.target.value)}
            className="w-full h-48 p-4 border rounded-lg focus:ring-2 focus:ring-green-500 outline-none resize-none"
            placeholder="המטלה המקורית שלך..."
          />
          <button 
            onClick={() => startRedesign()}
            disabled={loading || !assignmentText}
            className="mt-4 w-full bg-green-600 text-white py-3 rounded-lg font-bold hover:bg-green-700 disabled:bg-gray-400 transition-colors"
          >
            {loading ? 'מנתח מיומנויות...' : 'נתח מיומנויות בטקסונומיית בלום'}
          </button>
        </div>
      )}

      {step === 2 && bloomAnalysis && (
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 animate-fade-in">
          <h3 className="text-xl font-bold mb-4">בחר מיומנויות למיקוד</h3>
          <div className="space-y-6">
            <div className="grid gap-3">
              {bloomAnalysis.currentSkills.concat(bloomAnalysis.suggestedSkills).map((skill, idx) => (
                <div key={idx} className="flex items-start gap-3 p-4 bg-indigo-50 rounded-lg border border-indigo-100 hover:bg-indigo-100 transition-colors">
                  <input 
                    type="checkbox" 
                    checked={selectedSkills.some(s => s.name === skill.name)}
                    onChange={() => handleSkillToggle(skill)}
                    className="mt-1 w-5 h-5 rounded cursor-pointer"
                  />
                  <div className="flex-1 cursor-pointer" onClick={() => handleSkillToggle(skill)}>
                    <div className="flex items-center gap-2">
                      <span className="font-bold">{skill.name}</span>
                      <span className="text-xs bg-indigo-600 text-white px-2 py-0.5 rounded-full font-semibold">{skill.bloomLevel}</span>
                    </div>
                    <p className="text-sm text-gray-700 mt-1">{skill.reasoning}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
          <button 
            onClick={handleGetInitialStrategies}
            disabled={loading || selectedSkills.length === 0}
            className="mt-8 w-full bg-indigo-600 text-white py-4 rounded-lg font-bold hover:bg-indigo-700 shadow-lg"
          >
            {loading ? 'בונה קבוצות הערכה...' : 'המשך לבניית מערך ההערכה'}
          </button>
        </div>
      )}

      {step === 3 && strategies.length > 0 && (
        <div className="space-y-6 animate-fade-in pb-12">
          <div className="bg-white p-8 rounded-2xl shadow-xl border-t-8 border-indigo-600">
            <h3 className="text-2xl font-bold mb-2">מערך הערכה משולב - בחירת המרצה</h3>
            <p className="text-gray-600 mb-8">עבור כל קבוצת מיומנויות, בחר את הדרך המועדפת עליך להערכה.</p>

            <div className="space-y-8">
              {strategies.map((strat, idx) => (
                <div key={idx} className="p-6 rounded-xl bg-gray-50 border-2 border-gray-200">
                  <div className="flex flex-wrap gap-2 mb-4">
                    {strat.skills.map((s, i) => (
                      <span key={i} className="bg-indigo-100 text-indigo-800 text-sm px-3 py-1 rounded-full font-bold">{s}</span>
                    ))}
                  </div>

                  <div className="grid md:grid-cols-2 gap-6">
                    <div>
                      <label className="block text-sm font-bold text-gray-700 mb-2">סוג הערכה:</label>
                      <div className="flex gap-4">
                        <button 
                          onClick={() => updateStrategySelection(idx, 'FaceToFace')}
                          className={`flex-1 py-3 px-4 rounded-lg font-bold border-2 transition-all ${strat.userSelectedCategory === 'FaceToFace' ? 'bg-red-50 border-red-500 text-red-700' : 'bg-white border-gray-200 text-gray-400'}`}
                        >
                          פנים אל פנים
                        </button>
                        <button 
                          onClick={() => updateStrategySelection(idx, 'Submission')}
                          className={`flex-1 py-3 px-4 rounded-lg font-bold border-2 transition-all ${strat.userSelectedCategory === 'Submission' ? 'bg-blue-50 border-blue-500 text-blue-700' : 'bg-white border-gray-200 text-gray-400'}`}
                        >
                          משימת הגשה
                        </button>
                      </div>
                    </div>

                    {strat.userSelectedCategory && (
                      <div className="animate-fade-in">
                        <label className="block text-sm font-bold text-gray-700 mb-2">אופן ביצוע ספציפי:</label>
                        <select 
                          value={strat.userSelectedMethod}
                          onChange={(e) => updateStrategySelection(idx, strat.userSelectedCategory!, e.target.value)}
                          className="w-full p-3 border-2 border-indigo-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                        >
                          <option value="">-- בחר אפשרות --</option>
                          {ASSESSMENT_OPTIONS[strat.userSelectedCategory as keyof typeof ASSESSMENT_OPTIONS].map(opt => (
                            <option key={opt} value={opt}>{opt}</option>
                          ))}
                        </select>
                      </div>
                    )}
                  </div>
                  <p className="mt-4 text-xs text-gray-500 italic">המלצת העוזר: {strat.explanation}</p>
                </div>
              ))}
            </div>

            <button 
              onClick={handleFinalRephrase}
              disabled={loading}
              className="mt-12 w-full bg-green-600 text-white py-4 rounded-lg font-bold hover:bg-green-700 shadow-xl text-xl"
            >
              {loading ? 'מנסח את המטלה הסופית...' : 'צור את הנחיית המטלה והסיכום'}
            </button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-8 pb-20 animate-fade-in">
          <div className="bg-white p-8 rounded-xl shadow-md border-t-8 border-green-600">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2 text-indigo-900">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
              סיכום והנחיית המטלה המחודשת
            </h3>
            <div className="bg-gray-50 p-6 rounded-lg border border-indigo-100 text-gray-800 whitespace-pre-wrap leading-relaxed font-serif text-lg italic shadow-inner">
              {revisedTask}
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
            <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
              </svg>
              שאלות נוספות למערך?
            </h3>
            <div className="max-h-64 overflow-y-auto mb-4 space-y-4 p-4 bg-gray-50 rounded-lg border">
              {chatHistory.map((msg, i) => (
                <div key={i} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}>
