                    <p className="text-sm">{msg.text}</p>
                  </div>
                </div>
              ))}
              <div ref={chatEndRef} />
            </div>
            <div className="flex gap-2">
              <input 
                type="text" 
                value={followUpQuestion}
                onChange={(e) => setFollowUpQuestion(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleFollowUp()}
                placeholder="שאל משהו..."
                className="flex-1 p-3 border rounded-lg"
              />
              <button onClick={handleFollowUp} className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-bold">שלח</button>
            </div>
          </div>

          <div className="flex gap-4 no-print">
            <button onClick={() => window.print()} className="flex-1 border border-indigo-600 text-indigo-600 py-3 rounded-lg font-bold">הדפסה / שמירה</button>
            <button onClick={resetToHome} className="flex-1 bg-indigo-600 text-white py-3 rounded-lg font-bold">סיום</button>
          </div>
        </div>
      )}
    </div>
  );

  return (
    <Layout 
      title={mode === 'HOME' ? 'Re-Assess' : mode === 'TEST_AI' ? 'בדיקה מול AI' : 'עיצוב מחדש'} 
      onBack={mode !== 'HOME' ? resetToHome : undefined}
    >
      <style>{`
        .animate-fade-in { animation: fadeIn 0.4s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
        @media print { .no-print { display: none !important; } }
      `}</style>
      {mode === 'HOME' && renderHome()}
      {mode === 'REDESIGN' && renderRedesign()}
      {loading && (
        <div className="fixed inset-0 bg-black/20 backdrop-blur-sm flex items-center justify-center z-50">
          <div className="bg-white p-8 rounded-2xl shadow-2xl flex flex-col items-center gap-4 border-2 border-indigo-100">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-bold text-indigo-900 text-center">העוזר הפדגוגי מעבד את בחירותיך ומנסח את המשימה...</p>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

export enum BloomLevel {
  Remember = 'זכירה',
  Understand = 'הבנה',
  Apply = 'יישום',
  Analyze = 'אנליזה',
  Evaluate = 'הערכה',
  Create = 'יצירה'
}

export interface Skill {
  name: string;
  bloomLevel: BloomLevel;
  reasoning: string;
}

export interface AssessmentMethod {
  id: string;
  skills: string[];
  method: string;
  type: 'FaceToFace' | 'Submission';
  explanation: string;
  userSelectedCategory?: 'FaceToFace' | 'Submission';
  userSelectedMethod?: string;
}

export type AppMode = 'HOME' | 'TEST_AI' | 'REDESIGN';

import { GoogleGenAI, Type } from "@google/genai";
import { BloomLevel, Skill, AssessmentMethod } from "../types";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const testAiAssignment = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `ענה על המטלה הבאה כסטודנט מצטיין:\n\n${assignmentText}`,
    config: {
      temperature: 0.7,
    }
  });
  return response.text;
};

export const analyzeBloomTaxonomy = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נתח את המטלה הבאה לפי הטקסונומיה של בלום. 
    עליך לזהות את המיומנויות הנדרשות במשימה הנוכחית ולהציע הרחבות.

    כלל פדגוגי מחייב: למידה משמעותית היא היררכית. הניתוח חייב לכלול תמיד את רמות ה"זכירה" (Remember) וה"הבנה" (Understand) כבסיס הידע הכרחי למטלה.

    המטלה: ${assignmentText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          currentSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          },
          suggestedSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          }
        },
        required: ["currentSkills", "suggestedSkills"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateAssessmentStrategies = async (skills: Skill[], numStudents: number) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `עבור רשימת המיומנויות הבאה וכיתה של ${numStudents} סטודנטים, אגד אותן לקבוצות הערכה לוגיות (2-3 קבוצות).

    קח בחשבון שגודל הכיתה (${numStudents}) משפיע על הישימות של שיטות מסוימות (למשל, פרזנטציות אישיות קשות בכיתות גדולות).

    המיומנויות שנבחרו: ${JSON.stringify(skills)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            skills: { type: Type.ARRAY, items: { type: Type.STRING } },
            method: { type: Type.STRING },
            type: { type: Type.STRING, enum: ['FaceToFace', 'Submission'] },
            explanation: { type: Type.STRING }
          },
          required: ["skills", "method", "type", "explanation"]
        }
      }
    }
  });

  const res = JSON.parse(response.text);
  return res.map((item: any, index: number) => ({
    ...item,
    id: `group-${index}-${Date.now()}`
  }));
};

export const rephraseAssignment = async (originalText: string, targetSkills: Skill[], strategies: AssessmentMethod[], numStudents: number) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נסח מחדש את המטלה המקורית למטלה אקדמית שלמה וברורה לסטודנט בכיתה של ${numStudents} איש.

    שלב את הבחירות הספציפיות של המרצה:
    ${strategies.map(s => `- מיומנויות: [${s.skills.join(', ')}], שיטה: "${s.userSelectedMethod}" (${s.userSelectedCategory === 'FaceToFace' ? 'פנים אל פנים' : 'הגשה'}).`).join('\n')}

    הוסף המלצות פדגוגיות בסוף.

    מטלה מקורית: ${originalText}`,
  });
  return response.text;
};

export const askFollowUpQuestion = async (
  context: { originalText: string, revisedTask: string, strategies: AssessmentMethod[] },
  question: string,
  history: { role: 'user' | 'model', text: string }[]
) => {
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `אתה עוזר פדגוגי מומחה. המרצה עיצב איתך מטלה. ענה על שאלותיו במקצועיות.`,
    }
  });
  const response = await chat.sendMessage({ message: question });
  return response.text;
};

