const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('HOME');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);

  const [assignmentText, setAssignmentText] = useState('');
  const [numStudents, setNumStudents] = useState<number>(30);
  const [aiResponse, setAiResponse] = useState('');

  const [bloomAnalysis, setBloomAnalysis] = useState<{currentSkills: Skill[], suggestedSkills: Skill[]} | null>(null);
  const [selectedSkills, setSelectedSkills] = useState<Skill[]>([]);
  const [strategies, setStrategies] = useState<AssessmentMethod[]>([]);
  const [revisedTask, setRevisedTask] = useState('');

  const [followUpQuestion, setFollowUpQuestion] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const handleTestAi = async () => {
    if (!assignmentText.trim()) return;
    setLoading(true);
    try {
      const res = await testAiAssignment(assignmentText);
      setAiResponse(res || 'לא התקבלה תשובה');
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בבדיקת המטלה');
    } finally {
      setLoading(false);
    }
  };

  const startRedesign = async (initialText?: string) => {
    const textToAnalyze = initialText || assignmentText;
    if (!textToAnalyze.trim()) {
      alert('אנא הזן את הנחיית המטלה');
      return;
    }
    setAssignmentText(textToAnalyze);
    setMode('REDESIGN');
    setLoading(true);
    try {
      const analysis = await analyzeBloomTaxonomy(textToAnalyze);
      setBloomAnalysis(analysis);
      setSelectedSkills(analysis.currentSkills);
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בניתוח המטלה.');
    } finally {
      setLoading(false);
    }
  };

  const handleSkillToggle = (skill: Skill) => {
    setSelectedSkills(prev => 
      prev.some(s => s.name === skill.name)
        ? prev.filter(s => s.name !== skill.name)
        : [...prev, skill]
    );
  };

  const handleGetInitialStrategies = async () => {
    if (selectedSkills.length === 0) {
      alert('אנא בחר לפחות מיומנות אחת');
      return;
    }
    setLoading(true);
    try {
      const res = await generateAssessmentStrategies(selectedSkills, numStudents);
      const initialized = res.map((s: any) => ({
        ...s,
        userSelectedCategory: s.type,
        userSelectedMethod: ''
      }));
      setStrategies(initialized);
      setStep(3);
    } catch (error) {
      console.error(error);
      alert('שגיאה ביצירת אסטרטגיות');
    } finally {
      setLoading(false);
    }
  };

  const updateStrategySelection = (index: number, category: 'FaceToFace' | 'Submission', method?: string) => {
    const newStrategies = [...strategies];
    newStrategies[index] = {
      ...newStrategies[index],
      userSelectedCategory: category,
      userSelectedMethod: method || ''
    };
    setStrategies(newStrategies);
  };

  const moveSkillToGroup = (skillName: string, targetGroupId: string) => {
    const newStrategies = strategies.map(s => {
      const remainingSkills = s.skills.filter(sk => sk !== skillName);
      if (s.id === targetGroupId) {
        return { ...s, skills: [...s.skills.filter(sk => sk !== skillName), skillName] };
      }
      return { ...s, skills: remainingSkills };
    }).filter(s => s.skills.length > 0);
    setStrategies(newStrategies);
  };

  const addNewGroup = (skillName: string) => {
    // 1. Remove skill from its current group
    const updatedOldGroups = strategies.map(s => ({
      ...s,
      skills: s.skills.filter(sk => sk !== skillName)
    })).filter(s => s.skills.length > 0);

    // 2. Create the new group
    const newGroup: AssessmentMethod = {
      id: `group-${Date.now()}`,
      skills: [skillName],
      method: '',
      type: 'FaceToFace',
      explanation: 'קבוצה חדשה שהוגדרה על ידי המרצה.',
      userSelectedCategory: 'FaceToFace',
      userSelectedMethod: ''
    };

    setStrategies([...updatedOldGroups, newGroup]);
  };

  const handleFinalRephrase = async () => {
    if (!strategies.every(s => s.userSelectedMethod)) {
      alert('אנא בחר שיטת הערכה לכל אחד מהחלקים');
      return;
    }
    setLoading(true);
    try {
      const rephrased = await rephraseAssignment(assignmentText, selectedSkills, strategies, numStudents);
      setRevisedTask(rephrased);
      setStep(4);
    } catch (error) {
      console.error(error);
      alert('שגיאה בניסוח המטלה');
    } finally {
      setLoading(false);
    }
  };

  const handleFollowUp = async () => {
    if (!followUpQuestion.trim()) return;
    const q = followUpQuestion;
    setFollowUpQuestion('');
    setChatHistory(prev => [...prev, { role: 'user', text: q }]);
    setLoading(true);
    try {
      const response = await askFollowUpQuestion({ originalText: assignmentText, revisedTask, strategies }, q, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: response || '' }]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const resetToHome = () => {
    setMode('HOME');
    setStep(1);
    setAssignmentText('');
    setAiResponse('');
    setBloomAnalysis(null);
    setSelectedSkills([]);
    setStrategies([]);
    setRevisedTask('');
    setChatHistory([]);
  };

  const handleGoBack = () => {
    if (step > 1) {
      setStep(step - 1);
    } else {
      setMode('HOME');
    }
  };

  return (
    <Layout 
      title={mode === 'HOME' ? 'Re-Assess' : mode === 'TEST_AI' ? 'בדיקה מול AI' : 'עיצוב מחדש'} 
      onBack={mode !== 'HOME' ? handleGoBack : undefined}
    >
      <style>{`
        .animate-fade-in { animation: fadeIn 0.4s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
        @media print { .no-print { display: none !important; } }

        .skill-tag { transition: all 0.2s; }
        .skill-tag:hover { transform: scale(1.02); }
      `}</style>

      {mode === 'HOME' && (
        <div className="flex flex-col items-center gap-8 py-12">
          <div className="text-center space-y-4">
            <h2 className="text-4xl font-bold text-gray-800">איך המטלה שלך נראית בעידן ה-AI?</h2>
            <p className="text-xl text-gray-600 max-w-2xl">שיפור פדגוגיה ומניעת העתקות באמצעות עיצוב מחדש של דרכי הערכה.</p>
          </div>
          <div className="grid md:grid-cols-2 gap-6 w-full max-w-3xl">
            <button onClick={() => { setMode('TEST_AI'); setStep(1); }} className="bg-white border-2 border-indigo-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-indigo-400 text-right group">
              <div className="bg-indigo-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">בדוק מול ה-AI</h3>
              <p className="text-gray-600">ראה כיצד הבינה המלאכותית פותרת את המטלה הקיימת שלך כיום.</p>
            </button>
            <button onClick={() => { setMode('REDESIGN'); setStep(1); }} className="bg-white border-2 border-green-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-green-400 text-right group">
              <div className="bg-green-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-green-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">עיצוב משימה מחדש</h3>
              <p className="text-gray-600">נתח מיומנויות ושדרג את המערך הפדגוגי.</p>
            </button>
          </div>
        </div>
      )}

      {mode === 'TEST_AI' && (
        <div className="space-y-6 animate-fade-in">
          {step === 1 ? (
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
              <label className="block text-lg font-semibold mb-3">הזן את המטלה המקורית:</label>
              <textarea value={assignmentText} onChange={(e) => setAssignmentText(e.target.value)} className="w-full h-48 p-4 border rounded-lg outline-none" placeholder="..." />
              <button onClick={handleTestAi} disabled={loading || !assignmentText} className="mt-4 w-full bg-indigo-600 text-white py-3 rounded-lg font-bold">בדוק פתרון AI</button>
            </div>
          ) : (
            <div className="space-y-6">
              <div className="bg-blue-50 p-6 rounded-xl border border-blue-200">
                <h3 className="font-bold text-blue-900 mb-2">תשובת ה-AI:</h3>
                <div className="text-gray-800 whitespace-pre-wrap">{aiResponse}</div>
              </div>
              <div className="flex gap-4">
                <button onClick={() => startRedesign()} className="flex-1 bg-green-600 text-white py-3 rounded-lg font-bold">שדרג מטלה זו</button>
                <button onClick={handleGoBack} className="px-6 border py-3 rounded-lg">חזור</button>
              </div>
            </div>
          )}
        </div>
      )}

      {mode === 'REDESIGN' && (
        <div className="space-y-6 animate-fade-in">
          {step === 1 && (
            <div className="bg-white p-8 rounded-xl shadow-sm border border-gray-100">
              <div className="grid gap-6">
                <div>
                  <label className="block text-lg font-semibold mb-2">הנחיית המטלה:</label>
                  <textarea value={assignmentText} onChange={(e) => setAssignmentText(e.target.value)} className="w-full h-40 p-4 border rounded-lg" placeholder="מה הסטודנטים צריכים לעשות?" />
                </div>
                <div>
                  <label className="block text-lg font-semibold mb-2">מספר סטודנטים בקורס:</label>
                  <input type="number" value={numStudents} onChange={(e) => setNumStudents(parseInt(e.target.value))} className="w-32 p-3 border rounded-lg font-bold text-indigo-900" />
                </div>
              </div>
              <button onClick={() => startRedesign()} disabled={loading || !assignmentText} className="mt-8 w-full bg-green-600 text-white py-4 rounded-lg font-bold">נתח מיומנויות בטקסונומיית בלום</button>
            </div>
          )}

          {step === 2 && bloomAnalysis && (
            <div className="bg-white p-6 rounded-xl shadow-sm border animate-fade-in">
              <div className="mb-6 p-4 bg-amber-50 rounded-lg border border-amber-200">
                <p className="text-amber-800 font-bold">שימו לב: זיהינו את מיומנויות היסוד (זכירה והבנה) כבסיס הכרחי. בחר את המיומנויות שיוערכו במטלה החדשה.</p>
              </div>
              <h3 className="text-xl font-bold mb-4 text-gray-800">בחירת מיומנויות יעד</h3>
              <div className="grid gap-3">
                {bloomAnalysis.currentSkills.concat(bloomAnalysis.suggestedSkills).map((skill, idx) => (
                  <div key={idx} className={`flex items-start gap-3 p-4 rounded-lg border transition-all ${selectedSkills.some(s => s.name === skill.name) ? 'bg-indigo-50 border-indigo-300' : 'bg-gray-50 border-gray-200'}`}>
                    <input type="checkbox" checked={selectedSkills.some(s => s.name === skill.name)} onChange={() => handleSkillToggle(skill)} className="mt-1 w-5 h-5 cursor-pointer" />
                    <div className="flex-1 cursor-pointer" onClick={() => handleSkillToggle(skill)}>
                      <div className="flex items-center gap-2">
                        <span className="font-bold">{skill.name}</span>
                        <span className="text-xs bg-indigo-600 text-white px-2 py-0.5 rounded-full font-semibold">{skill.bloomLevel}</span>
                      </div>
                      <p className="text-sm text-gray-700 mt-1">{skill.reasoning}</p>
                    </div>
                  </div>
                ))}
              </div>
              <div className="flex gap-4 mt-8">
                <button onClick={handleGoBack} className="px-6 py-3 border rounded-lg font-bold hover:bg-gray-50 transition-all">חזור</button>
                <button onClick={handleGetInitialStrategies} disabled={loading || selectedSkills.length === 0} className="flex-1 bg-indigo-600 text-white py-3 rounded-lg font-bold shadow-lg hover:bg-indigo-700 transition-all">המשך לעיצוב הערכה</button>
              </div>
            </div>
          )}

          {step === 3 && strategies.length > 0 && (
            <div className="space-y-6 animate-fade-in pb-12">
              <div className="bg-white p-8 rounded-2xl shadow-xl border-t-8 border-indigo-600">
                <div className="flex justify-between items-center mb-6">
                  <div>
                    <h3 className="text-2xl font-bold text-indigo-900">ניהול קבוצות מיומנויות</h3>
                    <p className="text-gray-600">גררו או הזיזו מיומנויות בין קבוצות. לכל קבוצה מיוחסת שיטת הערכה.</p>
                  </div>
                  <button onClick={() => addNewGroup('מיומנות חדשה')} className="bg-green-50 text-green-700 px-4 py-2 rounded-xl font-bold border border-green-200 hover:bg-green-100 transition-all">+ הוסף קבוצה</button>
                </div>

                <div className="space-y-8">
                  {strategies.map((strat, idx) => (
                    <div key={strat.id} className="p-6 rounded-2xl bg-gray-50 border-2 border-gray-200 relative">
                      <div className="flex flex-wrap gap-2 mb-6">
                        {strat.skills.map((s, i) => (
                          <div key={i} className="skill-tag flex items-center bg-white text-indigo-900 border border-indigo-200 text-sm px-3 py-1.5 rounded-xl font-bold group relative">
                            {s}
                            <div className="hidden group-hover:flex absolute top-full right-0 mt-2 z-20 bg-white shadow-2xl border p-3 rounded-xl flex-col gap-2 min-w-[240px]">
                              <p className="text-xs font-bold text-gray-400 mb-1 border-b pb-1">העבר מיומנות זו לקבוצה:</p>
                              {strategies.map((target, tIdx) => (
                                target.id !== strat.id && (
                                  <button key={target.id} onClick={() => moveSkillToGroup(s, target.id)} className="text-right text-xs hover:bg-indigo-50 p-2 rounded transition-colors flex items-center gap-2">
                                    <span className="w-5 h-5 rounded-full bg-indigo-100 flex items-center justify-center text-[10px]">{tIdx + 1}</span>
                                    <span>{target.skills.slice(0, 1).join(', ')}...</span>
                                  </button>
                                )
                              ))}
                              <button onClick={() => addNewGroup(s)} className="text-right text-xs font-bold text-green-600 hover:bg-green-50 p-2 rounded border-t mt-1 pt-2">
                                + צור קבוצה נפרדת למיומנות זו
                              </button>
                            </div>
                          </div>
                        ))}
                      </div>

                      <div className="grid md:grid-cols-2 gap-8">
                        <div>
                          <label className="block text-sm font-bold text-gray-700 mb-3">סוג הערכה:</label>
                          <div className="flex gap-4">
                            <button onClick={() => updateStrategySelection(idx, 'FaceToFace')} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all flex flex-col items-center gap-1 ${strat.userSelectedCategory === 'FaceToFace' ? 'bg-amber-50 border-amber-400 text-amber-800 shadow-sm' : 'bg-white text-gray-400 border-gray-100 hover:border-gray-300'}`}>
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
                                פנים אל פנים
                            </button>
                            <button onClick={() => updateStrategySelection(idx, 'Submission')} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all flex flex-col items-center gap-1 ${strat.userSelectedCategory === 'Submission' ? 'bg-indigo-50 border-indigo-400 text-indigo-800 shadow-sm' : 'bg-white text-gray-400 border-gray-100 hover:border-gray-300'}`}>
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                                משימת הגשה
                            </button>
                          </div>
                        </div>

                        {strat.userSelectedCategory && (
                          <div className="animate-fade-in">
                            <label className="block text-sm font-bold text-gray-700 mb-3">בחירת שיטה (מסודר לפי קטגוריות):</label>
                            <select value={strat.userSelectedMethod} onChange={(e) => updateStrategySelection(idx, strat.userSelectedCategory!, e.target.value)} className="w-full p-4 border-2 border-indigo-200 rounded-xl bg-white outline-none focus:border-indigo-500 transition-all font-medium text-gray-800">
                              <option value="">-- בחר שיטה --</option>
                              {Object.entries(CATEGORIZED_OPTIONS[strat.userSelectedCategory as keyof typeof CATEGORIZED_OPTIONS]).map(([catName, options]) => (
                                <optgroup key={catName} label={catName}>
                                  {options.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                                </optgroup>
                              ))}
                            </select>
                            <p className="mt-2 text-xs text-gray-400 italic">השיטות מותאמות לסדר הטקסונומיה של בלום ולגודל הכיתה שלך ({numStudents}).</p>
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
                <div className="flex gap-4 mt-12 pt-8 border-t">
                  <button onClick={handleGoBack} className="px-10 py-4 border-2 rounded-xl font-bold hover:bg-gray-50 transition-all">חזור</button>
                  <button onClick={handleFinalRephrase} disabled={loading} className="flex-1 bg-green-600 text-white py-4 rounded-xl font-bold text-xl shadow-lg hover:bg-green-700 transition-all">צור מטלה וסיכום פדגוגי</button>
                </div>
              </div>
            </div>
          )}

          {step === 4 && (
            <div className="space-y-8 pb-20 animate-fade-in">
              <div className="bg-white p-8 rounded-2xl shadow-md border-t-8 border-green-600">
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-2xl font-bold text-indigo-900">סיכום המטלה והמלצות פדגוגיות</h3>
                  <span className="text-sm font-bold bg-indigo-50 text-indigo-700 px-4 py-1.5 rounded-full border border-indigo-200">גודל כיתה: {numStudents}</span>
                </div>
                <div className="bg-gray-50 p-8 rounded-2xl border border-indigo-100 text-gray-800 whitespace-pre-wrap leading-relaxed font-serif text-lg italic shadow-inner">
                  {revisedTask}
                </div>
              </div>

              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
                  </svg>
                  התאמות נוספות מול העוזר הפדגוגי
                </h3>
                <div className="max-h-64 overflow-y-auto mb-4 space-y-4 p-4 bg-gray-50 rounded-lg">
                  {chatHistory.map((msg, i) => (
                    <div key={i} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}>
                      <div className={`max-w-[80%] p-3 rounded-2xl ${msg.role === 'user' ? 'bg-indigo-100 text-indigo-900 shadow-sm' : 'bg-green-100 text-green-900 shadow-sm'}`}>{msg.text}</div>
                    </div>
                  ))}
                  <div ref={chatEndRef} />
                </div>
                <div className="flex gap-2">
                  <input type="text" value={followUpQuestion} onChange={(e) => setFollowUpQuestion(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleFollowUp()} placeholder="שאל משהו..." className="flex-1 p-3 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all shadow-inner" />
                  <button onClick={handleFollowUp} className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold hover:bg-indigo-700 transition-all">שלח</button>
                </div>
              </div>

              <div className="flex gap-4 no-print">
                <button onClick={handleGoBack} className="px-10 py-4 border-2 rounded-xl font-bold hover:bg-gray-50 transition-all">חזור לעריכה</button>
                <button onClick={() => window.print()} className="flex-1 border-2 border-indigo-600 text-indigo-600 py-4 rounded-xl font-bold hover:bg-indigo-50 transition-all">הדפסה / PDF</button>
                <button onClick={resetToHome} className="flex-1 bg-indigo-600 text-white py-4 rounded-xl font-bold hover:bg-indigo-700 transition-all">סיים וחזור לדף הבית</button>
              </div>
            </div>
          )}
        </div>
      )}

      {loading && (
        <div className="fixed inset-0 bg-black/20 backdrop-blur-sm flex items-center justify-center z-50">
          <div className="bg-white p-10 rounded-3xl shadow-2xl flex flex-col items-center gap-6 border-2 border-indigo-100 animate-pulse">
            <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-bold text-xl text-indigo-900 text-center">העוזר הפדגוגי מעבד את המידע...</p>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import Layout from './components/Layout';
import { AppMode, BloomLevel, Skill, AssessmentMethod } from './types';
import { 
  testAiAssignment, 
  analyzeBloomTaxonomy, 
  generateAssessmentStrategies, 
  rephraseAssignment,
  askFollowUpQuestion
} from './services/geminiService';

// Categorized assessment methods refined for better navigation
const CATEGORIZED_OPTIONS = {
  FaceToFace: {
    'בדיקת ידע מהירה (מתאים לכיתות גדולות)': [
      'בחנים קצרים בכיתה (Clickers / LMS)',
      'Polling (הצבעות כיתתיות)',
      'Concept checks (בדיקת ידע מושגי מהיר)',
      'מבחני הבנה בזמן אמת (שאלות סגורות/פתוחות קצרות)'
    ],
    'הערכה מעמיקה ודיון (מתאים לקבוצות קטנות/בינוניות)': [
      'פרזנטציות קצרות בקבוצות (פורמט אחיד)',
      'הצגת תוצר קבוצתי בכיתה',
      'דיונים מונחים בקבוצות משנה',
      'ניתוח דילמה חינוכית בזמן שיעור',
      'Viva - שאלת הבהרה אישית קצרה'
    ],
    'מבחנים פורמליים': [
      'מבחנים כתובים בכיתה (מפוקחים)',
      'מבדקי ביניים קצרים ומרובים',
      'מבחני ביצוע אחידים (Rubric-based)'
    ]
  },
  Submission: {
    'כתיבה ומחקר': [
      'עבודות בית פתוחות',
      'עבודות מחקר אישיות',
      'פרויקט מסכם כתוב',
      'תיק עבודות (Portfolio)'
    ],
    'תהליך ורפלקציה': [
      'יומן רפלקטיבי אישי',
      'הערכת עמיתים (Peer Assessment)',
      'הערכה עצמית',
      'תהליך כתיבה רב-שלבי'
    ],
    'חדשנות ו-AI': [
      'שילוב מבוקר של AI בתהליך',
      'רפלקציה על שימוש ב-AI',
      'סימולציה מול בינה מלאכותית',
      'ניתוח מקרי בוחן (Case studies)'
    ]
  }
};

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('HOME');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);

  const [assignmentText, setAssignmentText] = useState('');
  const [numStudents, setNumStudents] = useState<number>(30);
  const [aiResponse, setAiResponse] = useState('');

  const [bloomAnalysis, setBloomAnalysis] = useState<{currentSkills: Skill[], suggestedSkills: Skill[]} | null>(null);
  const [selectedSkills, setSelectedSkills] = useState<Skill[]>([]);
  const [strategies, setStrategies] = useState<AssessmentMethod[]>([]);
  const [revisedTask, setRevisedTask] = useState('');

  // UI state for managing skill inspection
  const [inspectedSkill, setInspectedSkill] = useState<{name: string, groupIdx: number} | null>(null);

  const [followUpQuestion, setFollowUpQuestion] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const handleTestAi = async () => {
    if (!assignmentText.trim()) return;
    setLoading(true);
    try {
      const res = await testAiAssignment(assignmentText);
      setAiResponse(res || 'לא התקבלה תשובה');
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בבדיקת המטלה');
    } finally {
      setLoading(false);
    }
  };

  const startRedesign = async (initialText?: string) => {
    const textToAnalyze = initialText || assignmentText;
    if (!textToAnalyze.trim()) {
      alert('אנא הזן את הנחיית המטלה');
      return;
    }
    setAssignmentText(textToAnalyze);
    setMode('REDESIGN');
    setLoading(true);
    try {
      const analysis = await analyzeBloomTaxonomy(textToAnalyze);
      setBloomAnalysis(analysis);
      setSelectedSkills(analysis.currentSkills);
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בניתוח המטלה.');
    } finally {
      setLoading(false);
    }
  };

  const handleSkillToggle = (skill: Skill) => {
    setSelectedSkills(prev => 
      prev.some(s => s.name === skill.name)
        ? prev.filter(s => s.name !== skill.name)
        : [...prev, skill]
    );
  };

  const handleGetInitialStrategies = async () => {
    if (selectedSkills.length === 0) {
      alert('אנא בחר לפחות מיומנות אחת');
      return;
    }
    setLoading(true);
    try {
      const res = await generateAssessmentStrategies(selectedSkills, numStudents);
      const initialized = res.map((s: any) => ({
        ...s,
        userSelectedCategory: s.type,
        userSelectedMethod: s.method // Initially use AI suggestion
      }));
      setStrategies(initialized);
      setStep(3);
    } catch (error) {
      console.error(error);
      alert('שגיאה ביצירת אסטרטגיות');
    } finally {
      setLoading(false);
    }
  };

  const updateStrategySelection = (index: number, category: 'FaceToFace' | 'Submission', method?: string) => {
    const newStrategies = [...strategies];
    newStrategies[index] = {
      ...newStrategies[index],
      userSelectedCategory: category,
      userSelectedMethod: method || ''
    };
    setStrategies(newStrategies);
  };

  const moveSkillToGroup = (skillName: string, targetGroupId: string) => {
    const newStrategies = strategies.map(s => {
      const remainingSkills = s.skills.filter(sk => sk !== skillName);
      if (s.id === targetGroupId) {
        return { ...s, skills: [...s.skills.filter(sk => sk !== skillName), skillName] };
      }
      return { ...s, skills: remainingSkills };
    }).filter(s => s.skills.length > 0);
    setStrategies(newStrategies);
    setInspectedSkill(null);
  };

  const addNewGroup = (skillName: string) => {
    const updatedOldGroups = strategies.map(s => ({
      ...s,
      skills: s.skills.filter(sk => sk !== skillName)
    })).filter(s => s.skills.length > 0);

    const newGroup: AssessmentMethod = {
      id: `group-${Date.now()}`,
      skills: [skillName],
      method: '',
      type: 'FaceToFace',
      explanation: 'קבוצה חדשה שהוגדרה על ידי המרצה.',
      userSelectedCategory: 'FaceToFace',
      userSelectedMethod: ''
    };

    setStrategies([...updatedOldGroups, newGroup]);
    setInspectedSkill(null);
  };

  const handleFinalRephrase = async () => {
    if (!strategies.every(s => s.userSelectedMethod)) {
      alert('אנא בחר שיטת הערכה לכל אחד מהחלקים');
      return;
    }
    setLoading(true);
    try {
      const rephrased = await rephraseAssignment(assignmentText, selectedSkills, strategies, numStudents);
      setRevisedTask(rephrased);
      setStep(4);
    } catch (error) {
      console.error(error);
      alert('שגיאה בניסוח המטלה');
    } finally {
      setLoading(false);
    }
  };

  const handleFollowUp = async () => {
    if (!followUpQuestion.trim()) return;
    const q = followUpQuestion;
    setFollowUpQuestion('');
    setChatHistory(prev => [...prev, { role: 'user', text: q }]);
    setLoading(true);
    try {
      const response = await askFollowUpQuestion({ originalText: assignmentText, revisedTask, strategies }, q, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: response || '' }]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const resetToHome = () => {
    setMode('HOME');
    setStep(1);
    setAssignmentText('');
    setAiResponse('');
    setBloomAnalysis(null);
    setSelectedSkills([]);
    setStrategies([]);
    setRevisedTask('');
    setChatHistory([]);
  };

  const handleGoBack = () => {
    if (step > 1) {
      setStep(step - 1);
    } else {
      setMode('HOME');
    }
  };

  return (
    <Layout 
      title={mode === 'HOME' ? 'Re-Assess' : mode === 'TEST_AI' ? 'בדיקה מול AI' : 'עיצוב מחדש'} 
      onBack={mode !== 'HOME' ? handleGoBack : undefined}
    >
      <style>{`
        .animate-fade-in { animation: fadeIn 0.4s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
        @media print { .no-print { display: none !important; } }

        .skill-btn { transition: all 0.2s; }
        .skill-btn:hover { transform: translateY(-1px); box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
      `}</style>

      {mode === 'HOME' && (
        <div className="flex flex-col items-center gap-8 py-12">
          <div className="text-center space-y-4">
            <h2 className="text-4xl font-bold text-gray-800">איך המטלה שלך נראית בעידן ה-AI?</h2>
            <p className="text-xl text-gray-600 max-w-2xl">שיפור פדגוגיה ומניעת העתקות באמצעות עיצוב מחדש של דרכי הערכה.</p>
          </div>
          <div className="grid md:grid-cols-2 gap-6 w-full max-w-3xl">
            <button onClick={() => { setMode('TEST_AI'); setStep(1); }} className="bg-white border-2 border-indigo-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-indigo-400 text-right group">
              <div className="bg-indigo-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">בדוק מול ה-AI</h3>
              <p className="text-gray-600">ראה כיצד הבינה המלאכותית פותרת את המטלה הקיימת שלך כיום.</p>
            </button>
            <button onClick={() => { setMode('REDESIGN'); setStep(1); }} className="bg-white border-2 border-green-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-green-400 text-right group">
              <div className="bg-green-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-green-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">עיצוב משימה מחדש</h3>
              <p className="text-gray-600">נתח מיומנויות ושדרג את המערך הפדגוגי.</p>
            </button>
          </div>
        </div>
      )}

      {mode === 'TEST_AI' && (
        <div className="space-y-6 animate-fade-in">
          {step === 1 ? (
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
              <label className="block text-lg font-semibold mb-3">הזן את המטלה המקורית:</label>
              <textarea value={assignmentText} onChange={(e) => setAssignmentText(e.target.value)} className="w-full h-48 p-4 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" placeholder="..." />
              <button onClick={handleTestAi} disabled={loading || !assignmentText} className="mt-4 w-full bg-indigo-600 text-white py-3 rounded-lg font-bold">בדוק פתרון AI</button>
            </div>
          ) : (
            <div className="space-y-6">
              <div className="bg-blue-50 p-6 rounded-xl border border-blue-200 shadow-inner">
                <h3 className="font-bold text-blue-900 mb-2">תשובת ה-AI (כך סטודנט יפתור זאת):</h3>
                <div className="text-gray-800 whitespace-pre-wrap leading-relaxed">{aiResponse}</div>
              </div>
              <div className="flex gap-4">
                <button onClick={() => startRedesign()} className="flex-1 bg-green-600 text-white py-3 rounded-lg font-bold shadow-lg">שדרג מטלה זו פדגוגית</button>
                <button onClick={handleGoBack} className="px-6 border py-3 rounded-lg font-semibold">חזור</button>
              </div>
            </div>
          )}
        </div>
      )}

      {mode === 'REDESIGN' && (
        <div className="space-y-6 animate-fade-in">
          {step === 1 && (
            <div className="bg-white p-8 rounded-xl shadow-sm border border-gray-100">
              <div className="grid gap-6">
                <div>
                  <label className="block text-lg font-semibold mb-2">הנחיית המטלה לעיצוב מחדש:</label>
                  <textarea value={assignmentText} onChange={(e) => setAssignmentText(e.target.value)} className="w-full h-40 p-4 border rounded-lg focus:ring-2 focus:ring-green-500" placeholder="מה הסטודנטים צריכים לעשות כיום?" />
                </div>
                <div>
                  <label className="block text-lg font-semibold mb-2">מספר סטודנטים בקורס:</label>
                  <input type="number" value={numStudents} onChange={(e) => setNumStudents(parseInt(e.target.value))} className="w-32 p-3 border rounded-lg font-bold text-indigo-900 focus:ring-2 focus:ring-indigo-500" />
                </div>
              </div>
              <button onClick={() => startRedesign()} disabled={loading || !assignmentText} className="mt-8 w-full bg-green-600 text-white py-4 rounded-lg font-bold text-lg">נתח מיומנויות בטקסונומיית בלום</button>
            </div>
          )}

          {step === 2 && bloomAnalysis && (
            <div className="bg-white p-6 rounded-xl shadow-sm border animate-fade-in">
              <div className="mb-6 p-4 bg-indigo-50 rounded-lg border border-indigo-200">
                <p className="text-indigo-900 font-bold">העוזר הפדגוגי זיהה את המיומנויות הבאות. בחר את אלו שתרצה להעריך במטלה החדשה.</p>
              </div>
              <h3 className="text-xl font-bold mb-4 text-gray-800 border-b pb-2">בחירת מיומנויות יעד</h3>
              <div className="grid gap-3 max-h-[500px] overflow-y-auto pr-2">
                {bloomAnalysis.currentSkills.concat(bloomAnalysis.suggestedSkills).map((skill, idx) => (
                  <div key={idx} className={`flex items-start gap-4 p-4 rounded-xl border transition-all ${selectedSkills.some(s => s.name === skill.name) ? 'bg-indigo-50 border-indigo-400 shadow-sm' : 'bg-gray-50 border-gray-200 opacity-80'}`}>
                    <input type="checkbox" checked={selectedSkills.some(s => s.name === skill.name)} onChange={() => handleSkillToggle(skill)} className="mt-1.5 w-6 h-6 rounded-md cursor-pointer accent-indigo-600" />
                    <div className="flex-1 cursor-pointer" onClick={() => handleSkillToggle(skill)}>
                      <div className="flex items-center gap-2">
                        <span className="font-bold text-indigo-900 text-lg">{skill.name}</span>
                        <span className="text-xs bg-indigo-600 text-white px-2 py-0.5 rounded-full font-semibold">{skill.bloomLevel}</span>
                      </div>
                      <p className="text-sm text-gray-700 mt-1 leading-relaxed">{skill.reasoning}</p>
                    </div>
                  </div>
                ))}
              </div>
              <div className="flex gap-4 mt-8 pt-6 border-t">
                <button onClick={handleGoBack} className="px-8 py-3 border rounded-lg font-bold hover:bg-gray-50">חזור</button>
                <button onClick={handleGetInitialStrategies} disabled={loading || selectedSkills.length === 0} className="flex-1 bg-indigo-600 text-white py-3 rounded-lg font-bold shadow-lg hover:bg-indigo-700 transition-all">המשך לעיצוב ההערכה</button>
              </div>
            </div>
          )}

          {step === 3 && strategies.length > 0 && (
            <div className="space-y-6 animate-fade-in pb-12">
              <div className="bg-white p-8 rounded-2xl shadow-xl border-t-8 border-indigo-600 relative">
                <div className="flex justify-between items-center mb-6">
                  <div>
                    <h3 className="text-2xl font-bold text-indigo-900">ניהול קבוצות מיומנויות</h3>
                    <p className="text-gray-600">לחץ על מיומנות כדי לראות מה היא כוללת ולהעבירה בין קבוצות.</p>
                  </div>
                  <button onClick={() => addNewGroup('מיומנות חדשה')} className="bg-green-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-green-700 transition-all shadow-md">+ הוסף קבוצת הערכה</button>
                </div>

                <div className="space-y-8">
                  {strategies.map((strat, idx) => (
                    <div key={strat.id} className="p-6 rounded-2xl bg-gray-50 border-2 border-indigo-100 shadow-sm transition-all hover:border-indigo-200">
                      <h4 className="text-sm font-bold text-indigo-400 mb-3 uppercase tracking-wider">קבוצת הערכה #{idx+1}</h4>
                      <div className="flex flex-wrap gap-3 mb-6">
                        {strat.skills.map((s, i) => (
                          <button 
                            key={i} 
                            onClick={() => setInspectedSkill({name: s, groupIdx: idx})}
                            className={`skill-btn flex items-center bg-white text-indigo-900 border-2 border-indigo-200 text-sm px-4 py-2 rounded-xl font-bold shadow-sm ${inspectedSkill?.name === s ? 'ring-4 ring-indigo-400 border-indigo-500' : ''}`}
                          >
                            {s}
                          </button>
                        ))}
                      </div>

                      {/* Skill Detail / Inspector */}
                      {inspectedSkill && inspectedSkill.groupIdx === idx && (
                        <div className="mb-6 p-5 bg-white rounded-xl border-2 border-indigo-500 shadow-lg animate-fade-in">
                          <div className="flex justify-between items-start mb-4">
                            <h5 className="font-bold text-lg text-indigo-900">{inspectedSkill.name}</h5>
                            <button onClick={() => setInspectedSkill(null)} className="text-gray-400 hover:text-gray-600">✕</button>
                          </div>
                          <p className="text-sm text-gray-700 mb-6 italic">
                            {bloomAnalysis?.currentSkills.find(sk => sk.name === inspectedSkill.name)?.reasoning || 
                             bloomAnalysis?.suggestedSkills.find(sk => sk.name === inspectedSkill.name)?.reasoning || 
                             "פרטי המיומנות נטענים..."}
                          </p>
                          <div className="flex flex-wrap gap-2 pt-4 border-t border-gray-100">
                            <span className="text-xs font-bold text-gray-400 w-full mb-1">העבר לקבוצה:</span>
                            {strategies.map((target, tIdx) => (
                              target.id !== strat.id && (
                                <button key={target.id} onClick={() => moveSkillToGroup(inspectedSkill.name, target.id)} className="bg-indigo-50 text-indigo-700 text-xs px-3 py-1.5 rounded-lg hover:bg-indigo-600 hover:text-white transition-all">קבוצה {tIdx + 1}</button>
                              )
                            ))}
                            <button onClick={() => addNewGroup(inspectedSkill.name)} className="bg-green-50 text-green-700 text-xs px-3 py-1.5 rounded-lg hover:bg-green-600 hover:text-white transition-all">+ קבוצה חדשה</button>
                          </div>
                        </div>
                      )}

                      <div className="grid md:grid-cols-2 gap-8 pt-4 border-t border-indigo-50">
                        <div>
                          <label className="block text-sm font-bold text-gray-700 mb-3">סוג הערכה:</label>
                          <div className="flex gap-4">
                            <button onClick={() => updateStrategySelection(idx, 'FaceToFace')} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all flex flex-col items-center gap-1 ${strat.userSelectedCategory === 'FaceToFace' ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border-gray-100 hover:border-indigo-200'}`}>פנים אל פנים</button>
                            <button onClick={() => updateStrategySelection(idx, 'Submission')} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all flex flex-col items-center gap-1 ${strat.userSelectedCategory === 'Submission' ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border-gray-100 hover:border-indigo-200'}`}>משימת הגשה</button>
                          </div>
                        </div>

                        {strat.userSelectedCategory && (
                          <div className="animate-fade-in">
                            <label className="block text-sm font-bold text-gray-700 mb-3">שיטה מומלצת:</label>
                            <select value={strat.userSelectedMethod} onChange={(e) => updateStrategySelection(idx, strat.userSelectedCategory!, e.target.value)} className="w-full p-4 border-2 border-indigo-200 rounded-xl bg-white outline-none focus:border-indigo-500 font-medium text-gray-800 shadow-sm transition-all">
                              <option value="">-- בחר שיטה --</option>
                              {Object.entries(CATEGORIZED_OPTIONS[strat.userSelectedCategory as keyof typeof CATEGORIZED_OPTIONS]).map(([catName, options]) => (
                                <optgroup key={catName} label={catName}>
                                  {options.map(opt => <option key={opt} value={opt}>{opt === strat.method ? `✨ מומלץ: ${opt}` : opt}</option>)}
                                </optgroup>
                              ))}
                            </select>
                            <p className="mt-3 text-xs text-indigo-600 font-bold bg-indigo-50 p-2 rounded-lg leading-relaxed">העוזר ממליץ: {strat.explanation}</p>
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
                <div className="flex gap-4 mt-12 pt-8 border-t border-gray-100">
                  <button onClick={handleGoBack} className="px-10 py-4 border-2 rounded-xl font-bold hover:bg-gray-50 transition-all">חזור</button>
                  <button onClick={handleFinalRephrase} disabled={loading} className="flex-1 bg-green-600 text-white py-4 rounded-xl font-bold text-xl shadow-xl hover:bg-green-700 transition-all">צור מטלה וסיכום סופי</button>
                </div>
              </div>
            </div>
          )}

          {step === 4 && (
            <div className="space-y-8 pb-20 animate-fade-in">
              <div className="bg-white p-10 rounded-2xl shadow-xl border-t-8 border-green-600">
                <div className="flex justify-between items-center mb-8 border-b pb-4">
                  <h3 className="text-3xl font-bold text-indigo-900">סיכום המטלה והמלצות פדגוגיות</h3>
                  <div className="bg-green-100 text-green-800 px-5 py-2 rounded-full font-bold text-sm border border-green-200">מוכן לפרסום</div>
                </div>
                <div className="bg-gray-50 p-8 rounded-2xl border border-indigo-100 text-gray-800 whitespace-pre-wrap leading-relaxed text-lg shadow-inner font-sans">
                  {revisedTask}
                </div>
              </div>

              <div className="bg-white p-8 rounded-2xl shadow-md border border-gray-200">
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-indigo-800">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>
                  התאמות נוספות ודיוקים
                </h3>
                <div className="max-h-80 overflow-y-auto mb-6 space-y-4 p-5 bg-gray-50 rounded-xl border shadow-inner">
                  {chatHistory.length === 0 && <p className="text-gray-400 text-center italic py-4">כאן תוכל לבקש מהעוזר לבצע שינויים ספציפיים בטקסט הסופי...</p>}
                  {chatHistory.map((msg, i) => (
                    <div key={i} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}>
                      <div className={`max-w-[85%] p-4 rounded-2xl shadow-sm ${msg.role === 'user' ? 'bg-indigo-100 text-indigo-900 border border-indigo-200' : 'bg-white text-gray-800 border border-gray-200'}`}>{msg.text}</div>
                    </div>
                  ))}
                  <div ref={chatEndRef} />
                </div>
                <div className="flex gap-2">
                  <input type="text" value={followUpQuestion} onChange={(e) => setFollowUpQuestion(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleFollowUp()} placeholder="למשל: 'הוסף טבלת הערכה מפורטת' או 'נסח מחדש כפנייה אישית'..." className="flex-1 p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
                  <button onClick={handleFollowUp} disabled={loading} className="bg-indigo-600 text-white px-8 py-2 rounded-xl font-bold hover:bg-indigo-700 transition-all">שלח</button>
                </div>
              </div>

              <div className="flex gap-4 no-print">
                <button onClick={handleGoBack} className="px-10 py-4 border-2 rounded-xl font-bold hover:bg-gray-100 transition-all">חזור לעריכה</button>
                <button onClick={() => window.print()} className="flex-1 border-2 border-indigo-600 text-indigo-600 py-4 rounded-xl font-bold hover:bg-indigo-50 transition-all">הורדה כ-PDF / הדפסה</button>
                <button onClick={resetToHome} className="flex-1 bg-indigo-600 text-white py-4 rounded-xl font-bold hover:bg-indigo-700 shadow-lg transition-all">סיים וחזור לדף הבית</button>
              </div>
            </div>
          )}
        </div>
      )}

      {loading && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-md flex items-center justify-center z-50">
          <div className="bg-white p-12 rounded-3xl shadow-2xl flex flex-col items-center gap-8 border-2 border-indigo-100 animate-pulse">
            <div className="w-20 h-20 border-8 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <div className="text-center">
              <p className="font-bold text-2xl text-indigo-900 mb-2">העוזר הפדגוגי מעבד את בקשתך...</p>
              <p className="text-indigo-500 font-medium">בונה מערך הערכה מותאם אישית</p>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import Layout from './components/Layout';
import { AppMode, BloomLevel, Skill, AssessmentMethod } from './types';
import { 
  testAiAssignment, 
  analyzeBloomTaxonomy, 
  generateAssessmentStrategies, 
  rephraseAssignment,
  askFollowUpQuestion
} from './services/geminiService';

// Categorized assessment methods refined for better navigation
const CATEGORIZED_OPTIONS = {
  FaceToFace: {
    'בדיקת ידע מהירה (מתאים לכיתות גדולות)': [
      'בחנים קצרים בכיתה (Clickers / LMS)',
      'Polling (הצבעות כיתתיות)',
      'Concept checks (בדיקת ידע מושגי מהיר)',
      'מבחני הבנה בזמן אמת (שאלות סגורות/פתוחות קצרות)'
    ],
    'הערכה מעמיקה ודיון (מתאים לקבוצות קטנות/בינוניות)': [
      'פרזנטציות קצרות בקבוצות (פורמט אחיד)',
      'הצגת תוצר קבוצתי בכיתה',
      'דיונים מונחים בקבוצות משנה',
      'ניתוח דילמה חינוכית בזמן שיעור',
      'Viva - שאלת הבהרה אישית קצרה'
    ],
    'מבחנים פורמליים': [
      'מבחנים כתובים בכיתה (מפוקחים)',
      'מבדקי ביניים קצרים ומרובים',
      'מבחני ביצוע אחידים (Rubric-based)'
    ]
  },
  Submission: {
    'כתיבה ומחקר': [
      'עבודות בית פתוחות',
      'עבודות מחקר אישיות',
      'פרויקט מסכם כתוב',
      'תיק עבודות (Portfolio)'
    ],
    'תהליך ורפלקציה': [
      'יומן רפלקטיבי אישי',
      'הערכת עמיתים (Peer Assessment)',
      'הערכה עצמית',
      'תהליך כתיבה רב-שלבי'
    ],
    'חדשנות ו-AI': [
      'שילוב מבוקר של AI בתהליך',
      'רפלקציה על שימוש ב-AI',
      'סימולציה מול בינה מלאכותית',
      'ניתוח מקרי בוחן (Case studies)'
    ]
  }
};

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('HOME');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);

  const [assignmentText, setAssignmentText] = useState('');
  const [numStudents, setNumStudents] = useState<number>(30);
  const [aiResponse, setAiResponse] = useState('');

  // Scoring state for Test AI mode
  const [lecturerScore, setLecturerScore] = useState<number | ''>('');
  const [lecturerFeedback, setLecturerFeedback] = useState('');

  const [bloomAnalysis, setBloomAnalysis] = useState<{currentSkills: Skill[], suggestedSkills: Skill[]} | null>(null);
  const [selectedSkills, setSelectedSkills] = useState<Skill[]>([]);
  const [strategies, setStrategies] = useState<AssessmentMethod[]>([]);
  const [revisedTask, setRevisedTask] = useState('');

  // UI state for managing skill inspection
  const [inspectedSkill, setInspectedSkill] = useState<{name: string, groupIdx: number} | null>(null);

  const [followUpQuestion, setFollowUpQuestion] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const handleTestAi = async () => {
    if (!assignmentText.trim()) return;
    setLoading(true);
    try {
      const res = await testAiAssignment(assignmentText);
      setAiResponse(res || 'לא התקבלה תשובה');
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בבדיקת המטלה');
    } finally {
      setLoading(false);
    }
  };

  const startRedesign = async (initialText?: string) => {
    const textToAnalyze = initialText || assignmentText;
    if (!textToAnalyze.trim()) {
      alert('אנא הזן את הנחיית המטלה');
      return;
    }
    setAssignmentText(textToAnalyze);
    setMode('REDESIGN');
    setLoading(true);
    try {
      const analysis = await analyzeBloomTaxonomy(textToAnalyze);
      setBloomAnalysis(analysis);
      setSelectedSkills(analysis.currentSkills);
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בניתוח המטלה.');
    } finally {
      setLoading(false);
    }
  };

  const handleSkillToggle = (skill: Skill) => {
    setSelectedSkills(prev => 
      prev.some(s => s.name === skill.name)
        ? prev.filter(s => s.name !== skill.name)
        : [...prev, skill]
    );
  };

  const handleGetInitialStrategies = async () => {
    if (selectedSkills.length === 0) {
      alert('אנא בחר לפחות מיומנות אחת');
      return;
    }
    setLoading(true);
    try {
      const res = await generateAssessmentStrategies(selectedSkills, numStudents);
      const initialized = res.map((s: any) => ({
        ...s,
        userSelectedCategory: s.type,
        userSelectedMethod: s.method // Initially use AI suggestion
      }));
      setStrategies(initialized);
      setStep(3);
    } catch (error) {
      console.error(error);
      alert('שגיאה ביצירת אסטרטגיות');
    } finally {
      setLoading(false);
    }
  };

  const updateStrategySelection = (index: number, category: 'FaceToFace' | 'Submission', method?: string) => {
    const newStrategies = [...strategies];
    newStrategies[index] = {
      ...newStrategies[index],
      userSelectedCategory: category,
      userSelectedMethod: method || ''
    };
    setStrategies(newStrategies);
  };

  const moveSkillToGroup = (skillName: string, targetGroupId: string) => {
    const newStrategies = strategies.map(s => {
      const remainingSkills = s.skills.filter(sk => sk !== skillName);
      if (s.id === targetGroupId) {
        return { ...s, skills: [...s.skills.filter(sk => sk !== skillName), skillName] };
      }
      return { ...s, skills: remainingSkills };
    }).filter(s => s.skills.length > 0);
    setStrategies(newStrategies);
    setInspectedSkill(null);
  };

  const addNewGroup = (skillName: string) => {
    const updatedOldGroups = strategies.map(s => ({
      ...s,
      skills: s.skills.filter(sk => sk !== skillName)
    })).filter(s => s.skills.length > 0);

    const newGroup: AssessmentMethod = {
      id: `group-${Date.now()}`,
      skills: [skillName],
      method: '',
      type: 'FaceToFace',
      explanation: 'קבוצה חדשה שהוגדרה על ידי המרצה.',
      userSelectedCategory: 'FaceToFace',
      userSelectedMethod: ''
    };

    setStrategies([...updatedOldGroups, newGroup]);
    setInspectedSkill(null);
  };

  const handleFinalRephrase = async () => {
    if (!strategies.every(s => s.userSelectedMethod)) {
      alert('אנא בחר שיטת הערכה לכל אחד מהחלקים');
      return;
    }
    setLoading(true);
    try {
      const rephrased = await rephraseAssignment(assignmentText, selectedSkills, strategies, numStudents);
      setRevisedTask(rephrased);
      setStep(4);
    } catch (error) {
      console.error(error);
      alert('שגיאה בניסוח המטלה');
    } finally {
      setLoading(false);
    }
  };

  const handleFollowUp = async () => {
    if (!followUpQuestion.trim()) return;
    const q = followUpQuestion;
    setFollowUpQuestion('');
    setChatHistory(prev => [...prev, { role: 'user', text: q }]);
    setLoading(true);
    try {
      const response = await askFollowUpQuestion({ originalText: assignmentText, revisedTask, strategies }, q, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: response || '' }]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const resetToHome = () => {
    setMode('HOME');
    setStep(1);
    setAssignmentText('');
    setAiResponse('');
    setLecturerScore('');
    setLecturerFeedback('');
    setBloomAnalysis(null);
    setSelectedSkills([]);
    setStrategies([]);
    setRevisedTask('');
    setChatHistory([]);
  };

  const handleGoBack = () => {
    if (step > 1) {
      setStep(step - 1);
    } else {
      setMode('HOME');
    }
  };

  return (
    <Layout 
      title={mode === 'HOME' ? 'Re-Assess' : mode === 'TEST_AI' ? 'בדיקה מול AI' : 'עיצוב מחדש'} 
      onBack={mode !== 'HOME' ? handleGoBack : undefined}
    >
      <style>{`
        .animate-fade-in { animation: fadeIn 0.4s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
        @media print { .no-print { display: none !important; } }

        .skill-btn { transition: all 0.2s; }
        .skill-btn:hover { transform: translateY(-1px); box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
      `}</style>

      {mode === 'HOME' && (
        <div className="flex flex-col items-center gap-8 py-12">
          <div className="text-center space-y-4">
            <h2 className="text-4xl font-bold text-gray-800">איך המטלה שלך נראית בעידן ה-AI?</h2>
            <p className="text-xl text-gray-600 max-w-2xl">שיפור פדגוגיה ומניעת העתקות באמצעות עיצוב מחדש של דרכי הערכה.</p>
          </div>
          <div className="grid md:grid-cols-2 gap-6 w-full max-w-3xl">
            <button onClick={() => { setMode('TEST_AI'); setStep(1); }} className="bg-white border-2 border-indigo-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-indigo-400 text-right group">
              <div className="bg-indigo-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">בדוק מול ה-AI</h3>
              <p className="text-gray-600">ראה כיצד הבינה המלאכותית פותרת את המטלה הקיימת שלך כיום.</p>
            </button>
            <button onClick={() => { setMode('REDESIGN'); setStep(1); }} className="bg-white border-2 border-green-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-green-400 text-right group">
              <div className="bg-green-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-green-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">עיצוב משימה מחדש</h3>
              <p className="text-gray-600">נתח מיומנויות ושדרג את המערך הפדגוגי.</p>
            </button>
          </div>
        </div>
      )}

      {mode === 'TEST_AI' && (
        <div className="space-y-6 animate-fade-in">
          {step === 1 ? (
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
              <label className="block text-lg font-semibold mb-3">הזן את המטלה המקורית לבדיקה:</label>
              <textarea value={assignmentText} onChange={(e) => setAssignmentText(e.target.value)} className="w-full h-48 p-4 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" placeholder="הדבק כאן את הנחיית המטלה שלך..." />
              <button onClick={handleTestAi} disabled={loading || !assignmentText} className="mt-4 w-full bg-indigo-600 text-white py-4 rounded-xl font-bold text-lg shadow-md hover:bg-indigo-700 transition-all">תן לבינה מלאכותית לפתור את המטלה</button>
            </div>
          ) : (
            <div className="space-y-6">
              <div className="bg-blue-50 p-6 rounded-xl border border-blue-200 shadow-inner">
                <h3 className="font-bold text-blue-900 mb-3 text-lg border-b border-blue-100 pb-2">תשובת ה-AI (כך נראה הפתרון האוטומטי):</h3>
                <div className="text-gray-800 whitespace-pre-wrap leading-relaxed bg-white/50 p-4 rounded-lg">{aiResponse}</div>
              </div>

              {/* Feedback and Scoring Section */}
              <div className="bg-white p-6 rounded-2xl border-2 border-indigo-100 shadow-xl space-y-6 animate-fade-in">
                <h3 className="text-xl font-bold text-indigo-900">הערכת מרצה לפתרון ה-AI</h3>

                <div className="grid md:grid-cols-3 gap-6">
                  <div className="md:col-span-1">
                    <label className="block text-sm font-bold text-gray-700 mb-2">ציון למטלה (0-100):</label>
                    <input 
                      type="number" 
                      min="0" 
                      max="100" 
                      value={lecturerScore} 
                      onChange={(e) => setLecturerScore(e.target.value === '' ? '' : Number(e.target.value))}
                      className="w-full p-4 border-2 border-indigo-100 rounded-xl focus:ring-2 focus:ring-indigo-500 font-bold text-2xl text-center text-indigo-900"
                      placeholder="ציון"
                    />
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-sm font-bold text-gray-700 mb-2">פידבק קצר על איכות הפתרון:</label>
                    <textarea 
                      value={lecturerFeedback}
                      onChange={(e) => setLecturerFeedback(e.target.value)}
                      className="w-full p-4 border-2 border-indigo-100 rounded-xl focus:ring-2 focus:ring-indigo-500 h-24"
                      placeholder="האם ה-AI ענה על הכל? האם היה עומק?"
                    />
                  </div>
                </div>

                {/* Recommendations based on score */}
                {lecturerScore !== '' && (
                  <div className="animate-fade-in p-6 rounded-xl border-l-8 border-indigo-600 bg-indigo-50">
                    <h4 className="font-bold text-indigo-900 mb-2 text-lg">
                      {lecturerScore > 70 ? '⚠️ המשימה רגישה ל-AI' : '✅ המשימה עמידה יחסית ל-AI'}
