export const testAiAssignment = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `ענה על המטלה הבאה כסטודנט מצטיין. התשובה צריכה להדגים כיצד סטודנט המשתמש בכלי AI חזקים היה פותר אותה:\n\n${assignmentText}`,
    config: {
      temperature: 0.7,
    }
  });
  return response.text;
};

export const analyzeBloomTaxonomy = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נתח את המטלה הבאה לפי הטקסונומיה של בלום. 
    עליך לזהות את המיומנויות הנדרשות במשימה הנוכחית ולהציע הרחבות שיחזקו את הלמידה.

    כלל פדגוגי מחייב: למידה משמעותית היא היררכית. הניתוח חייב לכלול תמיד את רמות ה"זכירה" (Remember) וה"הבנה" (Understand) כבסיס הידע הכרחי למטלה.

    המטלה: ${assignmentText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          currentSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          },
          suggestedSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          }
        },
        required: ["currentSkills", "suggestedSkills"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateAssessmentStrategies = async (skills: Skill[], numStudents: number) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `עבור רשימת המיומנויות הבאה וכיתה של ${numStudents} סטודנטים, אגד אותן לקבוצות הערכה לוגיות (2-3 קבוצות).

    כללים פדגוגיים להמלצה:
    1. קדם תהליך למידה משמעותי המשלב דרישה להתייחסות לתכנים שנלמדו בשיעור (ולא רק ידע כללי שה-AI מכיר).
    2. שקול אסטרטגיה שבה מיומנויות מסדר נמוך נבדקות במשימת הגשה, בעוד שמיומנויות מסדר גבוה (ניתוח, הערכה, יצירה) מוערכות במפגש פנים-אל-פנים.

    שיטות זמינות:
    FaceToFace: מבחנים כתובים, בחנים ממוחשבים, בחינה בע"פ, שאלות ידע מהירות, הצגת תוצר, הערכת דיון, כתיבה בכיתה, הערכה מדגמית.
    Submission: כתיבת משימה עם AI, משוב על תוצר AI, הערכת עמיתים, הערכה עצמית, סימולציה עם AI.

    המיומנויות שנבחרו: ${JSON.stringify(skills)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            skills: { type: Type.ARRAY, items: { type: Type.STRING } },
            method: { type: Type.STRING, description: "השיטה הספציפית המומלצת מתוך הרשימה" },
            type: { type: Type.STRING, enum: ['FaceToFace', 'Submission'] },
            explanation: { type: Type.STRING, description: "הסבר פדגוגי חיובי ומקדם למידה המדגיש את החיבור לתכנים שנלמדו בשיעור." }
          },
          required: ["skills", "method", "type", "explanation"]
        }
      }
    }
  });

  const res = JSON.parse(response.text);
  return res.map((item: any, index: number) => ({
    ...item,
    id: `group-${index}-${Date.now()}`
  }));
};

export interface TaskSection {
  title: string;
  content: string;
}

export const rephraseAssignment = async (originalText: string, targetSkills: Skill[], strategies: AssessmentMethod[], numStudents: number) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נסח מחדש את המטלה המקורית למטלה אקדמית מעודכנת המעודדת למידה משמעותית.

    דגשים חשובים לניסוח:
    1. הגישה צריכה להיות של 'מלווה למידה'.
    2. חובה לדרוש שילוב של תכנים ספציפיים שנלמדו בשיעור (דיונים, דוגמאות מהכיתה) כדי להבטיח שה-AI משמש כעוזר ולא כמקור ידע בלעדי.
    3. אם נבחרה שיטת "כתיבה והגשת עבודה בכיתה", אל תפרט בהנחיות לסטודנטים את השאלות המדויקות או המשימה המפורטת. ציין רק את הנושא הכללי והכנה נדרשת (למשל: "הכנה על בסיס השיעור בנושא X"), כדי למנוע יצירת תשובות מראש עם AI.
    4. התוצר הסופי חייב להיות מחולק לפרקים ברורים (למשל: רקע, הנחיות לסטודנטים, דגשי הערכה, המלצות למרצה).

    נתונים לשילוב:
    ${strategies.map(s => `- מיומנויות [${s.skills.join(', ')}] בשיטת "${s.userSelectedMethod}" (${s.userSelectedCategory}).`).join('\n')}

    מטלה מקורית: ${originalText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING, description: "Markdown format content for this section." }
          },
          required: ["title", "content"]
        }
      }
    }
  });
  return JSON.parse(response.text) as TaskSection[];
};

export const askFollowUpQuestion = async (
  context: { originalText: string, revisedTask: TaskSection[], strategies: AssessmentMethod[] },
  question: string,
  history: { role: 'user' | 'model', text: string }[]
) => {
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `אתה עוזר פדגוגי מומחה המאמין בלמידה מעצימה. התמקד בחיבור לתוכן שנלמד בשיעור וקידום חשיבה עצמאית.`,
    }
  });
  const response = await chat.sendMessage({ message: question });
  return response.text;
};

