                    <div key={idx} className={`p-6 rounded-2xl border-2 transition-all ${section.status === 'approved' ? 'border-green-400 bg-green-50/30' : section.status === 'removed' ? 'border-gray-200 bg-gray-50 opacity-50' : 'border-indigo-100 bg-white shadow-sm'}`}>
                      <div className="flex justify-between items-center mb-4">
                        <h4 className="text-xl font-bold text-indigo-900">{section.title}</h4>
                        <div className="flex gap-2">
                          <button onClick={() => updateSectionStatus(idx, 'approved')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'approved' ? 'bg-green-600 text-white' : 'bg-white border text-green-600 hover:bg-green-50'}`}>אשר</button>
                          <button onClick={() => toggleSectionEdit(idx)} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.isEditing ? 'bg-indigo-600 text-white shadow-inner' : 'bg-white border text-indigo-600 hover:bg-indigo-50'}`}>{section.isEditing ? 'שמור' : 'ערוך'}</button>
                          <button onClick={() => updateSectionStatus(idx, 'removed')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'removed' ? 'bg-red-600 text-white' : 'bg-white border text-red-600 hover:bg-red-50'}`}>הסר</button>
                        </div>
                      </div>
                      {section.isEditing ? (
                        <textarea className="w-full p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 editor-textarea h-64 bg-indigo-50/20" value={section.content} onChange={(e) => updateSectionContent(idx, e.target.value)} />
                      ) : (
