const renderMarkdown = (text: string) => {
  // Strip ALL asterisks as requested by the user
  const cleanText = text.replace(/\*/g, '');

  let html = cleanText
    // Headings
    .replace(/^### (.*$)/gim, '<h3 class="text-xl font-bold mt-4 mb-2 text-indigo-900">$1</h3>')
    .replace(/^## (.*$)/gim, '<h2 class="text-2xl font-bold mt-6 mb-3 text-indigo-900">$1</h2>')
    .replace(/^# (.*$)/gim, '<h1 class="text-3xl font-bold mt-8 mb-4 text-indigo-900">$1</h1>')
    // Newlines
    .replace(/\n/gim, '<br />');

  return { __html: html };
};

interface SectionState extends TaskSection {
  status: 'pending' | 'approved' | 'removed';
  isEditing: boolean;
}

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('HOME');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);
  const [assignmentText, setAssignmentText] = useState('');
  const [numStudents, setNumStudents] = useState<number>(30);
  const [aiResponse, setAiResponse] = useState('');
  const [lecturerScore, setLecturerScore] = useState<number | ''>('');
  const [lecturerFeedback, setLecturerFeedback] = useState('');
  const [bloomAnalysis, setBloomAnalysis] = useState<{currentSkills: Skill[], suggestedSkills: Skill[]} | null>(null);
  const [selectedSkills, setSelectedSkills] = useState<Skill[]>([]);
  const [strategies, setStrategies] = useState<AssessmentMethod[]>([]);
  const [revisedSections, setRevisedSections] = useState<SectionState[]>([]);
  const [inspectedSkill, setInspectedSkill] = useState<{name: string, groupIdx: number} | null>(null);
  const [followUpQuestion, setFollowUpQuestion] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [copySuccess, setCopySuccess] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const handleTestAi = async () => {
    if (!assignmentText.trim()) return;
    setLoading(true);
    try {
      const res = await testAiAssignment(assignmentText);
      setAiResponse(res || 'לא התקבלה תשובה');
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בבדיקת המטלה');
    } finally {
      setLoading(false);
    }
  };

  const startRedesign = async (initialText?: string) => {
    const textToAnalyze = initialText || assignmentText;
    if (!textToAnalyze.trim()) return;
    setAssignmentText(textToAnalyze);
    setMode('REDESIGN');
    setLoading(true);
    try {
      const analysis = await analyzeBloomTaxonomy(textToAnalyze);
      setBloomAnalysis(analysis);
      setSelectedSkills(analysis.currentSkills);
      setStep(2);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleSkillToggle = (skill: Skill) => {
    setSelectedSkills(prev => 
      prev.some(s => s.name === skill.name) ? prev.filter(s => s.name !== skill.name) : [...prev, skill]
    );
  };

  const handleGetInitialStrategies = async () => {
    if (selectedSkills.length === 0) return;
    setLoading(true);
    try {
      const res = await generateAssessmentStrategies(selectedSkills, numStudents);
      setStrategies(res.map((s: any) => ({ ...s, userSelectedCategory: s.type, userSelectedMethod: s.method })));
      setStep(3); 
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const updateStrategySelection = (index: number, category: 'FaceToFace' | 'Submission', method?: string) => {
    const newStrategies = [...strategies];
    newStrategies[index] = { ...newStrategies[index], userSelectedCategory: category, userSelectedMethod: method || '' };
    setStrategies(newStrategies);
  };

  const moveSkillToGroup = (skillName: string, targetGroupId: string) => {
    const newStrategies = strategies.map(s => {
      const remainingSkills = s.skills.filter(sk => sk !== skillName);
      if (s.id === targetGroupId) return { ...s, skills: [...s.skills.filter(sk => sk !== skillName), skillName] };
      return { ...s, skills: remainingSkills };
    }).filter(s => s.skills.length > 0);
    setStrategies(newStrategies);
    setInspectedSkill(null);
  };

  const addNewGroup = (skillName: string, isDefense: boolean = false) => {
    const updatedOldGroups = strategies.map(s => ({ ...s, skills: s.skills.filter(sk => sk !== skillName) })).filter(s => s.skills.length > 0);
    const newGroup: AssessmentMethod = {
      id: `group-${Date.now()}`,
      skills: skillName === 'כללי' ? ['תיקוף ידע פנים-מול-פנים'] : [skillName],
      method: isDefense ? 'בחינה אישית בע"פ' : '',
      type: 'FaceToFace',
      explanation: isDefense ? 'שלב ליווי פנים-אל-פנים לחיזוק הקשר ווידוא הבנה לאחר הגשה.' : 'קבוצה חדשה.',
      userSelectedCategory: 'FaceToFace',
      userSelectedMethod: isDefense ? 'בחינה אישית בע"פ' : ''
    };
    setStrategies([...updatedOldGroups, newGroup]);
    setInspectedSkill(null);
  };

  const handleFinalRephrase = async () => {
    if (!strategies.every(s => s.userSelectedMethod)) return;
    setLoading(true);
    try {
      const sections = await rephraseAssignment(assignmentText, selectedSkills, strategies, numStudents);
      setRevisedSections(sections.map(s => ({ ...s, status: 'pending', isEditing: false })));
      setStep(4);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleFollowUp = async () => {
    if (!followUpQuestion.trim()) return;
    const q = followUpQuestion;
    setFollowUpQuestion('');
    setChatHistory(prev => [...prev, { role: 'user', text: q }]);
    setLoading(true);
    try {
      const response = await askFollowUpQuestion({ originalText: assignmentText, revisedTask: revisedSections, strategies }, q, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: response || '' }]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const resetToHome = () => {
    setMode('HOME');
    setStep(1);
    setAssignmentText('');
    setAiResponse('');
    setLecturerScore('');
    setLecturerFeedback('');
    setBloomAnalysis(null);
    setSelectedSkills([]);
    setStrategies([]);
    setRevisedSections([]);
    setChatHistory([]);
  };

  const handleGoBack = () => {
    setStep(prev => prev > 1 ? prev - 1 : prev);
    if (step === 1) setMode('HOME');
  };

  const shouldShowDefenseSuggestion = (idx: number, strat: AssessmentMethod) => {
    if (idx !== 1) return false; 
    const isAiSubmission = strat.userSelectedCategory === 'Submission';
    const hasAnyFaceToFace = strategies.some((s) => s.userSelectedCategory === 'FaceToFace');
    return isAiSubmission && !hasAnyFaceToFace;
  };

  const updateSectionStatus = (index: number, status: 'approved' | 'removed') => {
    const newSections = [...revisedSections];
    newSections[index].status = status;
    setRevisedSections(newSections);
  };

  const updateSectionContent = (index: number, content: string) => {
    const newSections = [...revisedSections];
    newSections[index].content = content;
    setRevisedSections(newSections);
  };

  const toggleSectionEdit = (index: number) => {
    const newSections = [...revisedSections];
    newSections[index].isEditing = !newSections[index].isEditing;
    setRevisedSections(newSections);
  };

  const copyAllToClipboard = () => {
    const text = revisedSections
      .filter(s => s.status === 'approved')
      .map(s => `${s.title}\n\n${s.content.replace(/\*/g, '')}`)
      .join('\n\n---\n\n');
    navigator.clipboard.writeText(text).then(() => {
      setCopySuccess(true);
      setTimeout(() => setCopySuccess(false), 2000);
    });
  };

  const allSectionsHandled = revisedSections.length > 0 && revisedSections.every(s => s.status !== 'pending');
  const hasApprovedSections = revisedSections.some(s => s.status === 'approved');

  return (
    <Layout title={mode === 'HOME' ? 'Re-Assess' : mode === 'TEST_AI' ? 'בדיקה מול AI' : 'עיצוב מחדש'} onBack={mode !== 'HOME' ? handleGoBack : undefined}>
      <style>{`
        .animate-fade-in { animation: fadeIn 0.4s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }

        .skill-btn { transition: all 0.2s; }
        .skill-btn:hover { transform: translateY(-1px); box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
        .font-sans-normal { font-style: normal !important; font-family: 'Assistant', sans-serif; }

        .editor-textarea {
          font-family: 'Assistant', sans-serif;
          line-height: 1.625;
          font-size: 1.125rem;
          color: #1f2937;
        }
      `}</style>

      {mode === 'HOME' && (
        <div className="flex flex-col items-center gap-8 py-12">
          <div className="text-center space-y-4">
            <h2 className="text-4xl font-bold text-gray-800">איך המטלה שלך נראית בעידן ה-AI?</h2>
            <p className="text-xl text-gray-600 max-w-2xl">שיפור פדגוגיה ועידוד למידה משמעותית באמצעות עיצוב מחדש של דרכי הערכה.</p>
          </div>
          <div className="grid md:grid-cols-2 gap-6 w-full max-w-3xl">
            <button onClick={() => { setMode('TEST_AI'); setStep(1); }} className="bg-white border-2 border-indigo-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-indigo-400 text-right group transition-all">
              <div className="bg-indigo-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">בדוק מול ה-AI</h3>
              <p className="text-gray-600">ראה כיצד הבינה המלאכותית פותרת את המטלה הקיימת ונתח את העומק הפדגוגי שלה.</p>
            </button>
            <button onClick={() => { setMode('REDESIGN'); setStep(1); }} className="bg-white border-2 border-green-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-green-400 text-right group transition-all">
              <div className="bg-green-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-green-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">עיצוב למידה מחדש</h3>
              <p className="text-gray-600">נתח מיומנויות ושדרג את המערך הפדגוגי לליווי מיטבי של הסטודנטים.</p>
            </button>
          </div>
        </div>
      )}

      {mode === 'TEST_AI' && (
        <div className="space-y-6 animate-fade-in">
          {step === 1 ? (
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
              <label className="block text-lg font-semibold mb-3">הזן את המטלה המקורית לבדיקה:</label>
              <textarea value={assignmentText} onChange={(e) => setAssignmentText(e.target.value)} className="w-full h-48 p-4 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" placeholder="הדבק כאן את הנחיית המטלה שלך..." />
              <button onClick={handleTestAi} disabled={loading || !assignmentText} className="mt-4 w-full bg-indigo-600 text-white py-4 rounded-xl font-bold text-lg shadow-md hover:bg-indigo-700 transition-all">הדגם פתרון AI</button>
            </div>
          ) : (
            <div className="space-y-6">
              <div className="bg-blue-50 p-6 rounded-xl border border-blue-200 shadow-inner">
                <h3 className="font-bold text-blue-900 mb-3 text-lg border-b border-blue-100 pb-2">תשובת ה-AI:</h3>
                <div className="text-gray-800 whitespace-pre-wrap leading-relaxed bg-white p-4 rounded-lg shadow-sm font-sans-normal text-lg">{aiResponse}</div>
              </div>

              <div className="bg-white p-6 rounded-2xl border-2 border-indigo-100 shadow-xl space-y-6 animate-fade-in">
                <h3 className="text-xl font-bold text-indigo-900">הערכת מרצה לפתרון ה-AI</h3>
                <div className="grid md:grid-cols-3 gap-6">
                  <div className="md:col-span-1">
                    <label className="block text-sm font-bold text-gray-700 mb-2">ציון למטלה (0-100):</label>
                    <input type="number" min="0" max="100" value={lecturerScore} onChange={(e) => setLecturerScore(e.target.value === '' ? '' : Number(e.target.value))} className="w-full p-4 border-2 border-indigo-100 rounded-xl focus:ring-2 focus:ring-indigo-500 font-bold text-2xl text-center text-indigo-900" placeholder="ציון" />
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-sm font-bold text-gray-700 mb-2">פידבק קצר על איכות הפתרון:</label>
                    <textarea value={lecturerFeedback} onChange={(e) => setLecturerFeedback(e.target.value)} className="w-full p-4 border-2 border-indigo-100 rounded-xl focus:ring-2 focus:ring-indigo-500 h-24" placeholder="האם ה-AI הצליח להגיע לעומק הנדרש?" />
                  </div>
                </div>
                {lecturerScore !== '' && (
                  <div className="animate-fade-in p-6 rounded-xl border-l-8 border-indigo-600 bg-indigo-50">
                    <h4 className="font-bold text-indigo-900 mb-2 text-lg">{lecturerScore > 70 ? '⚠️ המשימה מאפשרת פתרון AI מהיר' : '✅ המשימה מאתגרת את ה-AI'}</h4>
                    <p className="text-gray-700">{lecturerScore > 70 ? 'נראה שהבינה המלאכותית מספקת מענה איכותי בקלות.' : 'המשימה שלך דורשת מיומנויות שה-AI מתקשה בהן.'}</p>
                  </div>
                )}
                <div className="flex flex-wrap gap-4 pt-4">
                  <button onClick={() => setStep(1)} className="flex-1 border-2 border-indigo-600 text-indigo-600 py-3 rounded-xl font-bold hover:bg-indigo-50 transition-all">דיוק המשימה וניסיון נוסף</button>
                  <button onClick={() => startRedesign()} className="flex-1 bg-green-600 text-white py-3 rounded-xl font-bold shadow-lg hover:bg-green-700 transition-all">עבור לעיצוב פדגוגי מקיף</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {mode === 'REDESIGN' && (
        <div className="space-y-6 animate-fade-in">
          {step === 1 && (
            <div className="bg-white p-8 rounded-xl shadow-sm border border-gray-100">
              <div className="grid gap-6">
                <div>
                  <label className="block text-lg font-semibold mb-2">הנחיית המטלה לעיצוב מחדש:</label>
                  <textarea value={assignmentText} onChange={(e) => setAssignmentText(e.target.value)} className="w-full h-40 p-4 border rounded-lg focus:ring-2 focus:ring-green-500" placeholder="מה הסטודנטים צריכים לעשות כיום?" />
                </div>
                <div>
                  <label className="block text-lg font-semibold mb-2">מספר סטודנטים בקורס:</label>
                  <input type="number" value={numStudents} onChange={(e) => setNumStudents(parseInt(e.target.value))} className="w-32 p-3 border rounded-lg font-bold text-indigo-900 focus:ring-2 focus:ring-indigo-500" />
                </div>
              </div>
              <button onClick={() => startRedesign()} disabled={loading || !assignmentText} className="mt-8 w-full bg-green-600 text-white py-4 rounded-lg font-bold text-lg">נתח מיומנויות בטקסונומיית בלום</button>
            </div>
          )}

          {step === 2 && bloomAnalysis && (
            <div className="bg-white p-6 rounded-xl shadow-sm border animate-fade-in">
              <div className="mb-6 p-4 bg-indigo-50 rounded-lg border border-indigo-200">
                <p className="text-indigo-900 font-bold">העוזר הפדגוגי זיהה את המיומנויות הבאות. בחר את אלו שתרצה להעריך במטלה החדשה.</p>
              </div>
              <h3 className="text-xl font-bold mb-4 text-gray-800 border-b pb-2">בחירת מיומנויות יעד</h3>
              <div className="grid gap-3 max-h-[500px] overflow-y-auto pr-2">
                {bloomAnalysis.currentSkills.concat(bloomAnalysis.suggestedSkills).map((skill, idx) => (
                  <div key={idx} className={`flex items-start gap-4 p-4 rounded-xl border transition-all ${selectedSkills.some(s => s.name === skill.name) ? 'bg-indigo-50 border-indigo-400 shadow-sm' : 'bg-gray-50 border-gray-200 opacity-80'}`}>
                    <input type="checkbox" checked={selectedSkills.some(s => s.name === skill.name)} onChange={() => handleSkillToggle(skill)} className="mt-1.5 w-6 h-6 rounded-md cursor-pointer accent-indigo-600" />
                    <div className="flex-1 cursor-pointer" onClick={() => handleSkillToggle(skill)}>
                      <div className="flex items-center gap-2">
                        <span className="font-bold text-indigo-900 text-lg">{skill.name}</span>
                        <span className="text-xs bg-indigo-600 text-white px-2 py-0.5 rounded-full font-semibold">{skill.bloomLevel}</span>
                      </div>
                      <p className="text-sm text-gray-700 mt-1 leading-relaxed">{skill.reasoning}</p>
                    </div>
                  </div>
                ))}
              </div>
              <div className="flex gap-4 mt-8 pt-6 border-t">
                <button onClick={handleGoBack} className="px-8 py-3 border rounded-lg font-bold hover:bg-gray-50">חזור</button>
                <button onClick={handleGetInitialStrategies} disabled={loading || selectedSkills.length === 0} className="flex-1 bg-indigo-600 text-white py-3 rounded-lg font-bold shadow-lg hover:bg-indigo-700 transition-all">המשך לניהול קבוצות מיומנויות</button>
              </div>
            </div>
          )}

          {step === 3 && strategies.length > 0 && (
            <div className="space-y-6 animate-fade-in pb-12">
              <div className="bg-white p-8 rounded-2xl shadow-xl border-t-8 border-indigo-600 relative">
                <div className="flex justify-between items-center mb-6">
                  <div>
                    <h3 className="text-2xl font-bold text-indigo-900">ניהול קבוצות מיומנויות</h3>
                    <p className="text-gray-600">התאם את הקבוצות לפי שיקול דעתך. העוזר מתחשב ב-{numStudents} סטודנטים.</p>
                  </div>
                  <button onClick={() => addNewGroup('מיומנות חדשה')} className="bg-green-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-green-700 transition-all shadow-md">+ הוסף קבוצה</button>
                </div>
                <div className="space-y-8">
                  {strategies.map((strat, idx) => (
                    <div key={strat.id} className="p-6 rounded-2xl bg-gray-50 border-2 border-indigo-100 shadow-sm">
                      <h4 className="text-sm font-bold text-indigo-400 mb-3 uppercase">קבוצת הערכה #{idx+1}</h4>
                      <div className="flex flex-wrap gap-3 mb-6">
                        {strat.skills.map((s, i) => (
                          <button key={i} onClick={() => setInspectedSkill({name: s, groupIdx: idx})} className={`skill-btn flex items-center bg-white text-indigo-900 border-2 border-indigo-200 text-sm px-4 py-2 rounded-xl font-bold shadow-sm ${inspectedSkill?.name === s ? 'ring-4 ring-indigo-400' : ''}`}>{s}</button>
                        ))}
                      </div>
                      {inspectedSkill && inspectedSkill.groupIdx === idx && (
                        <div className="mb-6 p-5 bg-white rounded-xl border-2 border-indigo-500 shadow-lg animate-fade-in">
                          <div className="flex justify-between items-start mb-4">
                            <h5 className="font-bold text-lg text-indigo-900">{inspectedSkill.name}</h5>
                            <button onClick={() => setInspectedSkill(null)} className="text-gray-400 hover:text-gray-600">✕</button>
                          </div>
                          <div className="flex flex-wrap gap-2 pt-4 border-t">
                            <span className="text-xs font-bold text-gray-400 w-full mb-1">העבר לקבוצה:</span>
                            {strategies.map((target, tIdx) => target.id !== strat.id && <button key={target.id} onClick={() => moveSkillToGroup(inspectedSkill.name, target.id)} className="bg-indigo-50 text-indigo-700 text-xs px-3 py-1.5 rounded-lg hover:bg-indigo-600 hover:text-white">קבוצה {tIdx + 1}</button>)}
                            <button onClick={() => addNewGroup(inspectedSkill.name)} className="bg-green-50 text-green-700 text-xs px-3 py-1.5 rounded-lg hover:bg-green-600 hover:text-white">+ קבוצה חדשה</button>
                          </div>
                        </div>
                      )}
                      <div className="grid md:grid-cols-2 gap-8 pt-4 border-t">
                        <div>
                          <label className="block text-sm font-bold text-gray-700 mb-3">סוג הערכה:</label>
                          <div className="flex gap-4">
                            <button onClick={() => updateStrategySelection(idx, 'FaceToFace')} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all ${strat.userSelectedCategory === 'FaceToFace' ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border-gray-100 hover:border-indigo-200'}`}>פנים אל פנים</button>
                            <button onClick={() => updateStrategySelection(idx, 'Submission')} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all ${strat.userSelectedCategory === 'Submission' ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border-gray-100 hover:border-indigo-200'}`}>משימת הגשה</button>
                          </div>
                        </div>
                        {strat.userSelectedCategory && (
                          <div className="animate-fade-in">
                            <label className="block text-sm font-bold text-gray-700 mb-3">בחירת שיטה:</label>
                            <select 
                              value={strat.userSelectedMethod} 
                              onChange={(e) => updateStrategySelection(idx, strat.userSelectedCategory!, e.target.value)} 
                              className="w-full p-4 border-2 border-indigo-200 rounded-xl bg-white outline-none focus:border-indigo-500 font-medium text-gray-800 shadow-sm appearance-none"
                            >
                              <option value="">-- בחר שיטה --</option>
                              {(() => {
                                // Filter unique options between general and defense
                                const baseOptions = CATEGORIZED_OPTIONS[strat.userSelectedCategory];
                                const defenseOptions = strat.userSelectedCategory === 'FaceToFace' ? CATEGORIZED_OPTIONS.Defense : [];

                                // Clean up duplicate options: only show them once regardless of where they come from
                                const combined = Array.from(new Set([...baseOptions, ...defenseOptions]));

                                return combined.map(opt => (
                                  <option key={opt} value={opt}>
                                    {opt === strat.method ? `${opt} (מומלץ)` : opt}
                                  </option>
                                ));
                              })()}
                            </select>
                            <p className="mt-3 text-xs text-indigo-600 font-bold bg-indigo-50 p-2 rounded-lg leading-relaxed">העוזר מציע: {strat.explanation}</p>
                            {shouldShowDefenseSuggestion(idx, strat) && (
                              <button onClick={() => addNewGroup('כללי', true)} className="mt-3 w-full text-xs bg-amber-50 text-amber-700 border border-amber-200 p-2 rounded-lg font-bold hover:bg-amber-100 shadow-sm transition-colors">+ הצעה: הוספת שלב ליווי פנים-אל-פנים לאחר ההגשה</button>
                            )}
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
                <div className="flex gap-4 mt-12 pt-8 border-t">
                  <button onClick={handleGoBack} className="px-10 py-4 border-2 rounded-xl font-bold hover:bg-gray-50 transition-all">חזור</button>
                  <button onClick={handleFinalRephrase} disabled={loading} className="flex-1 bg-green-600 text-white py-4 rounded-xl font-bold text-xl shadow-xl hover:bg-green-700 transition-all">צור מטלה וסיכום למידה</button>
                </div>
              </div>
            </div>
          )}

          {step === 4 && (
            <div className="space-y-8 pb-20 animate-fade-in">
              <div className="bg-white p-10 rounded-2xl shadow-xl border-t-8 border-green-600">
                <div className="flex justify-between items-center mb-8 border-b pb-4">
                  <h3 className="text-3xl font-bold text-indigo-900">ניהול ואישור חלקי המטלה</h3>
                  <div className={`px-5 py-2 rounded-full font-bold text-sm border shadow-sm transition-colors ${allSectionsHandled ? 'bg-green-100 text-green-800 border-green-200' : 'bg-amber-100 text-amber-800 border-amber-200'}`}>
                    {allSectionsHandled ? 'כל החלקים טופלו' : 'יש לאשר או לערוך את כל החלקים'}
                  </div>
                </div>
                <div className="space-y-6">
                  {revisedSections.map((section, idx) => (
                    <div key={idx} className={`p-6 rounded-2xl border-2 transition-all ${section.status === 'approved' ? 'border-green-400 bg-green-50/30' : section.status === 'removed' ? 'border-gray-200 bg-gray-50 opacity-50' : 'border-indigo-100 bg-white shadow-sm'}`}>
                      <div className="flex justify-between items-center mb-4">
                        <h4 className="text-xl font-bold text-indigo-900">{section.title}</h4>
                        <div className="flex gap-2">
                          <button onClick={() => updateSectionStatus(idx, 'approved')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'approved' ? 'bg-green-600 text-white' : 'bg-white border text-green-600 hover:bg-green-50'}`}>אשר</button>
                          <button onClick={() => toggleSectionEdit(idx)} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.isEditing ? 'bg-indigo-600 text-white shadow-inner' : 'bg-white border text-indigo-600 hover:bg-indigo-50'}`}>{section.isEditing ? 'שמור' : 'ערוך'}</button>
                          <button onClick={() => updateSectionStatus(idx, 'removed')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'removed' ? 'bg-red-600 text-white' : 'bg-white border text-red-600 hover:bg-red-50'}`}>הסר</button>
                        </div>
                      </div>
                      {section.isEditing ? (
                        <textarea className="w-full p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 editor-textarea h-64 bg-white" value={section.content} onChange={(e) => updateSectionContent(idx, e.target.value)} />
                      ) : (
                        <div className="prose prose-indigo max-w-none text-gray-800 leading-relaxed font-sans-normal whitespace-pre-wrap text-lg" dangerouslySetInnerHTML={renderMarkdown(section.content)} />
                      )}
                    </div>
                  ))}
                </div>
                <div className="mt-8 pt-6 border-t flex flex-wrap gap-4">
                  <button onClick={copyAllToClipboard} disabled={!hasApprovedSections} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all ${copySuccess ? 'bg-green-600 text-white border-green-600' : 'border-indigo-600 text-indigo-600 hover:bg-indigo-50 shadow-md'}`}>
                    {copySuccess ? 'הטקסט הועתק!' : 'העתק את כל חלקי המטלה שאושרו'}
                  </button>
                </div>
              </div>

              <div className="bg-white p-8 rounded-2xl shadow-md border border-gray-200 hide-on-print">
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-indigo-800"><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>דיוק והתייעצות נוספת</h3>
                <div className="max-h-80 overflow-y-auto mb-6 space-y-4 p-5 bg-gray-50 rounded-xl border shadow-inner">
                  {chatHistory.length === 0 && <p className="text-gray-400 text-center italic py-4">שאל שאלות נוספות לדיוק המטלה...</p>}
                  {chatHistory.map((msg, i) => (
                    <div key={i} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}><div className={`max-w-[85%] p-4 rounded-2xl shadow-sm ${msg.role === 'user' ? 'bg-indigo-100 text-indigo-900 border border-indigo-200' : 'bg-white text-gray-800 border border-gray-200'}`}>{msg.text}</div></div>
                  ))}
                  <div ref={chatEndRef} />
                </div>
                <div className="flex gap-2">
                  <input type="text" value={followUpQuestion} onChange={(e) => setFollowUpQuestion(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleFollowUp()} placeholder="שאל שאלה נוספת..." className="flex-1 p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
                  <button onClick={handleFollowUp} disabled={loading} className="bg-indigo-600 text-white px-8 py-2 rounded-xl font-bold hover:bg-indigo-700 transition-all">שלח</button>
                </div>
              </div>
              <div className="flex gap-4 hide-on-print">
                <button onClick={handleGoBack} className="px-10 py-4 border-2 rounded-xl font-bold hover:bg-gray-100 transition-all">חזור</button>
                <button onClick={resetToHome} className="flex-1 bg-indigo-900 text-white py-4 rounded-xl font-bold hover:bg-black shadow-lg transition-all">סיים וחזור לדף הבית</button>
              </div>
            </div>
          )}
        </div>
      )}

      {loading && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-md flex items-center justify-center z-50">
          <div className="bg-white p-12 rounded-3xl shadow-2xl flex flex-col items-center gap-8 border-2 border-indigo-100 animate-pulse">
            <div className="w-20 h-20 border-8 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <div className="text-center"><p className="font-bold text-2xl text-indigo-900 mb-2">מעבד פדגוגיה...</p></div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import Layout from './components/Layout';
import { AppMode, BloomLevel, Skill, AssessmentMethod } from './types';
import { 
  testAiAssignment, 
  analyzeBloomTaxonomy, 
  generateAssessmentStrategies, 
  rephraseAssignment, 
  askFollowUpQuestion,
  TaskSection
} from './services/geminiService';

