export const testAiAssignment = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `ענה על המטלה הבאה כסטודנט מצטיין. 
    החזר אך ורק את פתרון המטלה עצמו, כפי שסטודנט היה מגיש אותו. 
    אל תכתוב הקדמות (כמו "הנה הפתרון..."), אל תכתוב הערות מטא, ואל תכתוב סיכומים על איך ה-AI עזר. 
    התוצר חייב להיראות כעבודה אקדמית מושלמת ונקייה בלבד:\n\n${assignmentText}`,
    config: {
      temperature: 0.7,
    }
  });
  return response.text;
};

export const analyzeBloomTaxonomy = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נתח את המטלה הבאה לפי הטקסונומיה של בלום. 
    עליך לזהות את המיומנויות הנדרשות במשימה הנוכחית ולהציע הרחבות שיחזקו את הלמידה.

    כלל פדגוגי מחייב: למידה משמעותית היא היררכית. הניתוח חייב לכלול תמיד את רמות ה"זכירה" (Remember) וה"הבנה" (Understand) כבסיס הידע הכרחי למטלה.

    דגש פדגוגי קריטי לרמת ה"זכירה": 
    התייחס לזכירה של טרמינולוגיה, עקרונות, מבנים מושגיים או עוגני ידע מרכזיים שנלמדו. 
    הימנע מהתמקדות בפרטים ספציפיים מדי או זוטות טכניות. המטרה היא זיהוי של תשתיות הידע ההכרחיות.

    המטלה: ${assignmentText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          currentSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          },
          suggestedSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          }
        },
        required: ["currentSkills", "suggestedSkills"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateAssessmentStrategies = async (skills: Skill[], numStudents: number) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `עבור רשימת המיומנויות הבאה וכיתה של ${numStudents} סטודנטים, אגד אותן לקבוצות הערכה לוגיות (2-3 קבוצות).

    כללים פדגוגיים להמלצה:
    1. קדם תהליך למידה משמעותי המשלב דרישה להתייחסות לתכנים ספציפיים שנלמדו בשיעור (ולא רק ידע כללי שה-AI מכיר).
    2. התחשב בגודל הכיתה (${numStudents} סטודנטים): הצע שיטות בנות-יישום (Scalable). למשל, לכיתה גדולה הצע הערכה מדגמית או בחנים ממוחשבים, ולכיתה קטנה הצע בחינה בע"פ.
    3. שקול אסטרטגיה שבה מיומנויות מסדר נמוך נבדקות במשימת הגשה, בעוד שמיומנויות מסדר גבוה מוערכות במפגש פנים-אל-פנים.

    שיטות זמינות:
    FaceToFace (הערכה בסביבה מבוקרת): מבחן כתוב, בוחן ממוחשב, בחינה בע"פ, שאלות ידע בשיעור, הצגת תוצר, הערכת דיון, כתיבה בכיתה, הערכה מדגמית.
    Submission (הערכה בסביבה פתוחה): כתיבת משימה עם AI, משוב על תוצר AI, הערכת עמיתים, הערכה עצמית, סימולציה עם AI.

    המיומנויות שנבחרו: ${JSON.stringify(skills)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            skills: { type: Type.ARRAY, items: { type: Type.STRING } },
            method: { type: Type.STRING, description: "השיטה הספציפית המומלצת מתוך הרשימה" },
            type: { type: Type.STRING, enum: ['FaceToFace', 'Submission'] },
            explanation: { type: Type.STRING, description: "הסבר פדגוגי המדגיש את החיבור לתכנים שנלמדו בשיעור ואת ההתאמה לגודל הכיתה." }
          },
          required: ["skills", "method", "type", "explanation"]
        }
      }
    }
  });

  const res = JSON.parse(response.text);
  return res.map((item: any, index: number) => ({
    ...item,
    id: `group-${index}-${Date.now()}`
  }));
};

export interface TaskSection {
  title: string;
  content: string;
  audience: 'student' | 'lecturer';
}

export const rephraseAssignment = async (originalText: string, targetSkills: Skill[], strategies: AssessmentMethod[], numStudents: number) => {
  const labelsMap = {
    FaceToFace: 'הערכה בסביבה מבוקרת',
    Submission: 'הערכה בסביבה פתוחה'
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נסח מחדש את המטלה המקורית למטלה אקדמית מעודכנת. המטרה היא יצירת "משימת הערכה" שלמה ומפורטת.

    כללים מבניים חובה:
    1. עבור הסטודנטים: חלק את ההנחיות לפרקים נפרדים עבור כל אחד ממרכיבי המטלה.
       עבור כל אסטרטגיה ברשימה להלן, צור אובייקט TaskSection נפרד (audience: 'student') עם כותרת בפורמט: "חלק [מספר]: [שיטת ההערכה]".
       כל חלק כזה חייב להסביר לסטודנט בדיוק מה עליו לעשות ובאילו מיומנויות הוא משתמש.
    2. עבור המרצה: צור לפחות 2 פרקים נפרדים (audience: 'lecturer'):
       א. "שיקולי דעת פדגוגיים" - הסבר מדוע נבחרו השיטות הללו.
       ב. "הנחיות לוגיסטיות ודגשים לבדיקה" - כיצד לבצע את ההערכה בפועל עבור ${numStudents} סטודנטים.

    דגשים פדגוגיים:
    - דרוש שילוב של תכנים ספציפיים שנלמדו בשיעור.
    - הימנע משימוש מופרז בכוכביות (*) - שמור על טקסט נקי.

    נתונים לשילוב:
    ${strategies.map((s, idx) => `- אסטרטגיה ${idx + 1}: מיומנויות [${s.skills.join(', ')}] בשיטת "${s.userSelectedMethod}" (סוג: ${labelsMap[s.userSelectedCategory as keyof typeof labelsMap]}).`).join('\n')}

    מטלה מקורית: ${originalText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            audience: { type: Type.STRING, enum: ['student', 'lecturer'] }
          },
          required: ["title", "content", "audience"]
        }
      }
    }
  });
  return JSON.parse(response.text) as TaskSection[];
};

export const askFollowUpQuestion = async (
  context: { originalText: string, revisedTask: TaskSection[], strategies: AssessmentMethod[] },
  question: string,
  history: { role: 'user' | 'model', text: string }[]
) => {
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `אתה עוזר פדגוגי מומחה. התמקד בחיבור לתוכן שנלמד בשיעור ובשיטות הערכה מגוונות.`,
    }
  });
  const response = await chat.sendMessage({ message: question });
  return response.text;
};

