              </InfoBox>
              <label className="block text-lg font-semibold mb-3">נוסח המטלה הנוכחי:</label>
              <textarea value={assignmentText} onChange={(e) => setAssignmentText(e.target.value)} className="w-full h-48 p-4 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" placeholder="הדבק כאן את הנחיית המטלה שלך..." />
              <button onClick={handleTestAi} disabled={loading || !assignmentText} className="mt-4 w-full bg-indigo-600 text-white py-4 rounded-xl font-bold text-lg shadow-md hover:bg-indigo-700 transition-all">הדגם פתרון AI</button>
            </div>
          ) : (
            <div className="space-y-6">
              <InfoBox title="שלב 2: ניתוח התוצאה">
                לפניך פתרון שהופק על ידי AI. בחן אותו בעיניים של מרצה: האם הוא עונה על הדרישות? האם חסר בו עומק? תן ציון ופידבק כדי להחליט אם המטלה זקוקה לעיצוב מחדש.
              </InfoBox>
              <div className="bg-blue-50 p-6 rounded-xl border border-blue-200 shadow-inner">
                <h3 className="font-bold text-blue-900 mb-3 text-lg border-b border-blue-100 pb-2">תשובת ה-AI:</h3>
                <div className="text-gray-800 whitespace-pre-wrap leading-relaxed bg-white p-4 rounded-lg shadow-sm font-sans-normal text-lg">{aiResponse}</div>
              </div>

              <div className="bg-white p-6 rounded-2xl border-2 border-indigo-100 shadow-xl space-y-6 animate-fade-in">
                <h3 className="text-xl font-bold text-indigo-900">הערכת מרצה לפתרון ה-AI</h3>
                <div className="grid md:grid-cols-3 gap-6">
                  <div className="md:col-span-1">
                    <label className="block text-sm font-bold text-gray-700 mb-2">ציון למטלה (0-100):</label>
                    <input type="number" min="0" max="100" value={lecturerScore} onChange={(e) => setLecturerScore(e.target.value === '' ? '' : Number(e.target.value))} className="w-full p-4 border-2 border-indigo-100 rounded-xl focus:ring-2 focus:ring-indigo-500 font-bold text-2xl text-center text-indigo-900" placeholder="ציון" />
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-sm font-bold text-gray-700 mb-2">פידבק קצר על איכות הפתרון:</label>
                    <textarea value={lecturerFeedback} onChange={(e) => setLecturerFeedback(e.target.value)} className="w-full p-4 border-2 border-indigo-100 rounded-xl focus:ring-2 focus:ring-indigo-500 h-24" placeholder="האם ה-AI הצליח להגיע לעומק הנדרש?" />
                  </div>
                </div>
                {lecturerScore !== '' && (
                  <div className="animate-fade-in p-6 rounded-xl border-l-8 border-indigo-600 bg-indigo-50">
                    <h4 className="font-bold text-indigo-900 mb-2 text-lg">{lecturerScore > 70 ? '⚠️ המשימה מאפשרת פתרון AI מהיר' : '✅ המשימה מאתגרת את ה-AI'}</h4>
                    <p className="text-gray-700">{lecturerScore > 70 ? 'נראה שהבינה המלאכותית מספקת מענה איכותי בקלות. כדאי לשקול שינוי בדרכי ההערכה.' : 'המשימה שלך דורשת מיומנויות שה-AI מתקשה בהן, וזה מצוין!'}</p>
                  </div>
                )}
                <div className="flex flex-wrap gap-4 pt-4">
                  <button onClick={() => setStep(1)} className="flex-1 border-2 border-indigo-600 text-indigo-600 py-3 rounded-xl font-bold hover:bg-indigo-50 transition-all">דיוק המשימה וניסיון נוסף</button>
                  <button onClick={() => startRedesign()} className="flex-1 bg-green-600 text-white py-3 rounded-xl font-bold shadow-lg hover:bg-green-700 transition-all">עבור לעיצוב פדגוגי מקיף</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {mode === 'REDESIGN' && (
        <div className="space-y-6 animate-fade-in">
          {step === 1 && (
            <div className="bg-white p-8 rounded-xl shadow-sm border border-gray-100">
              <InfoBox title="תחילת תהליך העיצוב">
                כאן נגדיר את הבסיס למטלה החדשה. וודא שאתה מזין את מספר הסטודנטים המדויק, שכן העוזר יציע שיטות הערכה בנות-יישום (Scalable) בהתאם לגודל הכיתה.
              </InfoBox>
              <div className="grid gap-6">
                <div>
                  <label className="block text-lg font-semibold mb-2">הנחיית המטלה לעיצוב מחדש:</label>
                  <textarea value={assignmentText} onChange={(e) => setAssignmentText(e.target.value)} className="w-full h-40 p-4 border rounded-lg focus:ring-2 focus:ring-green-500" placeholder="מה הסטודנטים צריכים לעשות כיום?" />
                </div>
                <div>
                  <label className="block text-lg font-semibold mb-2">מספר סטודנטים בקורס:</label>
                  <input type="number" value={numStudents} onChange={(e) => setNumStudents(parseInt(e.target.value))} className="w-32 p-3 border rounded-lg font-bold text-indigo-900 focus:ring-2 focus:ring-indigo-500" />
                </div>
              </div>
              <button onClick={() => startRedesign()} disabled={loading || !assignmentText} className="mt-8 w-full bg-green-600 text-white py-4 rounded-lg font-bold text-lg">נתח מיומנויות בטקסונומיית בלום</button>
            </div>
          )}

          {step === 2 && bloomAnalysis && (
            <div className="bg-white p-6 rounded-xl shadow-sm border animate-fade-in">
