                <div className="flex flex-col md:flex-row gap-4">
                  <input 
                    type="text" 
                    value={newSkillName}
                    onChange={(e) => setNewSkillName(e.target.value)}
                    placeholder="שם המיומנות (למשל: עבודה בצוות, פרזנטציה...)"
                    className="flex-1 p-3 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                  <select 
                    value={newSkillLevel}
                    onChange={(e) => setNewSkillLevel(e.target.value as BloomLevel)}
                    className="p-3 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                  >
                    {Object.values(BloomLevel).map(level => (
                      <option key={level} value={level}>{level}</option>
                    ))}
                  </select>
                  <button 
                    onClick={handleAddCustomSkill}
                    disabled={!newSkillName.trim()}
                    className="bg-indigo-600 text-white px-6 py-3 rounded-lg font-bold hover:bg-indigo-700 transition-all disabled:opacity-50"
                  >
                    + הוסף מיומנות
                  </button>
                </div>
              </div>

              <div className="flex gap-4 mt-8 pt-6 border-t">
                <button onClick={handleGoBack} className="px-8 py-3 border rounded-lg font-bold hover:bg-gray-50">חזור</button>
                <button onClick={handleGetInitialStrategies} disabled={loading || selectedSkills.length === 0} className="flex-1 bg-indigo-600 text-white py-3 rounded-lg font-bold shadow-lg hover:bg-indigo-700 transition-all">המשך לניהול קבוצות מיומנויות</button>
              </div>
            </div>
          )}

          {step === 3 && strategies.length > 0 && (
            <div className="space-y-6 animate-fade-in pb-12">
              <div className="bg-white p-8 rounded-2xl shadow-xl border-t-8 border-indigo-600 relative">
                <InfoBox title="ניהול קבוצות הערכה">
                  כאן אנו בונים את מבנה המטלה. <strong>אגד מיומנויות לקבוצות</strong> (על ידי לחיצה על מיומנות והעברתה), ובחר עבור כל קבוצה את <strong>שיטת ההערכה</strong> המתאימה ביותר (מבוקרת או פתוחה).
                </InfoBox>

                <div className="flex justify-between items-center mb-6">
                  <div>
                    <h3 className="text-2xl font-bold text-indigo-900">ניהול קבוצות מיומנויות</h3>
                    <p className="text-gray-600">התאם את הקבוצות לפי שיקול דעתך. העוזר מתחשב ב-{numStudents} סטודנטים.</p>
                  </div>
                  <button onClick={() => addNewGroup('מיומנות חדשה')} className="bg-green-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-green-700 transition-all shadow-md">+ הוסף קבוצה</button>
                </div>
                <div className="space-y-8">
                  {strategies.map((strat, idx) => (
                    <div key={strat.id} className="p-6 rounded-2xl bg-gray-50 border-2 border-indigo-100 shadow-sm">
                      <h4 className="text-sm font-bold text-indigo-400 mb-3 uppercase">קבוצת הערכה #{idx+1}</h4>
                      <div className="flex flex-wrap gap-3 mb-6">
                        {strat.skills.map((s, i) => (
                          <button key={i} onClick={() => setInspectedSkill({name: s, groupIdx: idx})} className={`skill-btn flex items-center bg-white text-indigo-900 border-2 border-indigo-200 text-sm px-4 py-2 rounded-xl font-bold shadow-sm ${inspectedSkill?.name === s ? 'ring-4 ring-indigo-400' : ''}`}>{s}</button>
                        ))}
                      </div>
                      {inspectedSkill && inspectedSkill.groupIdx === idx && (
                        <div className="mb-6 p-5 bg-white rounded-xl border-2 border-indigo-500 shadow-lg animate-fade-in">
                          <div className="flex justify-between items-start mb-4">
                            <h5 className="font-bold text-lg text-indigo-900">{inspectedSkill.name}</h5>
                            <button onClick={() => setInspectedSkill(null)} className="text-gray-400 hover:text-gray-600">✕</button>
                          </div>
                          <div className="flex flex-wrap gap-2 pt-4 border-t">
                            <span className="text-xs font-bold text-gray-400 w-full mb-1">העבר לקבוצה:</span>
                            {strategies.map((target, tIdx) => target.id !== strat.id && <button key={target.id} onClick={() => moveSkillToGroup(inspectedSkill.name, target.id)} className="bg-indigo-50 text-indigo-700 text-xs px-3 py-1.5 rounded-lg hover:bg-indigo-600 hover:text-white">קבוצה {tIdx + 1}</button>)}
                            <button onClick={() => addNewGroup(inspectedSkill.name)} className="bg-green-50 text-green-700 text-xs px-3 py-1.5 rounded-lg hover:bg-green-600 hover:text-white">+ קבוצה חדשה</button>
                          </div>
                        </div>
                      )}
                      <div className="grid md:grid-cols-2 gap-8 pt-4 border-t">
                        <div>
                          <label className="block text-sm font-bold text-gray-700 mb-3">סוג הערכה:</label>
                          <div className="flex gap-4">
                            <button onClick={() => updateStrategySelection(idx, 'FaceToFace')} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all ${strat.userSelectedCategory === 'FaceToFace' ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border-gray-100 hover:border-indigo-200'}`}>הערכה בסביבה מבוקרת</button>
                            <button onClick={() => updateStrategySelection(idx, 'Submission')} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all ${strat.userSelectedCategory === 'Submission' ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border-gray-100 hover:border-indigo-200'}`}>הערכה בסביבה פתוחה</button>
                          </div>
                        </div>
                        {strat.userSelectedCategory && (
                          <div className="animate-fade-in">
                            <label className="block text-sm font-bold text-gray-700 mb-3">בחירת שיטה:</label>
                            <select 
                              value={strat.userSelectedMethod} 
                              onChange={(e) => updateStrategySelection(idx, strat.userSelectedCategory!, e.target.value)} 
                              className="w-full p-4 border-2 border-indigo-200 rounded-xl bg-white outline-none focus:border-indigo-500 font-medium text-gray-800 shadow-sm appearance-none"
                            >
                              <option value="">-- בחר שיטה --</option>
                              {(() => {
                                const baseOptions = CATEGORIZED_OPTIONS[strat.userSelectedCategory];
                                const defenseOptions = strat.userSelectedCategory === 'FaceToFace' ? CATEGORIZED_OPTIONS.Defense : [];
                                const combined = Array.from(new Set([...baseOptions, ...defenseOptions]));
                                return combined.map(opt => (
                                  <option key={opt} value={opt}>
                                    {opt === strat.method ? `${opt} (מומלץ)` : opt}
                                  </option>
                                ));
                              })()}
                            </select>
                            <p className="mt-3 text-xs text-indigo-600 font-bold bg-indigo-50 p-2 rounded-lg leading-relaxed">העוזר מציע: {strat.explanation}</p>
                            {shouldShowDefenseSuggestion(idx, strat) && (
                              <button onClick={() => addNewGroup('כללי', true)} className="mt-3 w-full text-xs bg-amber-50 text-amber-700 border border-amber-200 p-2 rounded-lg font-bold hover:bg-amber-100 shadow-sm transition-colors">+ הצעה: הוספת שלב ליווי פנים-אל-פנים לאחר ההגשה</button>
                            )}
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
                <div className="flex gap-4 mt-12 pt-8 border-t">
                  <button onClick={handleGoBack} className="px-10 py-4 border-2 rounded-xl font-bold hover:bg-gray-50 transition-all">חזור</button>
                  <button onClick={handleFinalRephrase} disabled={loading} className="flex-1 bg-green-600 text-white py-4 rounded-xl font-bold text-xl shadow-xl hover:bg-green-700 transition-all">צור מטלה וסיכום למידה</button>
                </div>
              </div>
            </div>
          )}

          {step === 4 && (
            <div className="space-y-8 pb-20 animate-fade-in">
              <div className="bg-white p-10 rounded-2xl shadow-xl border-t-8 border-green-600">
                <InfoBox title="אישור ועריכת תוצרי המטלה" variant="success">
                  לפניך נוסח המטלה המעודכן. <strong>מעבור על כל חלק</strong>: תוכל לאשר אותו כפי שהוא, לערוך את הטקסט או להסיר חלקים שאינם רלוונטיים. בסיום, תוכל להעתיק את כל החלקים שאושרו למסמך המטלה שלך.
                </InfoBox>

                <div className="flex justify-between items-center mb-8 border-b pb-4">
                  <h3 className="text-3xl font-bold text-indigo-900">משימת הערכה</h3>
                  <div className={`px-5 py-2 rounded-full font-bold text-sm border shadow-sm transition-colors ${allSectionsHandled ? 'bg-green-100 text-green-800 border-green-200' : 'bg-amber-100 text-amber-800 border-amber-200'}`}>
                    {allSectionsHandled ? 'כל החלקים טופלו' : 'יש לאשר או לערוך את כל החלקים'}
                  </div>
                </div>

                <div className="space-y-12">
                  <div>
                    <h4 className="text-2xl font-bold text-indigo-700 mb-6 border-r-4 border-indigo-600 pr-4">הנחיות לסטודנטים</h4>
                    <div className="space-y-6">
                      {revisedSections.filter(s => s.audience === 'student').map((section, idx) => {
                        const originalIdx = revisedSections.indexOf(section);
                        return (
                          <div key={originalIdx} className={`p-6 rounded-2xl border-2 transition-all ${section.status === 'approved' ? 'border-green-400 bg-green-50/30' : section.status === 'removed' ? 'border-gray-200 bg-gray-50 opacity-50' : 'border-indigo-100 bg-white shadow-sm'}`}>
                            <div className="flex justify-between items-center mb-4">
                              <h5 className="text-xl font-bold text-indigo-900">{section.title}</h5>
                              <div className="flex gap-2">
                                <button onClick={() => updateSectionStatus(originalIdx, 'approved')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'approved' ? 'bg-green-600 text-white' : 'bg-white border text-green-600 hover:bg-green-50'}`}>אשר</button>
                                <button onClick={() => toggleSectionEdit(originalIdx)} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.isEditing ? 'bg-indigo-600 text-white shadow-inner' : 'bg-white border text-indigo-600 hover:bg-indigo-50'}`}>{section.isEditing ? 'שמור' : 'ערוך'}</button>
                                <button onClick={() => updateSectionStatus(originalIdx, 'removed')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'removed' ? 'bg-red-600 text-white' : 'bg-white border text-red-600 hover:bg-red-50'}`}>הסר</button>
                              </div>
                            </div>
                            {section.isEditing ? (
                              <textarea className="w-full p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 editor-textarea h-64 bg-white" value={section.content} onChange={(e) => updateSectionContent(originalIdx, e.target.value)} />
                            ) : (
                              <div className="prose prose-indigo max-w-none text-gray-800 leading-relaxed font-sans-normal whitespace-pre-wrap text-lg" dangerouslySetInnerHTML={renderMarkdown(section.content)} />
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>

                  <div className="bg-gray-50 p-8 rounded-3xl border-2 border-dashed border-gray-300">
                    <h4 className="text-2xl font-bold text-gray-700 mb-6 border-r-4 border-gray-500 pr-4">שיקולי דעת והנחיות למרצה</h4>
                    <div className="space-y-6">
                      {revisedSections.filter(s => s.audience === 'lecturer').map((section, idx) => {
                        const originalIdx = revisedSections.indexOf(section);
                        return (
                          <div key={originalIdx} className={`p-6 rounded-2xl border-2 transition-all ${section.status === 'approved' ? 'border-green-400 bg-green-50/20' : section.status === 'removed' ? 'border-gray-200 bg-gray-50 opacity-50' : 'border-gray-200 bg-white'}`}>
                            <div className="flex justify-between items-center mb-4">
                              <h5 className="text-xl font-bold text-gray-800">{section.title}</h5>
                              <div className="flex gap-2">
                                <button onClick={() => updateSectionStatus(originalIdx, 'approved')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'approved' ? 'bg-green-600 text-white' : 'bg-white border text-green-600 hover:bg-green-50'}`}>אשר</button>
                                <button onClick={() => toggleSectionEdit(originalIdx)} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.isEditing ? 'bg-indigo-600 text-white shadow-inner' : 'bg-white border text-indigo-600 hover:bg-indigo-50'}`}>{section.isEditing ? 'שמור' : 'ערוך'}</button>
                                <button onClick={() => updateSectionStatus(originalIdx, 'removed')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'removed' ? 'bg-red-600 text-white' : 'bg-white border text-red-600 hover:bg-red-50'}`}>הסר</button>
                              </div>
                            </div>
                            {section.isEditing ? (
                              <textarea className="w-full p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 editor-textarea h-64 bg-white" value={section.content} onChange={(e) => updateSectionContent(originalIdx, e.target.value)} />
                            ) : (
                              <div className="prose prose-indigo max-w-none text-gray-700 leading-relaxed font-sans-normal whitespace-pre-wrap text-lg opacity-90 italic" dangerouslySetInnerHTML={renderMarkdown(section.content)} />
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>

                <div className="mt-12 pt-8 border-t flex flex-wrap gap-4">
                  <button onClick={copyAllToClipboard} disabled={!hasApprovedSections} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all ${copySuccess ? 'bg-green-600 text-white border-green-600' : 'border-indigo-600 text-indigo-600 hover:bg-indigo-50 shadow-md'}`}>
                    {copySuccess ? 'הטקסט הועתק!' : 'העתק את כל חלקי המטלה שאושרו'}
                  </button>
                </div>
              </div>

              <div className="bg-white p-8 rounded-2xl shadow-md border border-gray-200 hide-on-print">
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-indigo-800"><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>דיוק והתייעצות נוספת</h3>
                <div className="max-h-80 overflow-y-auto mb-6 space-y-4 p-5 bg-gray-50 rounded-xl border shadow-inner">
                  {chatHistory.length === 0 && <p className="text-gray-400 text-center italic py-4">שאל שאלות נוספות לדיוק המטלה...</p>}
                  {chatHistory.map((msg, i) => (
                    <div key={i} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}><div className={`max-w-[85%] p-4 rounded-2xl shadow-sm ${msg.role === 'user' ? 'bg-indigo-100 text-indigo-900 border border-indigo-200' : 'bg-white text-gray-800 border border-gray-200'}`}>{msg.text}</div></div>
                  ))}
                  <div ref={chatEndRef} />
                </div>
                <div className="flex gap-2">
                  <input type="text" value={followUpQuestion} onChange={(e) => setFollowUpQuestion(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleFollowUp()} placeholder="שאל שאלה נוספת..." className="flex-1 p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
                  <button onClick={handleFollowUp} disabled={loading} className="bg-indigo-600 text-white px-8 py-2 rounded-xl font-bold hover:bg-indigo-700 transition-all">שלח</button>
                </div>
              </div>
              <div className="flex gap-4 hide-on-print">
                <button onClick={handleGoBack} className="px-10 py-4 border-2 rounded-xl font-bold hover:bg-gray-100 transition-all">חזור</button>
                <button onClick={resetToHome} className="flex-1 bg-indigo-900 text-white py-4 rounded-xl font-bold hover:bg-black shadow-lg transition-all">סיים וחזור לדף הבית</button>
              </div>
            </div>
          )}
        </div>
      )}

      {loading && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-md flex items-center justify-center z-50">
          <div className="bg-white p-12 rounded-3xl shadow-2xl flex flex-col items-center gap-8 border-2 border-indigo-100 animate-pulse">
            <div className="w-20 h-20 border-8 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <div className="text-center"><p className="font-bold text-2xl text-indigo-900 mb-2">מעבד פדגוגיה...</p></div>
          </div>
        </div>
      )}
    </Layout>
  );
};

