import { GoogleGenAI, Type } from "@google/genai";
import { BloomLevel, Skill, AssessmentMethod } from "../types";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const testAiAssignment = async (assignmentText: string, fileData?: { data: string, mimeType: string }) => {
  const parts: any[] = [];

  // Add file if it exists
  if (fileData) {
    parts.push({
      inlineData: {
        data: fileData.data,
        mimeType: fileData.mimeType
      }
    });
  }

  // Add text instruction
  parts.push({
    text: `ענה על המטלה הבאה כסטודנט מצטיין. 
    החזר אך ורק את פתרון המטלה עצמו, כפי שסטודנט היה מגיש אותו. 
    אל תכתוב הקדמות (כמו "הנה הפתרון..."), אל תכתוב הערות מטא, ואל תכתוב סיכומים על איך ה-AI עזר. 

    הנחיה קריטית לעיצוב: התשובה חייבת להיות בטקסט פשוט (Plain Text) בלבד. 
    אין להשתמש בסימני Markdown (כמו כוכביות להדגשה, סולמיות לכותרות, וכו'). 
    כתוב את הטקסט בצורה נקייה וקריאה ללא עיצוב עשיר.

    תוכן המטלה (בנוסף לקובץ המצורף אם יש):
    ${assignmentText}`
  });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts },
    config: {
      temperature: 0.7,
    }
  });
  return response.text;
};

export const analyzeBloomTaxonomy = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נתח את המטלה הבאה לפי הטקסונומיה של בלום. 
    עליך לזהות את המיומנויות הנדרשות במשימה הנוכחית ולהציע הרחבות שיחזקו את הלמידה.

    כלל פדגוגי מחייב: למידה משמעותית היא היררכית. הניתוח חייב לכלול תמיד את רמות ה"זכירה" (Remember) וה"הבנה" (Understand) כבסיס הידע הכרחי למטלה.

    דגש פדגוגי קריטי לרמת ה"זכירה": 
    התייחס לזכירה של טרמינולוגיה, עקרונות, מבנים מושגיים או עוגני ידע מרכזיים שנלמדו. 
    הימנע מהתמקדות בפרטים ספציפיים מדי או זוטות טכניות. המטרה היא זיהוי של תשתיות הידע ההכרחיות.

    המטלה: ${assignmentText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          currentSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          },
          suggestedSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          }
        },
        required: ["currentSkills", "suggestedSkills"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateAssessmentStrategies = async (skills: Skill[], numStudents: number) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `עבור רשימת המיומנויות הבאה וכיתה של ${numStudents} סטודנטים, אגד אותן לקבוצות הערכה לוגיות (2-3 קבוצות).

    כללים פדגוגיים להמלצה:
    1. קדם תהליך למידה משמעותי המשלב דרישה להתייחסות לתכנים ספציפיים שנלמדו בשיעור (ולא רק ידע כללי שה-AI מכיר).
    2. התחשב בגודל הכיתה (${numStudents} סטודנטים): הצע שיטות בנות-יישום (Scalable). למשל, לכיתה גדולה הצע הערכה מדגמית או בחנים ממוחשבים, ולכיתה קטנה הצע בחינה בע"פ.
    3. שקול אסטרטגיה שבה מיומנויות מסדר נמוך נבדקות במשימת הגשה, בעוד שמיומנויות מסדר גבוה מוערכות במפגש פנים-אל-פנים.

    שיטות זמינות:
    FaceToFace (הערכה בסביבה מבוקרת): מבחן כתוב, בוחן ממוחשב, בחינה בע"פ, שאלות ידע בשיעור, הצגת תוצר, הערכת דיון, כתיבה בכיתה, הערכה מדגמית.
    Submission (הערכה בסביבה פתוחה): כתיבת משימה עם AI, משוב על תוצר AI, הערכת עמיתים, הערכה עצמית, סימולציה עם AI.

    המיומנויות שנבחרו: ${JSON.stringify(skills)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            skills: { type: Type.ARRAY, items: { type: Type.STRING } },
            method: { type: Type.STRING, description: "השיטה הספציפית המומלצת מתוך הרשימה" },
            type: { type: Type.STRING, enum: ['FaceToFace', 'Submission'] },
            explanation: { type: Type.STRING, description: "הסבר פדגוגי המדגיש את החיבור לתכנים שנלמדו בשיעור ואת ההתאמה לגודל הכיתה." }
          },
          required: ["skills", "method", "type", "explanation"]
        }
      }
    }
  });

  const res = JSON.parse(response.text);
  return res.map((item: any, index: number) => ({
    ...item,
    id: `group-${index}-${Date.now()}`
  }));
};

export interface TaskSection {
  title: string;
  content: string;
  audience: 'student' | 'lecturer';
}

export interface RephrasedResult {
  sections: TaskSection[];
  practicalTips: string;
}

export const rephraseAssignment = async (originalText: string, targetSkills: Skill[], strategies: AssessmentMethod[], numStudents: number) => {
  const labelsMap = {
    FaceToFace: 'הערכה בסביבה מבוקרת',
    Submission: 'הערכה בסביבה פתוחה'
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נסח מחדש את המטלה המקורית למטלה אקדמית מעודכנת. המטרה היא יצירת "משימת הערכה" שלמה ומפורטת.

    כללים מבניים חובה:
    1. עבור הסטודנטים (sections): חלק את ההנחיות לפרקים נפרדים עבור כל אחד ממרכיבי המטלה.
       עבור כל אסטרטגיה ברשימה להלן, צור אובייקט TaskSection נפרד (audience: 'student') עם כותרת בפורמט: "חלק [מספר]: [שיטת ההערכה]".
       כל חלק כזה חייב להסביר לסטודנט בדיוק מה עליו לעשות ובאילו מיומנויות הוא משתמש.
    2. עבור המרצה (sections): צור לפחות 2 פרקים נפרדים (audience: 'lecturer'):
       א. "שיקולי דעת פדגוגיים" - הסבר מדוע נבחרו השיטות הללו.
       ב. "הנחיות לוגיסטיות ודגשים לבדיקה" - כיצד לבצע את ההערכה בפועל עבור ${numStudents} סטודנטים.
    3. טיפים מעשיים (practicalTips): בנוסף לפרקים, כתוב סיכום קצר של עצות פרקטיות ורעיונות לגיוון המשימה ווידוא למידה אותנטית (למשל: שאלות ולידציה בכיתה, שינוי נתונים קטן, הצגה בעל פה מדגמית, וכו').

    דגשים פדגוגיים:
    - דרוש שילוב של תכנים ספציפיים שנלמדו בשיעור.
    - הימנע משימוש מופרז בכוכביות (*) - שמור על טקסט נקי.

    נתונים לשילוב:
    ${strategies.map((s, idx) => `- אסטרטגיה ${idx + 1}: מיומנויות [${s.skills.join(', ')}] בשיטת "${s.userSelectedMethod}" (סוג: ${labelsMap[s.userSelectedCategory as keyof typeof labelsMap]}).`).join('\n')}

    מטלה מקורית: ${originalText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                content: { type: Type.STRING },
                audience: { type: Type.STRING, enum: ['student', 'lecturer'] }
              },
              required: ["title", "content", "audience"]
            }
          },
          practicalTips: { type: Type.STRING }
        },
        required: ["sections", "practicalTips"]
      }
    }
  });
  return JSON.parse(response.text) as RephrasedResult;
};

export const askFollowUpQuestion = async (
  context: { originalText: string, revisedTask: TaskSection[], strategies: AssessmentMethod[] },
  question: string,
  history: { role: 'user' | 'model', text: string }[]
) => {
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `אתה עוזר פדגוגי מומחה. התמקד בחיבור לתוכן שנלמד בשיעור ובשיטות הערכה מגוונות.`,
    }
  });
  const response = await chat.sendMessage({ message: question });
  return response.text;
};

import React, { useState } from 'react';
import Layout from './components/Layout';
import { InfoBox } from './components/InfoBox';
import StepInput from './components/StepInput';
import StepSkillsAnalysis from './components/StepSkillsAnalysis';
import StepStrategyBuilder from './components/StepStrategyBuilder';
import StepFinalResult from './components/StepFinalResult';
import { AppMode, BloomLevel, Skill, AssessmentMethod } from './types';
import { 
  testAiAssignment, 
  analyzeBloomTaxonomy, 
  generateAssessmentStrategies, 
  rephraseAssignment, 
  askFollowUpQuestion,
  TaskSection
} from './services/geminiService';

interface SectionState extends TaskSection {
  status: 'pending' | 'approved' | 'removed';
  isEditing: boolean;
}

const stripMarkdown = (text: string) => {
  return text
    .replace(/\*\*(.*?)\*\*/g, '$1') // Bold
    .replace(/\*(.*?)\*/g, '$1') // Italic
    .replace(/##/g, '') // Headers
    .replace(/#/g, '') // Headers
    .replace(/`/g, '') // Code
    .replace(/\[(.*?)\]\(.*?\)/g, '$1') // Links
    .replace(/^\s*-\s/gm, '• ') // List items
    .trim();
};

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('HOME');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);
  const [assignmentText, setAssignmentText] = useState('');
  const [uploadedFile, setUploadedFile] = useState<{ name: string, data: string, mimeType: string } | null>(null);
  const [numStudents, setNumStudents] = useState<number>(30);
  const [aiResponse, setAiResponse] = useState('');
  const [lecturerScore, setLecturerScore] = useState<number | ''>('');
  const [lecturerFeedback, setLecturerFeedback] = useState('');
  const [bloomAnalysis, setBloomAnalysis] = useState<{currentSkills: Skill[], suggestedSkills: Skill[]} | null>(null);
  const [customSkills, setCustomSkills] = useState<Skill[]>([]);
  const [selectedSkills, setSelectedSkills] = useState<Skill[]>([]);
  const [strategies, setStrategies] = useState<AssessmentMethod[]>([]);
  const [revisedSections, setRevisedSections] = useState<SectionState[]>([]);
  const [practicalTips, setPracticalTips] = useState<string>('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const result = evt.target?.result as string;
      // Get base64 part
      const base64Data = result.split(',')[1];
      setUploadedFile({
        name: file.name,
        data: base64Data,
        mimeType: file.type
      });
    };
    reader.readAsDataURL(file);
  };

  const handleTestAi = async () => {
    if (!assignmentText.trim() && !uploadedFile) return;
    setLoading(true);
    try {
      const filePayload = uploadedFile ? { data: uploadedFile.data, mimeType: uploadedFile.mimeType } : undefined;
      const res = await testAiAssignment(assignmentText, filePayload);
      setAiResponse(res || 'לא התקבלה תשובה');
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בבדיקת המטלה - אנא וודא שהקובץ תקין (PDF/Word)');
    } finally {
      setLoading(false);
    }
  };

  const startRedesign = async (initialText?: string) => {
    const textToAnalyze = initialText || assignmentText;
    if (!textToAnalyze.trim()) return;
    setAssignmentText(textToAnalyze);
    setMode('REDESIGN');
    setLoading(true);
    try {
      const analysis = await analyzeBloomTaxonomy(textToAnalyze);
      setBloomAnalysis(analysis);
      setSelectedSkills(analysis.currentSkills);
      setCustomSkills([]);
      setStep(2);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleSkillToggle = (skill: Skill) => {
    setSelectedSkills(prev => 
      prev.some(s => s.name === skill.name) ? prev.filter(s => s.name !== skill.name) : [...prev, skill]
    );
  };

  const handleAddCustomSkill = (newSkill: Skill) => {
    setCustomSkills(prev => [...prev, newSkill]);
    setSelectedSkills(prev => [...prev, newSkill]);
  };

  const handleGetInitialStrategies = async () => {
    if (selectedSkills.length === 0) return;
    setLoading(true);
    try {
      const res = await generateAssessmentStrategies(selectedSkills, numStudents);
      setStrategies(res.map((s: any) => ({ ...s, userSelectedCategory: s.type, userSelectedMethod: s.method })));
      setStep(3); 
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const updateStrategySelection = (index: number, category: 'FaceToFace' | 'Submission', method?: string) => {
    const newStrategies = [...strategies];
    newStrategies[index] = { ...newStrategies[index], userSelectedCategory: category, userSelectedMethod: method || '' };
    setStrategies(newStrategies);
  };

  const moveSkillToGroup = (skillName: string, targetGroupId: string) => {
    const newStrategies = strategies.map(s => {
      const remainingSkills = s.skills.filter(sk => sk !== skillName);
      if (s.id === targetGroupId) return { ...s, skills: [...s.skills.filter(sk => sk !== skillName), skillName] };
      return { ...s, skills: remainingSkills };
    }).filter(s => s.skills.length > 0);
    setStrategies(newStrategies);
  };

  const addNewGroup = (skillName: string, isDefense: boolean = false) => {
    const updatedOldGroups = strategies.map(s => ({ ...s, skills: s.skills.filter(sk => sk !== skillName) })).filter(s => s.skills.length > 0);
    const newGroup: AssessmentMethod = {
      id: `group-${Date.now()}`,
      skills: skillName === 'כללי' ? ['הגנה על העבודה (Defense)'] : [skillName],
      method: isDefense ? 'בחינה אישית בע"פ' : '',
      type: 'FaceToFace',
      explanation: isDefense ? 'אימות למידה וזהות המגיש (Defense) - מומלץ במיוחד במטלות המותרות לביצוע עם AI.' : 'קבוצה חדשה.',
      userSelectedCategory: 'FaceToFace',
      userSelectedMethod: isDefense ? 'בחינה אישית בע"פ' : ''
    };
    setStrategies([...updatedOldGroups, newGroup]);
  };

  const handleFinalRephrase = async () => {
    if (!strategies.every(s => s.userSelectedMethod)) return;
    setLoading(true);
    try {
      const { sections, practicalTips } = await rephraseAssignment(assignmentText, selectedSkills, strategies, numStudents);
      setRevisedSections(sections.map(s => ({ ...s, status: 'pending', isEditing: false })));
      setPracticalTips(practicalTips);
      setStep(4);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleFollowUp = async (question: string) => {
    setChatHistory(prev => [...prev, { role: 'user', text: question }]);
    setLoading(true);
    try {
      const response = await askFollowUpQuestion({ originalText: assignmentText, revisedTask: revisedSections, strategies }, question, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: response || '' }]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const resetToHome = () => {
    setMode('HOME');
    setStep(1);
    setAssignmentText('');
    setUploadedFile(null);
    setAiResponse('');
    setLecturerScore('');
    setLecturerFeedback('');
    setBloomAnalysis(null);
    setCustomSkills([]);
    setSelectedSkills([]);
    setStrategies([]);
    setRevisedSections([]);
    setPracticalTips('');
    setChatHistory([]);
  };

  const handleGoBack = () => {
    setStep(prev => prev > 1 ? prev - 1 : prev);
    if (step === 1) setMode('HOME');
  };

  const updateSectionStatus = (index: number, status: 'approved' | 'removed') => {
    const newSections = [...revisedSections];
    newSections[index].status = status;
    setRevisedSections(newSections);
  };

  const updateSectionContent = (index: number, content: string) => {
    const newSections = [...revisedSections];
    newSections[index].content = content;
    setRevisedSections(newSections);
  };

  const toggleSectionEdit = (index: number) => {
    const newSections = [...revisedSections];
    newSections[index].isEditing = !newSections[index].isEditing;
    setRevisedSections(newSections);
  };

  return (
    <Layout title={mode === 'HOME' ? 'Re-Assess' : mode === 'TEST_AI' ? 'בדיקה מול AI' : 'עיצוב מחדש'} onBack={mode !== 'HOME' ? handleGoBack : undefined}>
      <style>{`
        .animate-fade-in { animation: fadeIn 0.4s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
        .skill-btn { transition: all 0.2s; }
        .skill-btn:hover { transform: translateY(-1px); box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
        .font-sans-normal { font-style: normal !important; font-family: 'Assistant', sans-serif; }
        .editor-textarea {
          font-family: 'Assistant', sans-serif;
          line-height: 1.625;
          font-size: 1.125rem;
          color: #1f2937;
        }
        .plain-text-response {
          font-family: 'Courier New', Courier, monospace;
          white-space: pre-wrap;
          line-height: 1.6;
        }
      `}</style>

      {mode === 'HOME' && (
        <div className="flex flex-col items-center gap-8 py-12">
          <div className="text-center space-y-4">
            <h2 className="text-4xl font-bold text-gray-800">איך המטלה שלך נראית בעידן ה-AI?</h2>
            <p className="text-xl text-gray-600 max-w-2xl">שיפור פדגוגיה ועידוד למידה משמעותית באמצעות עיצוב מחדש של דרכי הערכה.</p>
          </div>

          <InfoBox title="איך מתחילים?">
            בחר את המסלול המתאים לך: אם תרצה לראות תחילה כיצד ה-AI פותר את המטלה הקיימת שלך, בחר <strong>"בדוק מול ה-AI"</strong>. אם תרצה לגשת ישירות לעיצוב מחדש פדגוגי, בחר <strong>"עיצוב למידה מחדש"</strong>.
          </InfoBox>

          <div className="grid md:grid-cols-2 gap-6 w-full max-w-3xl">
            <button onClick={() => { setMode('TEST_AI'); setStep(1); }} className="bg-white border-2 border-indigo-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-indigo-400 text-right group transition-all">
              <div className="bg-indigo-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">בדוק מול ה-AI</h3>
              <p className="text-gray-600">ראה כיצד הבינה המלאכותית פותרת את המטלה הקיימת ונתח את העומק הפדגוגי שלה.</p>
            </button>
            <button onClick={() => { setMode('REDESIGN'); setStep(1); }} className="bg-white border-2 border-green-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-green-400 text-right group transition-all">
              <div className="bg-green-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-green-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">עיצוב למידה מחדש</h3>
              <p className="text-gray-600">נתח מיומנויות ושדרג את המערך הפדגוגי לליווי מיטבי של הסטודנטים.</p>
            </button>
          </div>
        </div>
      )}

      {mode === 'TEST_AI' && (
        <div className="space-y-6 animate-fade-in">
          {step === 1 ? (
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
              <InfoBox title="שלב 1: הזנת המטלה">
                הדבק כאן את נוסח המטלה המקורי שאתה נותן לסטודנטים, או העלה קובץ (PDF/Word). המערכת תשתמש ב-AI כדי לנסות לפתור אותה.
              </InfoBox>

              <div className="space-y-4">
                <div>
                  <label className="block text-lg font-semibold mb-2">אפשרות א': הדבק טקסט</label>
                  <textarea 
                    value={assignmentText} 
                    onChange={(e) => setAssignmentText(e.target.value)} 
                    className="w-full h-32 p-4 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" 
                    placeholder="הדבק כאן את הנחיית המטלה שלך..." 
                  />
                </div>

                <div className="flex items-center gap-4 my-2">
                  <div className="h-px bg-gray-200 flex-1"></div>
                  <span className="text-gray-400 text-sm font-bold">או</span>
                  <div className="h-px bg-gray-200 flex-1"></div>
                </div>

                <div>
                  <label className="block text-lg font-semibold mb-2">אפשרות ב': העלה קובץ (PDF / Word)</label>
                  <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-6 hover:bg-gray-50 transition-colors text-center cursor-pointer">
                    <input 
                      type="file" 
                      accept=".pdf,.docx,.txt" 
                      onChange={handleFileUpload}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    />
                    <div className="flex flex-col items-center justify-center pointer-events-none">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-gray-400 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                      </svg>
                      {uploadedFile ? (
                         <span className="text-indigo-600 font-bold">{uploadedFile.name}</span>
                      ) : (
                        <span className="text-gray-500">לחץ להעלאת קובץ (PDF, Word)</span>
                      )}
                    </div>
                  </div>
                </div>
              </div>

              <button onClick={handleTestAi} disabled={loading || (!assignmentText && !uploadedFile)} className="mt-6 w-full bg-indigo-600 text-white py-4 rounded-xl font-bold text-lg shadow-md hover:bg-indigo-700 transition-all">הדגם פתרון AI</button>
            </div>
          ) : (
            <div className="space-y-6">
              <InfoBox title="שלב 2: ניתוח התוצאה">
                לפניך פתרון שהופק על ידי AI. בחן אותו בעיניים של מרצה: האם הוא עונה על הדרישות? האם חסר בו עומק? תן ציון ופידבק כדי להחליט אם המטלה זקוקה לעיצוב מחדש.
              </InfoBox>
              <div className="bg-blue-50 p-6 rounded-xl border border-blue-200 shadow-inner">
                <h3 className="font-bold text-blue-900 mb-3 text-lg border-b border-blue-100 pb-2">תשובת ה-AI (טקסט בלבד):</h3>
                <div className="plain-text-response text-gray-800 bg-white p-6 rounded-lg shadow-sm border border-gray-100 text-lg">
                  {stripMarkdown(aiResponse)}
                </div>
              </div>

              <div className="bg-white p-6 rounded-2xl border-2 border-indigo-100 shadow-xl space-y-6 animate-fade-in">
                <h3 className="text-xl font-bold text-indigo-900">הערכת מרצה לפתרון ה-AI</h3>
                <div className="grid md:grid-cols-3 gap-6">
                  <div className="md:col-span-1">
                    <label className="block text-sm font-bold text-gray-700 mb-2">ציון למטלה (0-100):</label>
                    <input type="number" min="0" max="100" value={lecturerScore} onChange={(e) => setLecturerScore(e.target.value === '' ? '' : Number(e.target.value))} className="w-full p-4 border-2 border-indigo-100 rounded-xl focus:ring-2 focus:ring-indigo-500 font-bold text-2xl text-center text-indigo-900" placeholder="ציון" />
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-sm font-bold text-gray-700 mb-2">פידבק קצר על איכות הפתרון:</label>
                    <textarea value={lecturerFeedback} onChange={(e) => setLecturerFeedback(e.target.value)} className="w-full p-4 border-2 border-indigo-100 rounded-xl focus:ring-2 focus:ring-indigo-500 h-24" placeholder="האם ה-AI הצליח להגיע לעומק הנדרש?" />
                  </div>
                </div>
                {lecturerScore !== '' && (
                  <div className="animate-fade-in p-6 rounded-xl border-l-8 border-indigo-600 bg-indigo-50">
                    <h4 className="font-bold text-indigo-900 mb-2 text-lg">{lecturerScore > 70 ? '⚠️ המשימה מאפשרת פתרון AI מהיר' : '✅ המשימה מאתגרת את ה-AI'}</h4>
                    <p className="text-gray-700">{lecturerScore > 70 ? 'נראה שהבינה המלאכותית מספקת מענה איכותי בקלות. כדאי לשקול שינוי בדרכי ההערכה.' : 'המשימה שלך דורשת מיומנויות שה-AI מתקשה בהן, וזה מצוין!'}</p>
                  </div>
                )}
                <div className="flex flex-wrap gap-4 pt-4">
                  <button onClick={() => setStep(1)} className="flex-1 border-2 border-indigo-600 text-indigo-600 py-3 rounded-xl font-bold hover:bg-indigo-50 transition-all">דיוק המשימה וניסיון נוסף</button>
                  <button onClick={() => startRedesign()} className="flex-1 bg-green-600 text-white py-3 rounded-xl font-bold shadow-lg hover:bg-green-700 transition-all">עבור לעיצוב פדגוגי מקיף</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {mode === 'REDESIGN' && (
        <div className="space-y-6 animate-fade-in">
          {step === 1 && (
            <StepInput
              assignmentText={assignmentText}
              setAssignmentText={setAssignmentText}
              numStudents={numStudents}
              setNumStudents={setNumStudents}
              onNext={() => startRedesign()}
              loading={loading}
            />
          )}

          {step === 2 && bloomAnalysis && (
            <StepSkillsAnalysis
              bloomAnalysis={bloomAnalysis}
              selectedSkills={selectedSkills}
              handleSkillToggle={handleSkillToggle}
              customSkills={customSkills}
              onAddCustomSkill={handleAddCustomSkill}
              onNext={handleGetInitialStrategies}
              onBack={handleGoBack}
              loading={loading}
            />
          )}

          {step === 3 && strategies.length > 0 && (
            <StepStrategyBuilder
              strategies={strategies}
              numStudents={numStudents}
              updateStrategySelection={updateStrategySelection}
              moveSkillToGroup={moveSkillToGroup}
              addNewGroup={addNewGroup}
              onNext={handleFinalRephrase}
              onBack={handleGoBack}
              loading={loading}
            />
          )}

          {step === 4 && (
            <StepFinalResult
              revisedSections={revisedSections}
              practicalTips={practicalTips}
              updateSectionStatus={updateSectionStatus}
              updateSectionContent={updateSectionContent}
              toggleSectionEdit={toggleSectionEdit}
              chatHistory={chatHistory}
              onFollowUp={handleFollowUp}
              onReset={resetToHome}
              onBack={handleGoBack}
              loading={loading}
            />
          )}
        </div>
      )}

      {loading && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-md flex items-center justify-center z-50">
          <div className="bg-white p-12 rounded-3xl shadow-2xl flex flex-col items-center gap-8 border-2 border-indigo-100 animate-pulse">
            <div className="w-20 h-20 border-8 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <div className="text-center"><p className="font-bold text-2xl text-indigo-900 mb-2">מעבד פדגוגיה...</p></div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { BloomLevel, Skill, AssessmentMethod } from "../types";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const testAiAssignment = async (assignmentText: string, fileData?: { data: string, mimeType: string }) => {
  const parts: any[] = [];

  // Add file if it exists
  if (fileData) {
    parts.push({
      inlineData: {
        data: fileData.data,
        mimeType: fileData.mimeType
      }
    });
  }

  // Add text instruction
  parts.push({
    text: `ענה על המטלה הבאה כסטודנט מצטיין. 
    החזר אך ורק את פתרון המטלה עצמו, כפי שסטודנט היה מגיש אותו. 
    אל תכתוב הקדמות (כמו "הנה הפתרון..."), אל תכתוב הערות מטא, ואל תכתוב סיכומים על איך ה-AI עזר. 

    הנחיה קריטית לעיצוב: התשובה חייבת להיות בטקסט פשוט (Plain Text) בלבד. 
    אין להשתמש בסימני Markdown (כמו כוכביות להדגשה, סולמיות לכותרות, וכו'). 
    כתוב את הטקסט בצורה נקייה וקריאה ללא עיצוב עשיר.

    תוכן המטלה (בנוסף לקובץ המצורף אם יש):
    ${assignmentText}`
  });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts },
    config: {
      temperature: 0.7,
    }
  });
  return response.text;
};

export const analyzeBloomTaxonomy = async (assignmentText: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נתח את המטלה הבאה לפי הטקסונומיה של בלום. 
    עליך לזהות את המיומנויות הנדרשות במשימה הנוכחית ולהציע הרחבות שיחזקו את הלמידה.

    הנחיות קריטיות לניתוח מיומנויות "זכירה" (Remember):
    בעידן הבינה המלאכותית, פעולות זכירה פשוטות (כמו שליפת עובדות) נעשות בקלות ע"י ה-AI ולכן אינן נחשבות כ"למידה" משמעותית.
    בניתוח שלך, ציין תחת רמת ה"זכירה" אך ורק עוגני ידע קריטיים, עקרונות ליבה, או מושגי יסוד שהסטודנט *חייב* להפנים בזיכרון לטווח ארוך כדי לתפקד בתחום, ואי אפשר להסתמך רק על שליפה חיצונית עבורם.

    המטלה: ${assignmentText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          currentSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          },
          suggestedSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          }
        },
        required: ["currentSkills", "suggestedSkills"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateAssessmentStrategies = async (skills: Skill[], numStudents: number) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `עבור רשימת המיומנויות הבאה וכיתה של ${numStudents} סטודנטים, אגד אותן לקבוצות הערכה לוגיות (2-3 קבוצות).

    כללים פדגוגיים להמלצה:
    1. קדם תהליך למידה משמעותי המשלב דרישה להתייחסות לתכנים ספציפיים שנלמדו בשיעור (ולא רק ידע כללי שה-AI מכיר).
    2. התחשב בגודל הכיתה (${numStudents} סטודנטים): הצע שיטות בנות-יישום (Scalable).
    3. אם המשימה מאפשרת זאת, הצע למרצה לשלב דרישה לחיבור לניסיון האישי של הסטודנט או למקרה בוחן מקומי/אקטואלי שקשה ל-AI לזייף.

    שיטות זמינות:
    FaceToFace (הערכה בסביבה מבוקרת): מבחן כתוב, בוחן ממוחשב, בחינה בע"פ, שאלות ידע בשיעור, הצגת תוצר, הערכת דיון, כתיבה בכיתה, הערכה מדגמית.
    Submission (הערכה בסביבה פתוחה): כתיבת משימה עם AI, משוב על תוצר AI, הערכת עמיתים, הערכה עצמית, סימולציה עם AI, יומן רפלקציה, תיעוד שלבי העבודה.

    המיומנויות שנבחרו: ${JSON.stringify(skills)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            skills: { type: Type.ARRAY, items: { type: Type.STRING } },
            method: { type: Type.STRING, description: "השיטה הספציפית המומלצת מתוך הרשימה" },
            type: { type: Type.STRING, enum: ['FaceToFace', 'Submission'] },
            explanation: { type: Type.STRING, description: "הסבר פדגוגי המדגיש את החיבור לתכנים שנלמדו בשיעור ואת ההתאמה לגודל הכיתה." }
          },
          required: ["skills", "method", "type", "explanation"]
        }
      }
    }
  });

  const res = JSON.parse(response.text);
  return res.map((item: any, index: number) => ({
    ...item,
    id: `group-${index}-${Date.now()}`
  }));
};

export interface TaskSection {
  title: string;
  content: string;
  audience: 'student' | 'lecturer';
}

export interface RephrasedResult {
  sections: TaskSection[];
  practicalTips: string;
}

export const rephraseAssignment = async (originalText: string, targetSkills: Skill[], strategies: AssessmentMethod[], numStudents: number) => {
  const labelsMap = {
    FaceToFace: 'הערכה בסביבה מבוקרת',
    Submission: 'הערכה בסביבה פתוחה'
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נסח מחדש את המטלה המקורית למטלה אקדמית מעודכנת. המטרה היא יצירת "משימת הערכה" שלמה ומפורטת.

    כללים מבניים חובה:
    1. עבור הסטודנטים (sections): חלק את ההנחיות לפרקים נפרדים עבור כל אחד ממרכיבי המטלה.
       עבור כל אסטרטגיה ברשימה להלן, צור אובייקט TaskSection נפרד (audience: 'student') עם כותרת בפורמט: "חלק [מספר]: [שיטת ההערכה]".
       כל חלק כזה חייב להסביר לסטודנט בדיוק מה עליו לעשות ובאילו מיומנויות הוא משתמש.
    2. עבור המרצה (sections): צור לפחות 2 פרקים נפרדים (audience: 'lecturer'):
       א. "שיקולי דעת פדגוגיים" - הסבר מדוע נבחרו השיטות הללו.
       ב. "הנחיות לוגיסטיות ודגשים לבדיקה" - כיצד לבצע את ההערכה בפועל עבור ${numStudents} סטודנטים.
    3. טיפים מעשיים (practicalTips): בנוסף לפרקים, כתוב סיכום קצר של עצות פרקטיות ורעיונות לגיוון המשימה ווידוא למידה אותנטית (למשל: שאלות ולידציה בכיתה, שינוי נתונים קטן, הצגה בעל פה מדגמית, וכו').

    דגש על אותנטיות ופרסונליזציה:
    אם זה רלוונטי למשימה, הוסף בהנחיות לסטודנט דרישה מפורשת לקשר את התוכן לניסיון אישי, דוגמאות מהסביבה הקרובה, או ניתוח מקרה אקטואלי/מקומי - כדי להקשות על יצירת תשובה גנרית ע"י AI.

    נתונים לשילוב:
    ${strategies.map((s, idx) => `- אסטרטגיה ${idx + 1}: מיומנויות [${s.skills.join(', ')}] בשיטת "${s.userSelectedMethod}" (סוג: ${labelsMap[s.userSelectedCategory as keyof typeof labelsMap]}).`).join('\n')}

    מטלה מקורית: ${originalText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                content: { type: Type.STRING },
                audience: { type: Type.STRING, enum: ['student', 'lecturer'] }
              },
              required: ["title", "content", "audience"]
            }
          },
          practicalTips: { type: Type.STRING }
        },
        required: ["sections", "practicalTips"]
      }
    }
  });
  return JSON.parse(response.text) as RephrasedResult;
};

export const askFollowUpQuestion = async (
  context: { originalText: string, revisedTask: TaskSection[], strategies: AssessmentMethod[] },
  question: string,
  history: { role: 'user' | 'model', text: string }[]
) => {
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `אתה עוזר פדגוגי מומחה. התמקד בחיבור לתוכן שנלמד בשיעור ובשיטות הערכה מגוונות.`,
    }
  });
  const response = await chat.sendMessage({ message: question });
  return response.text;
};

export const generateRubric = async (revisedSections: TaskSection[]) => {
  const studentInstructions = revisedSections
    .filter(s => s.audience === 'student')
    .map(s => s.content)
    .join('\n');

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `צור מחוון הערכה (Rubric) מלא עבור המטלה הבאה.
    המחוון צריך להיות בפורמט Markdown של טבלה.
    הקריטריונים צריכים לכלול היבטים כמו: איכות התוכן, חשיבה ביקורתית, שימוש מושכל ב-AI (אם רלוונטי), איכות הפרזנטציה/כתיבה, ורפלקציה.
    עבור כל קריטריון, הגדר 3 רמות ביצוע: מצטיין, עובר, טעון שיפור.

    תוכן המטלה:
    ${studentInstructions}
    `,
  });
  return response.text;
};

