import React, { useState, useMemo } from 'react';
import { BloomLevel, Skill } from '../types';
import { InfoBox } from './InfoBox';

interface StepSkillsAnalysisProps {
  bloomAnalysis: {currentSkills: Skill[], suggestedSkills: Skill[]} | null;
  selectedSkills: Skill[];
  handleSkillToggle: (skill: Skill) => void;
  customSkills: Skill[];
  onAddCustomSkill: (skill: Skill) => void;
  onNext: () => void;
  onBack: () => void;
  loading: boolean;
}

const StepSkillsAnalysis: React.FC<StepSkillsAnalysisProps> = ({
  bloomAnalysis, selectedSkills, handleSkillToggle, customSkills, onAddCustomSkill, onNext, onBack, loading
}) => {
  const [newSkillName, setNewSkillName] = useState('');
  const [newSkillLevel, setNewSkillLevel] = useState<BloomLevel>(BloomLevel.Apply);

  const handleAdd = () => {
    if (!newSkillName.trim()) return;
    const newSkill: Skill = {
      name: newSkillName.trim(),
      bloomLevel: newSkillLevel,
      reasoning: 'הוספה ידנית על ידי המרצה'
    };
    onAddCustomSkill(newSkill);
    setNewSkillName('');
  };

  const chartData = useMemo(() => {
    if (!bloomAnalysis) return { low: 0, high: 0 };

    const allSkills = [...bloomAnalysis.currentSkills, ...bloomAnalysis.suggestedSkills, ...customSkills];
    const lowOrderLevels = [BloomLevel.Remember, BloomLevel.Understand];

    let lowCount = 0;
    let highCount = 0;

    allSkills.forEach(skill => {
        // Consider selected skills, or all if none selected yet for the overview
        if (selectedSkills.length > 0 && !selectedSkills.some(s => s.name === skill.name)) return;

        if (lowOrderLevels.includes(skill.bloomLevel)) {
            lowCount++;
        } else {
            highCount++;
        }
    });

    const total = lowCount + highCount;
    if (total === 0) return { low: 0, high: 0 };
    return {
        low: Math.round((lowCount / total) * 100),
        high: Math.round((highCount / total) * 100)
    };

  }, [bloomAnalysis, customSkills, selectedSkills]);

  if (!bloomAnalysis) return null;

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border animate-fade-in">
      <InfoBox title="בחירת מיומנויות יעד">
        העוזר הפדגוגי ניתח את המטלה וחילק אותה למיומנויות. <strong>סמן ב-V</strong> את המיומנויות שברצונך להעריך במטלה החדשה. תוכל גם להוסיף מיומנויות משלך בתיבה למטה.
      </InfoBox>

      {/* Bloom Taxonomy Chart */}
      <div className="mb-8 p-6 bg-gray-50 rounded-xl border border-gray-200">
        <h4 className="font-bold text-gray-800 mb-4 text-center">פילוח רמות חשיבה (טקסונומיית בלום)</h4>
        <div className="flex h-12 rounded-full overflow-hidden shadow-inner">
            <div 
                style={{ width: `${chartData.low}%` }} 
                className="bg-amber-300 flex items-center justify-center text-amber-900 font-bold text-sm transition-all duration-500"
            >
                {chartData.low > 5 && `זכירה והבנה (${chartData.low}%)`}
            </div>
            <div 
                style={{ width: `${chartData.high}%` }} 
                className="bg-indigo-500 flex items-center justify-center text-white font-bold text-sm transition-all duration-500"
            >
                {chartData.high > 5 && `יישום, אנליזה ויצירה (${chartData.high}%)`}
            </div>
        </div>
        <div className="flex justify-between mt-2 text-xs text-gray-500 px-1">
             <span>רמות חשיבה בסיסיות (חשופות יותר ל-AI)</span>
             <span>רמות חשיבה גבוהות (למידה עמוקה)</span>
        </div>
      </div>

      <div className="grid gap-3 max-h-[500px] overflow-y-auto pr-2 mb-6">
        {bloomAnalysis.currentSkills.concat(bloomAnalysis.suggestedSkills).concat(customSkills).map((skill, idx) => (
          <div key={idx} className={`flex items-start gap-4 p-4 rounded-xl border transition-all ${selectedSkills.some(s => s.name === skill.name) ? 'bg-indigo-50 border-indigo-400 shadow-sm' : 'bg-gray-50 border-gray-200 opacity-80'}`}>
            <input type="checkbox" checked={selectedSkills.some(s => s.name === skill.name)} onChange={() => handleSkillToggle(skill)} className="mt-1.5 w-6 h-6 rounded-md cursor-pointer accent-indigo-600" />
            <div className="flex-1 cursor-pointer" onClick={() => handleSkillToggle(skill)}>
              <div className="flex items-center gap-2">
                <span className="font-bold text-indigo-900 text-lg">{skill.name}</span>
                <span className="text-xs bg-indigo-600 text-white px-2 py-0.5 rounded-full font-semibold">{skill.bloomLevel}</span>
              </div>
              <p className="text-sm text-gray-700 mt-1 leading-relaxed">{skill.reasoning}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="bg-gray-50 p-6 rounded-xl border border-gray-200 border-dashed mb-6">
        <h4 className="font-bold text-gray-800 mb-4">הוסף מיומנות יעד נוספת</h4>
        <div className="flex flex-col md:flex-row gap-4">
          <input 
            type="text" 
            value={newSkillName}
            onChange={(e) => setNewSkillName(e.target.value)}
            placeholder="שם המיומנות (למשל: עבודה בצוות, פרזנטציה...)"
            className="flex-1 p-3 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
          />
          <select 
            value={newSkillLevel}
            onChange={(e) => setNewSkillLevel(e.target.value as BloomLevel)}
            className="p-3 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
          >
            {Object.values(BloomLevel).map(level => (
              <option key={level} value={level}>{level}</option>
            ))}
          </select>
          <button 
            onClick={handleAdd}
            disabled={!newSkillName.trim()}
            className="bg-indigo-600 text-white px-6 py-3 rounded-lg font-bold hover:bg-indigo-700 transition-all disabled:opacity-50"
          >
            + הוסף מיומנות
          </button>
        </div>
      </div>

      <div className="flex gap-4 mt-8 pt-6 border-t">
        <button onClick={onBack} className="px-8 py-3 border rounded-lg font-bold hover:bg-gray-50">חזור</button>
        <button onClick={onNext} disabled={loading || selectedSkills.length === 0} className="flex-1 bg-indigo-600 text-white py-3 rounded-lg font-bold shadow-lg hover:bg-indigo-700 transition-all">המשך לניהול קבוצות מיומנויות</button>
      </div>
    </div>
  );
};

export default StepSkillsAnalysis;

import React, { useState, useRef, useEffect } from 'react';
import { TaskSection, generateRubric } from '../services/geminiService';
import { InfoBox } from './InfoBox';

const renderMarkdown = (text: string) => {
  const cleanText = text.replace(/\*/g, '');

  let html = cleanText
    .replace(/^### (.*$)/gim, '<h3 class="text-xl font-bold mt-4 mb-2 text-indigo-900">$1</h3>')
    .replace(/^## (.*$)/gim, '<h2 class="text-2xl font-bold mt-6 mb-3 text-indigo-900">$1</h2>')
    .replace(/^# (.*$)/gim, '<h1 class="text-3xl font-bold mt-8 mb-4 text-indigo-900">$1</h1>')
    .replace(/\|/gim, '<span class="text-gray-300 mx-2">|</span>') // Simple style for table pipes if not standard table
    .replace(/\n/gim, '<br />');

  // Basic markdown table support for rubric
  if (text.includes('|')) {
    // If it looks like a markdown table, try to render it slightly better or leave as pre-wrap
     return { __html: `<div class="overflow-x-auto"><pre class="whitespace-pre-wrap font-sans text-sm">${text}</pre></div>` };
  }

  return { __html: html };
};

interface SectionState extends TaskSection {
  status: 'pending' | 'approved' | 'removed';
  isEditing: boolean;
}

interface StepFinalResultProps {
  revisedSections: SectionState[];
  practicalTips: string;
  updateSectionStatus: (index: number, status: 'approved' | 'removed') => void;
  updateSectionContent: (index: number, content: string) => void;
  toggleSectionEdit: (index: number) => void;
  chatHistory: {role: 'user' | 'model', text: string}[];
  onFollowUp: (question: string) => void;
  onReset: () => void;
  onBack: () => void;
  loading: boolean;
}

const StepFinalResult: React.FC<StepFinalResultProps> = ({
  revisedSections, practicalTips, updateSectionStatus, updateSectionContent, toggleSectionEdit,
  chatHistory, onFollowUp, onReset, onBack, loading
}) => {
  const [followUpQuestion, setFollowUpQuestion] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);
  const [rubric, setRubric] = useState<string | null>(null);
  const [rubricLoading, setRubricLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const allSectionsHandled = revisedSections.length > 0 && revisedSections.every(s => s.status !== 'pending');
  const hasApprovedSections = revisedSections.some(s => s.status === 'approved');

  const copyAllToClipboard = () => {
    const text = revisedSections
      .filter(s => s.status === 'approved')
      .map(s => `${s.title}\n\n${s.content.replace(/\*/g, '')}`)
      .join('\n\n---\n\n');
    navigator.clipboard.writeText(text).then(() => {
      setCopySuccess(true);
      setTimeout(() => setCopySuccess(false), 2000);
    });
  };

  const handleSendFollowUp = () => {
    if (!followUpQuestion.trim()) return;
    onFollowUp(followUpQuestion);
    setFollowUpQuestion('');
  };

  const handleGenerateRubric = async () => {
    setRubricLoading(true);
    try {
        const res = await generateRubric(revisedSections);
        setRubric(res);
    } catch (e) {
        console.error(e);
        alert('שגיאה ביצירת המחוון');
    } finally {
        setRubricLoading(false);
    }
  };

  return (
    <div className="space-y-8 pb-20 animate-fade-in">
      <div className="bg-white p-10 rounded-2xl shadow-xl border-t-8 border-green-600">
        <InfoBox title="אישור ועריכת תוצרי המטלה" variant="success">
          לפניך נוסח המטלה המעודכן. <strong>מעבור על כל חלק</strong>: תוכל לאשר אותו כפי שהוא, לערוך את הטקסט או להסיר חלקים שאינם רלוונטיים. בסיום, תוכל להעתיק את כל החלקים שאושרו למסמך המטלה שלך.
        </InfoBox>

        <div className="flex justify-between items-center mb-8 border-b pb-4">
          <h3 className="text-3xl font-bold text-indigo-900">משימת הערכה</h3>
          <div className={`px-5 py-2 rounded-full font-bold text-sm border shadow-sm transition-colors ${allSectionsHandled ? 'bg-green-100 text-green-800 border-green-200' : 'bg-amber-100 text-amber-800 border-amber-200'}`}>
            {allSectionsHandled ? 'כל החלקים טופלו' : 'יש לאשר או לערוך את כל החלקים'}
          </div>
        </div>

        {practicalTips && (
          <div className="bg-amber-50 p-6 rounded-xl border border-amber-200 mb-10 shadow-sm">
            <h4 className="flex items-center gap-2 text-xl font-bold text-amber-900 mb-3">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              טיפים מעשיים לגיוון והערכה אותנטית
            </h4>
            <p className="text-amber-900/90 leading-relaxed whitespace-pre-wrap text-lg font-sans-normal">{practicalTips}</p>
          </div>
        )}

        <div className="space-y-12">
          <div>
            <h4 className="text-2xl font-bold text-indigo-700 mb-6 border-r-4 border-indigo-600 pr-4">הנחיות לסטודנטים</h4>
            <div className="space-y-6">
              {revisedSections.filter(s => s.audience === 'student').map((section, idx) => {
                const originalIdx = revisedSections.indexOf(section);
                return (
                  <div key={originalIdx} className={`p-6 rounded-2xl border-2 transition-all ${section.status === 'approved' ? 'border-green-400 bg-green-50/30' : section.status === 'removed' ? 'border-gray-200 bg-gray-50 opacity-50' : 'border-indigo-100 bg-white shadow-sm'}`}>
                    <div className="flex justify-between items-center mb-4">
                      <h5 className="text-xl font-bold text-indigo-900">{section.title}</h5>
                      <div className="flex gap-2">
                        <button onClick={() => updateSectionStatus(originalIdx, 'approved')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'approved' ? 'bg-green-600 text-white' : 'bg-white border text-green-600 hover:bg-green-50'}`}>אשר</button>
                        <button onClick={() => toggleSectionEdit(originalIdx)} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.isEditing ? 'bg-indigo-600 text-white shadow-inner' : 'bg-white border text-indigo-600 hover:bg-indigo-50'}`}>{section.isEditing ? 'שמור' : 'ערוך'}</button>
                        <button onClick={() => updateSectionStatus(originalIdx, 'removed')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'removed' ? 'bg-red-600 text-white' : 'bg-white border text-red-600 hover:bg-red-50'}`}>הסר</button>
                      </div>
                    </div>
                    {section.isEditing ? (
                      <textarea className="w-full p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 editor-textarea h-64 bg-white" value={section.content} onChange={(e) => updateSectionContent(originalIdx, e.target.value)} />
                    ) : (
                      <div className="prose prose-indigo max-w-none text-gray-800 leading-relaxed font-sans-normal whitespace-pre-wrap text-lg" dangerouslySetInnerHTML={renderMarkdown(section.content)} />
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          <div className="bg-gray-50 p-8 rounded-3xl border-2 border-dashed border-gray-300">
            <h4 className="text-2xl font-bold text-gray-700 mb-6 border-r-4 border-gray-500 pr-4">שיקולי דעת והנחיות למרצה</h4>
            <div className="space-y-6">
              {revisedSections.filter(s => s.audience === 'lecturer').map((section, idx) => {
                const originalIdx = revisedSections.indexOf(section);
                return (
                  <div key={originalIdx} className={`p-6 rounded-2xl border-2 transition-all ${section.status === 'approved' ? 'border-green-400 bg-green-50/20' : section.status === 'removed' ? 'border-gray-200 bg-gray-50 opacity-50' : 'border-gray-200 bg-white'}`}>
                    <div className="flex justify-between items-center mb-4">
                      <h5 className="text-xl font-bold text-gray-800">{section.title}</h5>
                      <div className="flex gap-2">
                        <button onClick={() => updateSectionStatus(originalIdx, 'approved')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'approved' ? 'bg-green-600 text-white' : 'bg-white border text-green-600 hover:bg-green-50'}`}>אשר</button>
                        <button onClick={() => toggleSectionEdit(originalIdx)} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.isEditing ? 'bg-indigo-600 text-white shadow-inner' : 'bg-white border text-indigo-600 hover:bg-indigo-50'}`}>{section.isEditing ? 'שמור' : 'ערוך'}</button>
                        <button onClick={() => updateSectionStatus(originalIdx, 'removed')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'removed' ? 'bg-red-600 text-white' : 'bg-white border text-red-600 hover:bg-red-50'}`}>הסר</button>
                      </div>
                    </div>
                    {section.isEditing ? (
                      <textarea className="w-full p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 editor-textarea h-64 bg-white" value={section.content} onChange={(e) => updateSectionContent(originalIdx, e.target.value)} />
                    ) : (
                      <div className="prose prose-indigo max-w-none text-gray-700 leading-relaxed font-sans-normal whitespace-pre-wrap text-lg opacity-90 italic" dangerouslySetInnerHTML={renderMarkdown(section.content)} />
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Rubric Generator Section */}
        <div className="mt-10 border-t pt-8">
            <div className="flex justify-between items-center mb-4">
                <h4 className="text-2xl font-bold text-indigo-900">מחוון הערכה (Rubric)</h4>
                {!rubric && (
                    <button 
                        onClick={handleGenerateRubric} 
                        disabled={rubricLoading}
                        className="bg-indigo-50 text-indigo-700 border border-indigo-200 px-6 py-2 rounded-xl font-bold hover:bg-indigo-100 transition-all shadow-sm"
                    >
                        {rubricLoading ? 'מייצר מחוון...' : '✨ צור מחוון הערכה למטלה'}
                    </button>
                )}
            </div>
            {rubric && (
                 <div className="bg-white p-6 rounded-2xl border-2 border-indigo-100 shadow-sm animate-fade-in overflow-x-auto">
                    <div className="prose prose-indigo max-w-none" dangerouslySetInnerHTML={renderMarkdown(rubric)} />
                 </div>
            )}
        </div>

        <div className="mt-12 pt-8 border-t flex flex-wrap gap-4">
          <button onClick={copyAllToClipboard} disabled={!hasApprovedSections} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all ${copySuccess ? 'bg-green-600 text-white border-green-600' : 'border-indigo-600 text-indigo-600 hover:bg-indigo-50 shadow-md'}`}>
            {copySuccess ? 'הטקסט הועתק!' : 'העתק את כל חלקי המטלה שאושרו'}
          </button>
        </div>
      </div>

      <div className="bg-white p-8 rounded-2xl shadow-md border border-gray-200 hide-on-print">
        <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-indigo-800"><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>דיוק והתייעצות נוספת</h3>
        <div className="max-h-80 overflow-y-auto mb-6 space-y-4 p-5 bg-gray-50 rounded-xl border shadow-inner">
          {chatHistory.length === 0 && <p className="text-gray-400 text-center italic py-4">שאל שאלות נוספות לדיוק המטלה...</p>}
          {chatHistory.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}><div className={`max-w-[85%] p-4 rounded-2xl shadow-sm ${msg.role === 'user' ? 'bg-indigo-100 text-indigo-900 border border-indigo-200' : 'bg-white text-gray-800 border border-gray-200'}`}>{msg.text}</div></div>
          ))}
          <div ref={chatEndRef} />
        </div>
        <div className="flex gap-2">
          <input type="text" value={followUpQuestion} onChange={(e) => setFollowUpQuestion(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleSendFollowUp()} placeholder="שאל שאלה נוספת..." className="flex-1 p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
          <button onClick={handleSendFollowUp} disabled={loading} className="bg-indigo-600 text-white px-8 py-2 rounded-xl font-bold hover:bg-indigo-700 transition-all">שלח</button>
        </div>
      </div>
      <div className="flex gap-4 hide-on-print">
        <button onClick={onBack} className="px-10 py-4 border-2 rounded-xl font-bold hover:bg-gray-100 transition-all">חזור</button>
        <button onClick={onReset} className="flex-1 bg-indigo-900 text-white py-4 rounded-xl font-bold hover:bg-black shadow-lg transition-all">סיים וחזור לדף הבית</button>
      </div>
    </div>
  );
};

export default StepFinalResult;

import React from 'react';

interface StepperProps {
  currentStep: number;
  onStepClick: (step: number) => void;
  maxReachedStep: number;
}

const steps = [
  { id: 1, label: 'הזנת נתונים' },
  { id: 2, label: 'ניתוח מיומנויות' },
  { id: 3, label: 'אסטרטגיות' },
  { id: 4, label: 'תוצר סופי' }
];

const Stepper: React.FC<StepperProps> = ({ currentStep, onStepClick, maxReachedStep }) => {
  return (
    <div className="w-full max-w-4xl mx-auto mb-10 px-4">
      <div className="relative flex items-center justify-between w-full">
        {/* Connection Lines */}
        <div className="absolute top-1/2 left-0 right-0 h-1 bg-gray-200 -z-10 transform -translate-y-1/2 rounded-full"></div>
        <div 
          className="absolute top-1/2 right-0 h-1 bg-indigo-500 -z-10 transform -translate-y-1/2 rounded-full transition-all duration-500" 
          style={{ width: `${((currentStep - 1) / (steps.length - 1)) * 100}%` }}
        ></div>

        {steps.map((step) => {
          const isCompleted = step.id < currentStep;
          const isCurrent = step.id === currentStep;
          const isClickable = step.id <= maxReachedStep;

          return (
            <button
              key={step.id}
              onClick={() => isClickable && onStepClick(step.id)}
              disabled={!isClickable}
              className={`flex flex-col items-center group focus:outline-none`}
            >
              <div 
                className={`w-10 h-10 rounded-full flex items-center justify-center border-4 font-bold text-sm transition-all duration-300 z-10
                ${isCurrent ? 'bg-indigo-600 border-indigo-200 text-white scale-110 shadow-lg' : 
                  isCompleted ? 'bg-indigo-500 border-indigo-500 text-white' : 
                  'bg-white border-gray-300 text-gray-400'
                }
                ${isClickable ? 'cursor-pointer hover:border-indigo-400' : 'cursor-default'}
                `}
              >
                {isCompleted ? (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                  </svg>
                ) : (
                  step.id
                )}
              </div>
              <span className={`absolute mt-12 text-xs font-bold whitespace-nowrap transition-colors duration-300 ${isCurrent ? 'text-indigo-900' : 'text-gray-400'}`}>
                {step.label}
              </span>
            </button>
          );
        })}
      </div>
    </div>
  );
};

export default Stepper;

import React, { useState } from 'react';
import Layout from './components/Layout';
import { InfoBox } from './components/InfoBox';
import StepInput from './components/StepInput';
import StepSkillsAnalysis from './components/StepSkillsAnalysis';
import StepStrategyBuilder from './components/StepStrategyBuilder';
import StepFinalResult from './components/StepFinalResult';
import Stepper from './components/Stepper';
import { AppMode, BloomLevel, Skill, AssessmentMethod } from './types';
import { 
  testAiAssignment, 
  analyzeBloomTaxonomy, 
  generateAssessmentStrategies, 
  rephraseAssignment, 
  askFollowUpQuestion,
  TaskSection
} from './services/geminiService';

interface SectionState extends TaskSection {
  status: 'pending' | 'approved' | 'removed';
  isEditing: boolean;
}

const stripMarkdown = (text: string) => {
  return text
    .replace(/\*\*(.*?)\*\*/g, '$1') // Bold
    .replace(/\*(.*?)\*/g, '$1') // Italic
    .replace(/##/g, '') // Headers
    .replace(/#/g, '') // Headers
    .replace(/`/g, '') // Code
    .replace(/\[(.*?)\]\(.*?\)/g, '$1') // Links
    .replace(/^\s*-\s/gm, '• ') // List items
    .trim();
};

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('HOME');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);
  const [maxReachedStep, setMaxReachedStep] = useState(1);
  const [assignmentText, setAssignmentText] = useState('');
  const [uploadedFile, setUploadedFile] = useState<{ name: string, data: string, mimeType: string } | null>(null);
  const [numStudents, setNumStudents] = useState<number>(30);
  const [aiResponse, setAiResponse] = useState('');
  const [lecturerScore, setLecturerScore] = useState<number | ''>('');
  const [lecturerFeedback, setLecturerFeedback] = useState('');
  const [bloomAnalysis, setBloomAnalysis] = useState<{currentSkills: Skill[], suggestedSkills: Skill[]} | null>(null);
  const [customSkills, setCustomSkills] = useState<Skill[]>([]);
  const [selectedSkills, setSelectedSkills] = useState<Skill[]>([]);
  const [strategies, setStrategies] = useState<AssessmentMethod[]>([]);
  const [revisedSections, setRevisedSections] = useState<SectionState[]>([]);
  const [practicalTips, setPracticalTips] = useState<string>('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const result = evt.target?.result as string;
      // Get base64 part
      const base64Data = result.split(',')[1];
      setUploadedFile({
        name: file.name,
        data: base64Data,
        mimeType: file.type
      });
    };
    reader.readAsDataURL(file);
  };

  const handleTestAi = async () => {
    if (!assignmentText.trim() && !uploadedFile) return;
    setLoading(true);
    try {
      const filePayload = uploadedFile ? { data: uploadedFile.data, mimeType: uploadedFile.mimeType } : undefined;
      const res = await testAiAssignment(assignmentText, filePayload);
      setAiResponse(res || 'לא התקבלה תשובה');
      setStep(2);
    } catch (error) {
      console.error(error);
      alert('שגיאה בבדיקת המטלה - אנא וודא שהקובץ תקין (PDF/Word)');
    } finally {
      setLoading(false);
    }
  };

  const startRedesign = async (initialText?: string) => {
    const textToAnalyze = initialText || assignmentText;
    if (!textToAnalyze.trim()) return;
    setAssignmentText(textToAnalyze);
    setMode('REDESIGN');
    setLoading(true);
    try {
      const analysis = await analyzeBloomTaxonomy(textToAnalyze);
      setBloomAnalysis(analysis);
      setSelectedSkills(analysis.currentSkills);
      setCustomSkills([]);
      setStep(2);
      setMaxReachedStep(Math.max(maxReachedStep, 2));
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleSkillToggle = (skill: Skill) => {
    setSelectedSkills(prev => 
      prev.some(s => s.name === skill.name) ? prev.filter(s => s.name !== skill.name) : [...prev, skill]
    );
  };

  const handleAddCustomSkill = (newSkill: Skill) => {
    setCustomSkills(prev => [...prev, newSkill]);
    setSelectedSkills(prev => [...prev, newSkill]);
  };

  const handleGetInitialStrategies = async () => {
    if (selectedSkills.length === 0) return;
    setLoading(true);
    try {
      const res = await generateAssessmentStrategies(selectedSkills, numStudents);
      setStrategies(res.map((s: any) => ({ ...s, userSelectedCategory: s.type, userSelectedMethod: s.method })));
      setStep(3);
      setMaxReachedStep(Math.max(maxReachedStep, 3));
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const updateStrategySelection = (index: number, category: 'FaceToFace' | 'Submission', method?: string) => {
    const newStrategies = [...strategies];
    newStrategies[index] = { ...newStrategies[index], userSelectedCategory: category, userSelectedMethod: method || '' };
    setStrategies(newStrategies);
  };

  const moveSkillToGroup = (skillName: string, targetGroupId: string) => {
    const newStrategies = strategies.map(s => {
      const remainingSkills = s.skills.filter(sk => sk !== skillName);
      if (s.id === targetGroupId) return { ...s, skills: [...s.skills.filter(sk => sk !== skillName), skillName] };
      return { ...s, skills: remainingSkills };
    }).filter(s => s.skills.length > 0);
    setStrategies(newStrategies);
  };

  const addNewGroup = (skillName: string, isDefense: boolean = false) => {
    const updatedOldGroups = strategies.map(s => ({ ...s, skills: s.skills.filter(sk => sk !== skillName) })).filter(s => s.skills.length > 0);
    const newGroup: AssessmentMethod = {
      id: `group-${Date.now()}`,
      skills: skillName === 'כללי' ? ['הגנה על העבודה (Defense)'] : [skillName],
      method: isDefense ? 'בחינה אישית בע"פ' : '',
      type: 'FaceToFace',
      explanation: isDefense ? 'אימות למידה וזהות המגיש (Defense) - מומלץ במיוחד במטלות המותרות לביצוע עם AI.' : 'קבוצה חדשה.',
      userSelectedCategory: 'FaceToFace',
      userSelectedMethod: isDefense ? 'בחינה אישית בע"פ' : ''
    };
    setStrategies([...updatedOldGroups, newGroup]);
  };

  const handleFinalRephrase = async () => {
    if (!strategies.every(s => s.userSelectedMethod)) return;
    setLoading(true);
    try {
      const { sections, practicalTips } = await rephraseAssignment(assignmentText, selectedSkills, strategies, numStudents);
      setRevisedSections(sections.map(s => ({ ...s, status: 'pending', isEditing: false })));
      setPracticalTips(practicalTips);
      setStep(4);
      setMaxReachedStep(Math.max(maxReachedStep, 4));
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleFollowUp = async (question: string) => {
    setChatHistory(prev => [...prev, { role: 'user', text: question }]);
    setLoading(true);
    try {
      const response = await askFollowUpQuestion({ originalText: assignmentText, revisedTask: revisedSections, strategies }, question, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: response || '' }]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const resetToHome = () => {
    setMode('HOME');
    setStep(1);
    setMaxReachedStep(1);
    setAssignmentText('');
    setUploadedFile(null);
    setAiResponse('');
    setLecturerScore('');
    setLecturerFeedback('');
    setBloomAnalysis(null);
    setCustomSkills([]);
    setSelectedSkills([]);
    setStrategies([]);
    setRevisedSections([]);
    setPracticalTips('');
    setChatHistory([]);
  };

  const handleGoBack = () => {
    setStep(prev => prev > 1 ? prev - 1 : prev);
    if (step === 1) setMode('HOME');
  };

  const updateSectionStatus = (index: number, status: 'approved' | 'removed') => {
    const newSections = [...revisedSections];
    newSections[index].status = status;
    setRevisedSections(newSections);
  };

  const updateSectionContent = (index: number, content: string) => {
    const newSections = [...revisedSections];
    newSections[index].content = content;
    setRevisedSections(newSections);
  };

  const toggleSectionEdit = (index: number) => {
    const newSections = [...revisedSections];
    newSections[index].isEditing = !newSections[index].isEditing;
    setRevisedSections(newSections);
  };

  const goToStep = (targetStep: number) => {
    if (targetStep <= maxReachedStep) {
      setStep(targetStep);
    }
  };

  return (
    <Layout title={mode === 'HOME' ? 'Re-Assess' : mode === 'TEST_AI' ? 'בדיקה מול AI' : 'עיצוב מחדש'} onBack={mode !== 'HOME' ? handleGoBack : undefined}>
      <style>{`
        .animate-fade-in { animation: fadeIn 0.4s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
        .skill-btn { transition: all 0.2s; }
        .skill-btn:hover { transform: translateY(-1px); box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
        .font-sans-normal { font-style: normal !important; font-family: 'Assistant', sans-serif; }
        .editor-textarea {
          font-family: 'Assistant', sans-serif;
          line-height: 1.625;
          font-size: 1.125rem;
          color: #1f2937;
        }
        .plain-text-response {
          font-family: 'Courier New', Courier, monospace;
          white-space: pre-wrap;
          line-height: 1.6;
        }
      `}</style>

      {mode === 'HOME' && (
        <div className="flex flex-col items-center gap-8 py-12">
          <div className="text-center space-y-4">
            <h2 className="text-4xl font-bold text-gray-800">איך המטלה שלך נראית בעידן ה-AI?</h2>
            <p className="text-xl text-gray-600 max-w-2xl">שיפור פדגוגיה ועידוד למידה משמעותית באמצעות עיצוב מחדש של דרכי הערכה.</p>
          </div>

          <InfoBox title="איך מתחילים?">
            בחר את המסלול המתאים לך: אם תרצה לראות תחילה כיצד ה-AI פותר את המטלה הקיימת שלך, בחר <strong>"בדוק מול ה-AI"</strong>. אם תרצה לגשת ישירות לעיצוב מחדש פדגוגי, בחר <strong>"עיצוב למידה מחדש"</strong>.
          </InfoBox>

          <div className="grid md:grid-cols-2 gap-6 w-full max-w-3xl">
            <button onClick={() => { setMode('TEST_AI'); setStep(1); }} className="bg-white border-2 border-indigo-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-indigo-400 text-right group transition-all">
              <div className="bg-indigo-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">בדוק מול ה-AI</h3>
              <p className="text-gray-600">ראה כיצד הבינה המלאכותית פותרת את המטלה הקיימת ונתח את העומק הפדגוגי שלה.</p>
            </button>
            <button onClick={() => { setMode('REDESIGN'); setStep(1); }} className="bg-white border-2 border-green-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-green-400 text-right group transition-all">
              <div className="bg-green-50 w-12 h-12 rounded-lg flex items-center justify-center mb-4 group-hover:bg-green-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">עיצוב למידה מחדש</h3>
              <p className="text-gray-600">נתח מיומנויות ושדרג את המערך הפדגוגי לליווי מיטבי של הסטודנטים.</p>
            </button>
          </div>
        </div>
      )}

      {mode === 'TEST_AI' && (
        <div className="space-y-6 animate-fade-in">
          {step === 1 ? (
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
              <InfoBox title="שלב 1: הזנת המטלה">
                הדבק כאן את נוסח המטלה המקורי שאתה נותן לסטודנטים, או העלה קובץ (PDF/Word). המערכת תשתמש ב-AI כדי לנסות לפתור אותה.
              </InfoBox>

              <div className="space-y-4">
                <div>
                  <label className="block text-lg font-semibold mb-2">אפשרות א': הדבק טקסט</label>
                  <textarea 
                    value={assignmentText} 
                    onChange={(e) => setAssignmentText(e.target.value)} 
                    className="w-full h-32 p-4 border rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" 
                    placeholder="הדבק כאן את הנחיית המטלה שלך..." 
                  />
                </div>

                <div className="flex items-center gap-4 my-2">
                  <div className="h-px bg-gray-200 flex-1"></div>
                  <span className="text-gray-400 text-sm font-bold">או</span>
                  <div className="h-px bg-gray-200 flex-1"></div>
                </div>

                <div>
                  <label className="block text-lg font-semibold mb-2">אפשרות ב': העלה קובץ (PDF / Word)</label>
                  <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-6 hover:bg-gray-50 transition-colors text-center cursor-pointer">
                    <input 
                      type="file" 
                      accept=".pdf,.docx,.txt" 
                      onChange={handleFileUpload}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    />
                    <div className="flex flex-col items-center justify-center pointer-events-none">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-gray-400 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
