                </div>
              </div>

              <button onClick={handleTestAi} disabled={loading || (!assignmentText && !uploadedFile)} className="mt-6 w-full bg-indigo-600 text-white py-4 rounded-xl font-bold text-lg shadow-md hover:bg-indigo-700 transition-all">הדגם פתרון AI</button>
            </div>
          ) : (
            <div className="space-y-6">
              <InfoBox title="שלב 2: ניתוח התוצאה">
                לפניך פתרון שהופק על ידי AI. בחן אותו בעיניים של מרצה: האם הוא עונה על הדרישות? האם חסר בו עומק? תן ציון ופידבק כדי להחליט אם המטלה זקוקה לעיצוב מחדש.
              </InfoBox>
              <div className="bg-blue-50 p-6 rounded-xl border border-blue-200 shadow-inner">
                <h3 className="font-bold text-blue-900 mb-3 text-lg border-b border-blue-100 pb-2">תשובת ה-AI (טקסט בלבד):</h3>
                <div className="plain-text-response text-gray-800 bg-white p-6 rounded-lg shadow-sm border border-gray-100 text-lg">
                  {stripMarkdown(aiResponse)}
                </div>
              </div>

              <div className="bg-white p-6 rounded-2xl border-2 border-indigo-100 shadow-xl space-y-6 animate-fade-in">
                <h3 className="text-xl font-bold text-indigo-900">הערכת מרצה לפתרון ה-AI</h3>
                <div className="grid md:grid-cols-3 gap-6">
                  <div className="md:col-span-1">
                    <label className="block text-sm font-bold text-gray-700 mb-2">ציון למטלה (0-100):</label>
                    <input type="number" min="0" max="100" value={lecturerScore} onChange={(e) => setLecturerScore(e.target.value === '' ? '' : Number(e.target.value))} className="w-full p-4 border-2 border-indigo-100 rounded-xl focus:ring-2 focus:ring-indigo-500 font-bold text-2xl text-center text-indigo-900" placeholder="ציון" />
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-sm font-bold text-gray-700 mb-2">פידבק קצר על איכות הפתרון:</label>
                    <textarea value={lecturerFeedback} onChange={(e) => setLecturerFeedback(e.target.value)} className="w-full p-4 border-2 border-indigo-100 rounded-xl focus:ring-2 focus:ring-indigo-500 h-24" placeholder="האם ה-AI הצליח להגיע לעומק הנדרש?" />
                  </div>
                </div>
                {lecturerScore !== '' && (
                  <div className="animate-fade-in p-6 rounded-xl border-l-8 border-indigo-600 bg-indigo-50">
                    <h4 className="font-bold text-indigo-900 mb-2 text-lg">{lecturerScore > 70 ? '⚠️ המשימה מאפשרת פתרון AI מהיר' : '✅ המשימה מאתגרת את ה-AI'}</h4>
                    <p className="text-gray-700">{lecturerScore > 70 ? 'נראה שהבינה המלאכותית מספקת מענה איכותי בקלות. כדאי לשקול שינוי בדרכי ההערכה.' : 'המשימה שלך דורשת מיומנויות שה-AI מתקשה בהן, וזה מצוין!'}</p>
                  </div>
                )}
                <div className="flex flex-wrap gap-4 pt-4">
                  <button onClick={() => setStep(1)} className="flex-1 border-2 border-indigo-600 text-indigo-600 py-3 rounded-xl font-bold hover:bg-indigo-50 transition-all">דיוק המשימה וניסיון נוסף</button>
                  <button onClick={() => startRedesign()} className="flex-1 bg-green-600 text-white py-3 rounded-xl font-bold shadow-lg hover:bg-green-700 transition-all">עבור לעיצוב פדגוגי מקיף</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {mode === 'REDESIGN' && (
        <div className="space-y-6 animate-fade-in">
          <Stepper currentStep={step} onStepClick={goToStep} maxReachedStep={maxReachedStep} />

          {step === 1 && (
            <StepInput
              assignmentText={assignmentText}
              setAssignmentText={setAssignmentText}
              numStudents={numStudents}
              setNumStudents={setNumStudents}
              onNext={() => startRedesign()}
              loading={loading}
            />
          )}

          {step === 2 && bloomAnalysis && (
            <StepSkillsAnalysis
              bloomAnalysis={bloomAnalysis}
              selectedSkills={selectedSkills}
              handleSkillToggle={handleSkillToggle}
              customSkills={customSkills}
              onAddCustomSkill={handleAddCustomSkill}
              onNext={handleGetInitialStrategies}
              onBack={handleGoBack}
              loading={loading}
            />
          )}

          {step === 3 && strategies.length > 0 && (
            <StepStrategyBuilder
              strategies={strategies}
              numStudents={numStudents}
              updateStrategySelection={updateStrategySelection}
              moveSkillToGroup={moveSkillToGroup}
              addNewGroup={addNewGroup}
              onNext={handleFinalRephrase}
              onBack={handleGoBack}
              loading={loading}
            />
          )}

          {step === 4 && (
            <StepFinalResult
              revisedSections={revisedSections}
              practicalTips={practicalTips}
              updateSectionStatus={updateSectionStatus}
              updateSectionContent={updateSectionContent}
              toggleSectionEdit={toggleSectionEdit}
              chatHistory={chatHistory}
              onFollowUp={handleFollowUp}
              onReset={resetToHome}
              onBack={handleGoBack}
              loading={loading}
            />
          )}
        </div>
      )}

      {loading && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-md flex items-center justify-center z-50">
          <div className="bg-white p-12 rounded-3xl shadow-2xl flex flex-col items-center gap-8 border-2 border-indigo-100 animate-pulse">
            <div className="w-20 h-20 border-8 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <div className="text-center"><p className="font-bold text-2xl text-indigo-900 mb-2">מעבד פדגוגיה...</p></div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { BloomLevel, Skill, AssessmentMethod } from "../types";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

// NOTE: testAiAssignment function removed as per requirements to remove that mode.

export const analyzeBloomTaxonomy = async (assignmentText: string, fileData?: { data: string, mimeType: string }) => {
  const parts: any[] = [];

  // Add file if it exists
  if (fileData) {
    parts.push({
      inlineData: {
        data: fileData.data,
        mimeType: fileData.mimeType
      }
    });
  }

  parts.push({
    text: `נתח את המטלה הבאה לפי הטקסונומיה של בלום. 
    עליך לזהות את המיומנויות הנדרשות במשימה הנוכחית ולהציע הרחבות שיחזקו את הלמידה.

    הנחיות קריטיות לניתוח מיומנויות "זכירה" (Remember):
    בעידן הבינה המלאכותית, פעולות זכירה פשוטות (כמו שליפת עובדות) נעשות בקלות ע"י ה-AI ולכן אינן נחשבות כ"למידה" משמעותית.
    בניתוח שלך, ציין תחת רמת ה"זכירה" אך ורק עוגני ידע קריטיים, עקרונות ליבה, או מושגי יסוד שהסטודנט *חייב* להפנים בזיכרון לטווח ארוך כדי לתפקד בתחום, ואי אפשר להסתמך רק על שליפה חיצונית עבורם.

    המטלה (טקסט ו/או קובץ מצורף): ${assignmentText}`
  });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          currentSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          },
          suggestedSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          }
        },
        required: ["currentSkills", "suggestedSkills"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateAssessmentStrategies = async (skills: Skill[], numStudents: number) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `עבור רשימת המיומנויות הבאה וכיתה של ${numStudents} סטודנטים, אגד אותן לקבוצות הערכה לוגיות (2-3 קבוצות).

    כללים פדגוגיים להמלצה:
    1. קדם תהליך למידה משמעותי המשלב דרישה להתייחסות לתכנים ספציפיים שנלמדו בשיעור (ולא רק ידע כללי שה-AI מכיר).
    2. התחשב בגודל הכיתה (${numStudents} סטודנטים): הצע שיטות בנות-יישום (Scalable).
    3. אם המשימה מאפשרת זאת, הצע למרצה לשלב דרישה לחיבור לניסיון האישי של הסטודנט או למקרה בוחן מקומי/אקטואלי שקשה ל-AI לזייף.

    שיטות זמינות:
    FaceToFace (הערכה בסביבה מבוקרת): מבחן כתוב, בוחן ממוחשב, בחינה בע"פ, שאלות ידע בשיעור, הצגת תוצר, הערכת דיון, כתיבה בכיתה, הערכה מדגמית.
    Submission (הערכה בסביבה פתוחה): כתיבת משימה עם AI, משוב על תוצר AI, הערכת עמיתים, הערכה עצמית, סימולציה עם AI, יומן רפלקציה, תיעוד שלבי העבודה.

    המיומנויות שנבחרו: ${JSON.stringify(skills)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            skills: { type: Type.ARRAY, items: { type: Type.STRING } },
            method: { type: Type.STRING, description: "השיטה הספציפית המומלצת מתוך הרשימה" },
            type: { type: Type.STRING, enum: ['FaceToFace', 'Submission'] },
            explanation: { type: Type.STRING, description: "הסבר פדגוגי המדגיש את החיבור לתכנים שנלמדו בשיעור ואת ההתאמה לגודל הכיתה." }
          },
          required: ["skills", "method", "type", "explanation"]
        }
      }
    }
  });

  const res = JSON.parse(response.text);
  return res.map((item: any, index: number) => ({
    ...item,
    id: `group-${index}-${Date.now()}`
  }));
};

export interface TaskSection {
  title: string;
  content: string;
  audience: 'student' | 'lecturer';
}

export interface RephrasedResult {
  sections: TaskSection[];
  practicalTips: string;
}

export const rephraseAssignment = async (originalText: string, targetSkills: Skill[], strategies: AssessmentMethod[], numStudents: number) => {
  const labelsMap = {
    FaceToFace: 'הערכה בסביבה מבוקרת',
    Submission: 'הערכה בסביבה פתוחה'
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נסח מחדש את המטלה המקורית למטלה אקדמית מעודכנת. המטרה היא יצירת "משימת הערכה" שלמה ומפורטת.

    כללים מבניים חובה:
    1. עבור הסטודנטים (sections): חלק את ההנחיות לפרקים נפרדים עבור כל אחד ממרכיבי המטלה.
       עבור כל אסטרטגיה ברשימה להלן, צור אובייקט TaskSection נפרד (audience: 'student') עם כותרת בפורמט: "חלק [מספר]: [שיטת ההערכה]".
       כל חלק כזה חייב להסביר לסטודנט בדיוק מה עליו לעשות ובאילו מיומנויות הוא משתמש.
    2. עבור המרצה (sections): צור לפחות 2 פרקים נפרדים (audience: 'lecturer'):
       א. "שיקולי דעת פדגוגיים" - הסבר מדוע נבחרו השיטות הללו.
       ב. "הנחיות לוגיסטיות ודגשים לבדיקה" - כיצד לבצע את ההערכה בפועל עבור ${numStudents} סטודנטים.
    3. סיכום האסטרטגיות (practicalTips): בסעיף זה כתוב סיכום קצר ובהיר של האסטרטגיות שנבחרו, וכיצד הן משרתות את המיומנויות שנבחרו בתהליך העיצוב (למשל: "נבחרה אסטרטגיה של הגנה בע"פ כדי לוודא זכירה של מושגי יסוד..."). התמקד בבחירות החדשות שנעשו.

    דגש על אותנטיות ופרסונליזציה:
    אם זה רלוונטי למשימה, הוסף בהנחיות לסטודנט דרישה מפורשת לקשר את התוכן לניסיון אישי, דוגמאות מהסביבה הקרובה, או ניתוח מקרה אקטואלי/מקומי - כדי להקשות על יצירת תשובה גנרית ע"י AI.

    נתונים לשילוב:
    ${strategies.map((s, idx) => `- אסטרטגיה ${idx + 1}: מיומנויות [${s.skills.join(', ')}] בשיטת "${s.userSelectedMethod}" (סוג: ${labelsMap[s.userSelectedCategory as keyof typeof labelsMap]}).`).join('\n')}

    מטלה מקורית: ${originalText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                content: { type: Type.STRING },
                audience: { type: Type.STRING, enum: ['student', 'lecturer'] }
              },
              required: ["title", "content", "audience"]
            }
          },
          practicalTips: { type: Type.STRING, description: "Summary of strategies and chosen skills" }
        },
        required: ["sections", "practicalTips"]
      }
    }
  });
  return JSON.parse(response.text) as RephrasedResult;
};

export const askFollowUpQuestion = async (
  context: { originalText: string, revisedTask: TaskSection[], strategies: AssessmentMethod[] },
  question: string,
  history: { role: 'user' | 'model', text: string }[]
) => {
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `אתה עוזר פדגוגי מומחה. התמקד בחיבור לתוכן שנלמד בשיעור ובשיטות הערכה מגוונות.`,
    }
  });
  const response = await chat.sendMessage({ message: question });
  return response.text;
};

export const generateRubric = async (revisedSections: TaskSection[]) => {
  const studentInstructions = revisedSections
    .filter(s => s.audience === 'student')
    .map(s => s.content)
    .join('\n');

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `צור מחוון הערכה (Rubric) מלא עבור המטלה הבאה.

    הנחיית עיצוב קריטית: 
    אין להשתמש בטבלאות Markdown (כלומר בלי תווים כמו | או ---).
    במקום טבלה, השתמש ברשימה מובנית וברורה.
    עבור כל קריטריון, כתוב את שמו ככותרת מודגשת, ואז פרט את רמות הביצוע (מצטיין, עובר, טעון שיפור) כרשימת תבליטים מתחתיו.

    הקריטריונים צריכים לכלול היבטים כמו: איכות התוכן, חשיבה ביקורתית, שימוש מושכל ב-AI (אם רלוונטי), איכות הפרזנטציה/כתיבה, ורפלקציה.

    תוכן המטלה:
    ${studentInstructions}
    `,
  });
  return response.text;
};

