const renderMarkdown = (text: string) => {
  const cleanText = text.replace(/\*/g, ''); // Remove explicit stars if needed, but we keep bold tags later

  let html = cleanText
    .replace(/^### (.*$)/gim, '<h3 class="text-xl font-bold mt-4 mb-2 text-indigo-900">$1</h3>')
    .replace(/^## (.*$)/gim, '<h2 class="text-2xl font-bold mt-6 mb-3 text-indigo-900">$1</h2>')
    .replace(/^# (.*$)/gim, '<h1 class="text-3xl font-bold mt-8 mb-4 text-indigo-900">$1</h1>')
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>') // Handle bold
    .replace(/\n/gim, '<br />');

  // If there are still pipe characters from potential markdown tables, clean them for display
  if (html.includes('|')) {
     html = html.replace(/\|/g, ''); 
     html = html.replace(/-{3,}/g, ''); // Remove divider lines
  }

  return { __html: html };
};

