                        <button onClick={() => updateSectionStatus(originalIdx, 'approved')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'approved' ? 'bg-green-600 text-white' : 'bg-white border text-green-600 hover:bg-green-50'}`}>אשר</button>
                        <button onClick={() => toggleSectionEdit(originalIdx)} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.isEditing ? 'bg-indigo-600 text-white shadow-inner' : 'bg-white border text-indigo-600 hover:bg-indigo-50'}`}>{section.isEditing ? 'שמור' : 'ערוך'}</button>
                        <button onClick={() => updateSectionStatus(originalIdx, 'removed')} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${section.status === 'removed' ? 'bg-red-600 text-white' : 'bg-white border text-red-600 hover:bg-red-50'}`}>הסר</button>
                      </div>
                    </div>
                    {section.isEditing ? (
                      <textarea className="w-full p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 editor-textarea h-64 bg-white" value={section.content} onChange={(e) => updateSectionContent(originalIdx, e.target.value)} />
                    ) : (
                      <div className="prose prose-indigo max-w-none text-gray-700 leading-relaxed font-sans-normal whitespace-pre-wrap text-lg opacity-90 italic" dangerouslySetInnerHTML={renderMarkdown(section.content)} />
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Rubric Generator Section */}
        <div className="mt-10 border-t pt-8">
            <div className="flex justify-between items-center mb-4">
                <h4 className="text-2xl font-bold text-indigo-900">מחוון הערכה (Rubric)</h4>
                {!rubric && (
                    <button 
                        onClick={handleGenerateRubric} 
                        disabled={rubricLoading}
                        className="bg-indigo-50 text-indigo-700 border border-indigo-200 px-6 py-2 rounded-xl font-bold hover:bg-indigo-100 transition-all shadow-sm"
                    >
                        {rubricLoading ? 'מייצר מחוון...' : '✨ צור מחוון הערכה למטלה'}
                    </button>
                )}
            </div>
            {rubric && (
                 <div className="bg-white p-6 rounded-2xl border-2 border-indigo-100 shadow-sm animate-fade-in">
                    <div className="flex justify-between items-center mb-4">
                        <div className="text-sm text-gray-500 italic">ניתן לערוך את הטבלה ע"י לחיצה על "ערוך"</div>
                        <div className="flex gap-2">
                           <button onClick={() => setIsRubricEditing(!isRubricEditing)} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all ${isRubricEditing ? 'bg-indigo-600 text-white shadow-inner' : 'bg-white border text-indigo-600 hover:bg-indigo-50'}`}>
                             {isRubricEditing ? 'שמור שינויים' : 'ערוך טבלה'}
                           </button>
                           <button onClick={copyRubricToClipboard} className={`px-4 py-1.5 rounded-lg font-bold text-xs transition-all border ${rubricCopySuccess ? 'bg-green-600 text-white border-green-600' : 'bg-white text-gray-600 border-gray-300 hover:bg-gray-50'}`}>
                             {rubricCopySuccess ? 'הועתק!' : 'העתק מחוון'}
                           </button>
                        </div>
                    </div>
                    <div className="overflow-x-auto">
                      <table className="w-full text-right border-collapse min-w-[800px]">
                        <thead>
                          <tr className="bg-indigo-50 text-indigo-900">
                            <th className="p-3 border border-indigo-100 w-1/4">קריטריון</th>
                            <th className="p-3 border border-indigo-100 w-1/4">מצטיין</th>
                            <th className="p-3 border border-indigo-100 w-1/4">טוב / עובר</th>
                            <th className="p-3 border border-indigo-100 w-1/4">טעון שיפור</th>
                          </tr>
                        </thead>
                        <tbody>
                          {rubric.map((row, idx) => (
                            <tr key={idx} className="hover:bg-gray-50">
                              <td className="p-3 border border-gray-200 align-top font-bold text-gray-800">
                                {isRubricEditing ? <textarea value={row.criterion} onChange={(e) => handleRubricChange(idx, 'criterion', e.target.value)} className="w-full h-full p-2 border rounded bg-white text-sm" rows={3} /> : row.criterion}
                              </td>
                              <td className="p-3 border border-gray-200 align-top text-gray-700 text-sm">
                                {isRubricEditing ? <textarea value={row.excellent} onChange={(e) => handleRubricChange(idx, 'excellent', e.target.value)} className="w-full h-full p-2 border rounded bg-white text-sm" rows={4} /> : row.excellent}
                              </td>
                              <td className="p-3 border border-gray-200 align-top text-gray-700 text-sm">
                                {isRubricEditing ? <textarea value={row.good} onChange={(e) => handleRubricChange(idx, 'good', e.target.value)} className="w-full h-full p-2 border rounded bg-white text-sm" rows={4} /> : row.good}
                              </td>
                              <td className="p-3 border border-gray-200 align-top text-gray-700 text-sm">
                                {isRubricEditing ? <textarea value={row.needsImprovement} onChange={(e) => handleRubricChange(idx, 'needsImprovement', e.target.value)} className="w-full h-full p-2 border rounded bg-white text-sm" rows={4} /> : row.needsImprovement}
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                 </div>
            )}
        </div>

        <div className="mt-12 pt-8 border-t flex flex-wrap gap-4">
          <button onClick={copyAllToClipboard} disabled={!hasApprovedSections} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all ${copySuccess ? 'bg-green-600 text-white border-green-600' : 'border-indigo-600 text-indigo-600 hover:bg-indigo-50 shadow-md'}`}>
            {copySuccess ? 'הטקסט הועתק!' : 'העתק את כל חלקי המטלה שאושרו'}
          </button>
        </div>
      </div>

      <div className="bg-white p-8 rounded-2xl shadow-md border border-gray-200 hide-on-print">
        <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-indigo-800"><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>דיוק והתייעצות נוספת</h3>
        <div className="max-h-80 overflow-y-auto mb-6 space-y-4 p-5 bg-gray-50 rounded-xl border shadow-inner">
          {chatHistory.length === 0 && <p className="text-gray-400 text-center italic py-4">שאל שאלות נוספות לדיוק המטלה...</p>}
          {chatHistory.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}><div className={`max-w-[85%] p-4 rounded-2xl shadow-sm ${msg.role === 'user' ? 'bg-indigo-100 text-indigo-900 border border-indigo-200' : 'bg-white text-gray-800 border border-gray-200'}`}>{msg.text}</div></div>
          ))}
          <div ref={chatEndRef} />
        </div>
        <div className="flex gap-2">
          <input type="text" value={followUpQuestion} onChange={(e) => setFollowUpQuestion(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleSendFollowUp()} placeholder="שאל שאלה נוספת..." className="flex-1 p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 shadow-inner" />
          <button onClick={handleSendFollowUp} disabled={loading} className="bg-indigo-600 text-white px-8 py-2 rounded-xl font-bold hover:bg-indigo-700 transition-all">שלח</button>
        </div>
      </div>
      <div className="flex gap-4 hide-on-print">
        <button onClick={onBack} className="px-10 py-4 border-2 rounded-xl font-bold hover:bg-gray-100 transition-all">חזור</button>
        <button onClick={onReset} className="flex-1 bg-indigo-900 text-white py-4 rounded-xl font-bold hover:bg-black shadow-lg transition-all">סיים וחזור לדף הבית</button>
      </div>
    </div>
  );
};

export default StepFinalResult;

import React, { useState } from 'react';
import Layout from './components/Layout';
import { InfoBox } from './components/InfoBox';
import StepInput from './components/StepInput';
import StepSkillsAnalysis from './components/StepSkillsAnalysis';
import StepStrategyBuilder from './components/StepStrategyBuilder';
import StepFinalResult from './components/StepFinalResult';
import Stepper from './components/Stepper';
import { AppMode, BloomLevel, Skill, AssessmentMethod } from './types';
import mammoth from 'mammoth';
import { 
  analyzeBloomTaxonomy, 
  generateAssessmentStrategies, 
  rephraseAssignment, 
  askFollowUpQuestion,
  TaskSection
} from './services/geminiService';

interface SectionState extends TaskSection {
  status: 'pending' | 'approved' | 'removed';
  isEditing: boolean;
}

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('HOME');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);
  const [maxReachedStep, setMaxReachedStep] = useState(1);
  const [assignmentText, setAssignmentText] = useState('');
  const [uploadedFile, setUploadedFile] = useState<{ name: string, data: string, mimeType: string } | null>(null);
  const [numStudents, setNumStudents] = useState<number>(30);
  const [bloomAnalysis, setBloomAnalysis] = useState<{currentSkills: Skill[], suggestedSkills: Skill[]} | null>(null);
  const [customSkills, setCustomSkills] = useState<Skill[]>([]);
  const [selectedSkills, setSelectedSkills] = useState<Skill[]>([]);
  const [strategies, setStrategies] = useState<AssessmentMethod[]>([]);
  const [revisedSections, setRevisedSections] = useState<SectionState[]>([]);
  const [practicalTips, setPracticalTips] = useState<string>('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Handle DOCX files by extracting text
    if (file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document') {
      const reader = new FileReader();
      reader.onload = async (evt) => {
        const arrayBuffer = evt.target?.result as ArrayBuffer;
        try {
          const result = await mammoth.extractRawText({ arrayBuffer });
          const text = result.value;
          setAssignmentText(prev => {
             const newText = prev ? prev + '\n\n' + text : text;
             return newText;
          });
          // Clear any previously uploaded file binary to avoid sending docx to API
          setUploadedFile(null);
          // Optional: You could notify the user that text was extracted
        } catch (error) {
          console.error("Error reading Word file:", error);
          alert("שגיאה בקריאת קובץ Word. אנא נסה להעתיק את הטקסט ידנית.");
        }
      };
      reader.readAsArrayBuffer(file);
      return;
    }

    // Handle PDF and other supported types
    const reader = new FileReader();
    reader.onload = (evt) => {
      const result = evt.target?.result as string;
      // Get base64 part
      const base64Data = result.split(',')[1];
      setUploadedFile({
        name: file.name,
        data: base64Data,
        mimeType: file.type
      });
    };
    reader.readAsDataURL(file);
  };

  const startRedesign = async (initialText?: string) => {
    const textToAnalyze = initialText || assignmentText;
    if (!textToAnalyze.trim() && !uploadedFile) return;
    setAssignmentText(textToAnalyze);
    setMode('REDESIGN');
    setLoading(true);
    try {
      const filePayload = uploadedFile ? { data: uploadedFile.data, mimeType: uploadedFile.mimeType } : undefined;
      const analysis = await analyzeBloomTaxonomy(textToAnalyze, filePayload);
      setBloomAnalysis(analysis);
      setSelectedSkills(analysis.currentSkills);
      setCustomSkills([]);
      setStep(2);
      setMaxReachedStep(Math.max(maxReachedStep, 2));
    } catch (error) {
      console.error(error);
      alert('שגיאה בניתוח המטלה. אנא נסה שנית.');
    } finally {
      setLoading(false);
    }
  };

  const handleSkillToggle = (skill: Skill) => {
    setSelectedSkills(prev => 
      prev.some(s => s.name === skill.name) ? prev.filter(s => s.name !== skill.name) : [...prev, skill]
    );
  };

  const handleAddCustomSkill = (newSkill: Skill) => {
    setCustomSkills(prev => [...prev, newSkill]);
    setSelectedSkills(prev => [...prev, newSkill]);
  };

  const handleGetInitialStrategies = async () => {
    if (selectedSkills.length === 0) return;
    setLoading(true);
    try {
      const res = await generateAssessmentStrategies(selectedSkills, numStudents);
      setStrategies(res.map((s: any) => ({ ...s, userSelectedCategory: s.type, userSelectedMethod: s.method })));
      setStep(3);
      setMaxReachedStep(Math.max(maxReachedStep, 3));
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const updateStrategySelection = (index: number, category: 'FaceToFace' | 'Submission', method?: string) => {
    const newStrategies = [...strategies];
    newStrategies[index] = { ...newStrategies[index], userSelectedCategory: category, userSelectedMethod: method || '' };
    setStrategies(newStrategies);
  };

  const moveSkillToGroup = (skillName: string, targetGroupId: string) => {
    const newStrategies = strategies.map(s => {
      const remainingSkills = s.skills.filter(sk => sk !== skillName);
      if (s.id === targetGroupId) return { ...s, skills: [...s.skills.filter(sk => sk !== skillName), skillName] };
      return { ...s, skills: remainingSkills };
    }).filter(s => s.skills.length > 0);
    setStrategies(newStrategies);
  };

  const addNewGroup = (skillName: string, isDefense: boolean = false) => {
    const updatedOldGroups = strategies.map(s => ({ ...s, skills: s.skills.filter(sk => sk !== skillName) })).filter(s => s.skills.length > 0);
    const newGroup: AssessmentMethod = {
      id: `group-${Date.now()}`,
      skills: skillName === 'כללי' ? ['הגנה על העבודה (Defense)'] : [skillName],
      method: isDefense ? 'בחינה אישית בע"פ' : '',
      type: 'FaceToFace',
      explanation: isDefense ? 'אימות למידה וזהות המגיש (Defense) - מומלץ במיוחד במטלות המותרות לביצוע עם AI.' : 'קבוצה חדשה.',
      userSelectedCategory: 'FaceToFace',
      userSelectedMethod: isDefense ? 'בחינה אישית בע"פ' : ''
    };
    setStrategies([...updatedOldGroups, newGroup]);
  };

  const handleFinalRephrase = async () => {
    if (!strategies.every(s => s.userSelectedMethod)) return;
    setLoading(true);
    try {
      const { sections, practicalTips } = await rephraseAssignment(assignmentText, selectedSkills, strategies, numStudents);
      setRevisedSections(sections.map(s => ({ ...s, status: 'pending', isEditing: false })));
      setPracticalTips(practicalTips);
      setStep(4);
      setMaxReachedStep(Math.max(maxReachedStep, 4));
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleFollowUp = async (question: string) => {
    setChatHistory(prev => [...prev, { role: 'user', text: question }]);
    setLoading(true);
    try {
      const response = await askFollowUpQuestion({ originalText: assignmentText, revisedTask: revisedSections, strategies }, question, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: response || '' }]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const resetToHome = () => {
    setMode('HOME');
    setStep(1);
    setMaxReachedStep(1);
    setAssignmentText('');
    setUploadedFile(null);
    setBloomAnalysis(null);
    setCustomSkills([]);
    setSelectedSkills([]);
    setStrategies([]);
    setRevisedSections([]);
    setPracticalTips('');
    setChatHistory([]);
  };

  const handleGoBack = () => {
    setStep(prev => prev > 1 ? prev - 1 : prev);
    if (step === 1) setMode('HOME');
  };

  const updateSectionStatus = (index: number, status: 'approved' | 'removed') => {
    const newSections = [...revisedSections];
    newSections[index].status = status;
    setRevisedSections(newSections);
  };

  const updateSectionContent = (index: number, content: string) => {
    const newSections = [...revisedSections];
    newSections[index].content = content;
    setRevisedSections(newSections);
  };

  const toggleSectionEdit = (index: number) => {
    const newSections = [...revisedSections];
    newSections[index].isEditing = !newSections[index].isEditing;
    setRevisedSections(newSections);
  };

  const goToStep = (targetStep: number) => {
    if (targetStep <= maxReachedStep) {
      setStep(targetStep);
    }
  };

  return (
    <Layout title={mode === 'HOME' ? 'Re-Assess' : 'עיצוב מחדש'} onBack={mode !== 'HOME' ? handleGoBack : undefined}>
      <style>{`
        .animate-fade-in { animation: fadeIn 0.4s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
        .skill-btn { transition: all 0.2s; }
        .skill-btn:hover { transform: translateY(-1px); box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
        .font-sans-normal { font-style: normal !important; font-family: 'Assistant', sans-serif; }
        .editor-textarea {
          font-family: 'Assistant', sans-serif;
          line-height: 1.625;
          font-size: 1.125rem;
          color: #1f2937;
        }
      `}</style>

      {mode === 'HOME' && (
        <div className="flex flex-col items-center gap-8 py-12">
          <div className="text-center space-y-4">
            <h2 className="text-4xl font-bold text-gray-800">איך המטלה שלך נראית בעידן ה-AI?</h2>
            <p className="text-xl text-gray-600 max-w-2xl">שיפור פדגוגיה ועידוד למידה משמעותית באמצעות עיצוב מחדש של דרכי הערכה.</p>
          </div>

          <div className="bg-amber-50 p-6 rounded-xl border border-amber-200 max-w-3xl w-full text-amber-900 shadow-sm">
            <h3 className="flex items-center gap-2 font-bold text-lg mb-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
              טיפ חשוב לפני שמתחילים
            </h3>
            <p className="leading-relaxed">
              לפני שתיגש לעיצוב מחדש, אנו ממליצים מאוד לקחת את המטלה הנוכחית שלך ולנסות לפתור אותה בעצמך באמצעות כלי AI (כמו ChatGPT, Claude, או Gemini). בדיקה זו תאפשר לך לראות במו עיניך באיזו מידה ניתן לקבל תשובה טובה ובכך לעזור לך לתכנן אם ואלו חלקים דורשים עיצוב מחדש, בנוסף כדאי לחשוב איזה ידע ומיומניות נדרשים כדי לשפר את תשובת הבינה ולשקול להכניס אותם לתוך תוכנית הלימודים.
            </p>
          </div>

          <div className="w-full max-w-md">
            <button onClick={() => { setMode('REDESIGN'); setStep(1); }} className="w-full bg-white border-2 border-green-100 p-8 rounded-2xl shadow-sm hover:shadow-md hover:border-green-400 text-center group transition-all">
              <div className="bg-green-50 w-16 h-16 rounded-full flex items-center justify-center mb-4 mx-auto group-hover:bg-green-600 group-hover:text-white transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">התחל עיצוב למידה מחדש</h3>
              <p className="text-gray-600">נתח מיומנויות ושדרג את המערך הפדגוגי לליווי מיטבי של הסטודנטים.</p>
            </button>
          </div>
        </div>
      )}

      {mode === 'REDESIGN' && (
        <div className="space-y-6 animate-fade-in">
          <Stepper currentStep={step} onStepClick={goToStep} maxReachedStep={maxReachedStep} />

          {step === 1 && (
            <StepInput
              assignmentText={assignmentText}
              setAssignmentText={setAssignmentText}
              uploadedFile={uploadedFile}
              onFileUpload={handleFileUpload}
              numStudents={numStudents}
              setNumStudents={setNumStudents}
              onNext={() => startRedesign()}
              loading={loading}
            />
          )}

          {step === 2 && bloomAnalysis && (
            <StepSkillsAnalysis
              bloomAnalysis={bloomAnalysis}
              selectedSkills={selectedSkills}
              handleSkillToggle={handleSkillToggle}
              customSkills={customSkills}
              onAddCustomSkill={handleAddCustomSkill}
              onNext={handleGetInitialStrategies}
              onBack={handleGoBack}
              loading={loading}
            />
          )}

          {step === 3 && strategies.length > 0 && (
            <StepStrategyBuilder
              strategies={strategies}
              numStudents={numStudents}
              updateStrategySelection={updateStrategySelection}
              moveSkillToGroup={moveSkillToGroup}
              addNewGroup={addNewGroup}
              onNext={handleFinalRephrase}
              onBack={handleGoBack}
              loading={loading}
            />
          )}

          {step === 4 && (
            <StepFinalResult
              revisedSections={revisedSections}
              practicalTips={practicalTips}
              updateSectionStatus={updateSectionStatus}
              updateSectionContent={updateSectionContent}
              toggleSectionEdit={toggleSectionEdit}
              chatHistory={chatHistory}
              onFollowUp={handleFollowUp}
              onReset={resetToHome}
              onBack={handleGoBack}
              loading={loading}
            />
          )}
        </div>
      )}

      {loading && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-md flex items-center justify-center z-50">
          <div className="bg-white p-12 rounded-3xl shadow-2xl flex flex-col items-center gap-8 border-2 border-indigo-100 animate-pulse">
            <div className="w-20 h-20 border-8 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <div className="text-center"><p className="font-bold text-2xl text-indigo-900 mb-2">מעבד פדגוגיה...</p></div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { BloomLevel, Skill, AssessmentMethod } from "../types";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

// NOTE: testAiAssignment function removed as per requirements to remove that mode.

export const analyzeBloomTaxonomy = async (assignmentText: string, fileData?: { data: string, mimeType: string }) => {
  const parts: any[] = [];

  // Add file if it exists
  if (fileData) {
    parts.push({
      inlineData: {
        data: fileData.data,
        mimeType: fileData.mimeType
      }
    });
  }

  parts.push({
    text: `נתח את המטלה הבאה לפי הטקסונומיה של בלום. 
    עליך לזהות את המיומנויות הנדרשות במשימה הנוכחית ולהציע הרחבות שיחזקו את הלמידה.

    הנחיות קריטיות לניתוח מיומנויות "זכירה" (Remember):
    בעידן הבינה המלאכותית, פעולות זכירה פשוטות (כמו שליפת עובדות) נעשות בקלות ע"י ה-AI ולכן אינן נחשבות כ"למידה" משמעותית.
    בניתוח שלך, ציין תחת רמת ה"זכירה" אך ורק עוגני ידע קריטיים, עקרונות ליבה, או מושגי יסוד שהסטודנט *חייב* להפנים בזיכרון לטווח ארוך כדי לתפקד בתחום, ואי אפשר להסתמך רק על שליפה חיצונית עבורם.

    המטלה (טקסט ו/או קובץ מצורף): ${assignmentText}`
  });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          currentSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          },
          suggestedSkills: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                bloomLevel: { type: Type.STRING, enum: Object.values(BloomLevel) },
                reasoning: { type: Type.STRING }
              },
              required: ["name", "bloomLevel", "reasoning"]
            }
          }
        },
        required: ["currentSkills", "suggestedSkills"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateAssessmentStrategies = async (skills: Skill[], numStudents: number) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `עבור רשימת המיומנויות הבאה וכיתה של ${numStudents} סטודנטים, בנה תהליך הערכה המורכב מ-2 עד 3 חלקים (קבוצות הערכה).

    עליך להפעיל שיקול דעת פדגוגי בקביעת סדר החלקים (Sequence):
    הימנע מתבנית קבועה. שקול כל מקרה לגופו:
    - דפוס 1 (Inquiry First): להתחיל במטלת יצירה/חקר (Submission) ורק לאחר מכן לבצע הגנה או בדיקה (FaceToFace). זה מתאים מאוד למטלות מורכבות בעידן ה-AI.
    - דפוס 2 (Foundations First): להתחיל בבדיקת ידע בסיסי (FaceToFace) ורק לאחר מכן לאפשר יישום בבית (Submission).

    עליך לבחור את הסדר הנכון ביותר עבור המיומנויות הספציפיות הללו.

    כללים פדגוגיים להמלצה:
    1. קדם תהליך למידה משמעותי המשלב דרישה להתייחסות לתכנים ספציפיים שנלמדו בשיעור.
    2. התחשב בגודל הכיתה (${numStudents} סטודנטים) בבחירת השיטה.
    3. הסבר בבהירות מדוע בחרת בסדר הזה (למשל: "התחלנו ב-Submission כדי לאפשר עומק, ואנו מסיימים ב-FaceToFace כדי לאמת מקוריות").

    שיטות זמינות:
    FaceToFace (הערכה בסביבה מבוקרת): מבחן כתוב, בוחן ממוחשב, בחינה בע"פ, שאלות ידע בשיעור, הצגת תוצר, הערכת דיון, כתיבה בכיתה, הערכה מדגמית.
    Submission (הערכה בסביבה פתוחה): כתיבת משימה עם AI, משוב על תוצר AI, הערכת עמיתים, הערכה עצמית, סימולציה עם AI, יומן רפלקציה, תיעוד שלבי העבודה.

    המיומנויות שנבחרו: ${JSON.stringify(skills)}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            skills: { type: Type.ARRAY, items: { type: Type.STRING } },
            method: { type: Type.STRING, description: "השיטה הספציפית המומלצת מתוך הרשימה" },
            type: { type: Type.STRING, enum: ['FaceToFace', 'Submission'] },
            explanation: { type: Type.STRING, description: "הסבר פדגוגי: נמק את בחירת השיטה ואת מיקומה ברצף ההערכה." }
          },
          required: ["skills", "method", "type", "explanation"]
        }
      }
    }
  });

  const res = JSON.parse(response.text);
  return res.map((item: any, index: number) => ({
    ...item,
    id: `group-${index}-${Date.now()}`
  }));
};

export interface TaskSection {
  title: string;
  content: string;
  audience: 'student' | 'lecturer';
}

export interface RephrasedResult {
  sections: TaskSection[];
  practicalTips: string;
}

export interface RubricRow {
  criterion: string;
  excellent: string;
  good: string;
  needsImprovement: string;
}

export const rephraseAssignment = async (originalText: string, targetSkills: Skill[], strategies: AssessmentMethod[], numStudents: number) => {
  const labelsMap = {
    FaceToFace: 'הערכה בסביבה מבוקרת',
    Submission: 'הערכה בסביבה פתוחה'
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `נסח מחדש את המטלה המקורית למטלה אקדמית מעודכנת. המטרה היא יצירת "משימת הערכה" שלמה ומפורטת.

    כללים מבניים חובה:
    1. עבור הסטודנטים (sections): חלק את ההנחיות לפרקים נפרדים עבור כל אחד ממרכיבי המטלה.
       עבור כל אסטרטגיה ברשימה להלן, צור אובייקט TaskSection נפרד (audience: 'student') עם כותרת בפורמט: "חלק [מספר]: [שיטת ההערכה]".
       כל חלק כזה חייב להסביר לסטודנט בדיוק מה עליו לעשות ובאילו מיומנויות הוא משתמש.
    2. עבור המרצה (sections): צור לפחות 2 פרקים נפרדים (audience: 'lecturer'):
       א. "שיקולי דעת פדגוגיים" - הסבר מדוע נבחרו השיטות הללו.
       ב. "הנחיות לוגיסטיות ודגשים לבדיקה" - כיצד לבצע את ההערכה בפועל עבור ${numStudents} סטודנטים.
    3. סיכום האסטרטגיות (practicalTips): בסעיף זה כתוב סיכום קצר ובהיר של האסטרטגיות שנבחרו, וכיצד הן משרתות את המיומנויות שנבחרו בתהליך העיצוב (למשל: "נבחרה אסטרטגיה של הגנה בע"פ כדי לוודא זכירה של מושגי יסוד..."). התמקד בבחירות החדשות שנעשו.

    דגש על אותנטיות ופרסונליזציה:
    אם זה רלוונטי למשימה, הוסף בהנחיות לסטודנט דרישה מפורשת לקשר את התוכן לניסיון אישי, דוגמאות מהסביבה הקרובה, או ניתוח מקרה אקטואלי/מקומי - כדי להקשות על יצירת תשובה גנרית ע"י AI.

    נתונים לשילוב:
    ${strategies.map((s, idx) => `- אסטרטגיה ${idx + 1}: מיומנויות [${s.skills.join(', ')}] בשיטת "${s.userSelectedMethod}" (סוג: ${labelsMap[s.userSelectedCategory as keyof typeof labelsMap]}).`).join('\n')}

    מטלה מקורית: ${originalText}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                content: { type: Type.STRING },
                audience: { type: Type.STRING, enum: ['student', 'lecturer'] }
              },
              required: ["title", "content", "audience"]
            }
          },
          practicalTips: { type: Type.STRING, description: "Summary of strategies and chosen skills" }
        },
        required: ["sections", "practicalTips"]
      }
    }
  });
  return JSON.parse(response.text) as RephrasedResult;
};

export const askFollowUpQuestion = async (
  context: { originalText: string, revisedTask: TaskSection[], strategies: AssessmentMethod[] },
  question: string,
  history: { role: 'user' | 'model', text: string }[]
) => {
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `אתה עוזר פדגוגי מומחה. התמקד בחיבור לתוכן שנלמד בשיעור ובשיטות הערכה מגוונות.`,
    }
  });
  const response = await chat.sendMessage({ message: question });
  return response.text;
};

export const generateRubric = async (revisedSections: TaskSection[]) => {
  const studentInstructions = revisedSections
    .filter(s => s.audience === 'student')
    .map(s => s.content)
    .join('\n');

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `צור מחוון הערכה (Rubric) מלא עבור המטלה הבאה.
    הקריטריונים צריכים לכלול היבטים כמו: איכות התוכן, חשיבה ביקורתית, שימוש מושכל ב-AI (אם רלוונטי), איכות הפרזנטציה/כתיבה, ורפלקציה.
    עבור כל קריטריון, נסח את התיאור עבור שלוש רמות ביצוע: מצטיין, עובר (טוב), וטעון שיפור.

    תוכן המטלה:
    ${studentInstructions}
    `,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            criterion: { type: Type.STRING, description: "שם הקריטריון" },
            excellent: { type: Type.STRING, description: "תיאור ביצוע מצטיין" },
            good: { type: Type.STRING, description: "תיאור ביצוע עובר/טוב" },
            needsImprovement: { type: Type.STRING, description: "תיאור ביצוע טעון שיפור" }
          },
          required: ["criterion", "excellent", "good", "needsImprovement"]
        }
      }
    }
  });
  return JSON.parse(response.text) as RubricRow[];
};

import React, { useState } from 'react';
import { AssessmentMethod } from '../types';
import { InfoBox } from './InfoBox';

const CATEGORIZED_OPTIONS = {
  FaceToFace: [
    'מבחן כתוב בכיתה',
    'בוחן ממוחשב קצר בכיתה',
    'בחינה אישית בע"פ',
    'שאלות ידע מהירות בשיעור',
    'הצגת תוצר קבוצתי',
    'הערכת דיון קבוצתי',
    'כתיבה והגשת עבודה בכיתה',
    'הערכה מדגמית'
  ],
  Submission: [
    'כתיבת משימה עם AI',
    'משוב על תוצר AI',
    'הערכת עמיתים',
    'הערכה עצמית',
    'סימולציה שפותחה עם AI',
    'יומן רפלקציה',
    'תיעוד שלבי העבודה'
  ],
  Defense: [
    'בחינה אישית בע"פ',
    'הערכה מדגמית',
    'שאלות לקבוצת המגישים בכיתה'
  ]
};

interface StepStrategyBuilderProps {
  strategies: AssessmentMethod[];
  numStudents: number;
  updateStrategySelection: (index: number, category: 'FaceToFace' | 'Submission', method?: string) => void;
  moveSkillToGroup: (skillName: string, targetGroupId: string) => void;
  addNewGroup: (skillName: string, isDefense?: boolean) => void;
  onNext: () => void;
  onBack: () => void;
  loading: boolean;
}

const StepStrategyBuilder: React.FC<StepStrategyBuilderProps> = ({
  strategies, numStudents, updateStrategySelection, moveSkillToGroup, addNewGroup, onNext, onBack, loading
}) => {
  const [inspectedSkill, setInspectedSkill] = useState<{name: string, groupIdx: number} | null>(null);

  const shouldShowDefenseSuggestion = (idx: number, strat: AssessmentMethod) => {
    // Show defense suggestion if this is the last item and it is a submission
    const isLast = idx === strategies.length - 1;
    const isAiSubmission = strat.userSelectedCategory === 'Submission';
    const hasRoomForMore = strategies.length < 3;
    return isLast && isAiSubmission && hasRoomForMore;
  };

  return (
    <div className="space-y-6 animate-fade-in pb-12">
      <div className="bg-white p-8 rounded-2xl shadow-xl border-t-8 border-indigo-600 relative">
        <InfoBox title="בניית תהליך ההערכה">
          לפניך הצעה לרצף הערכה המותאם למיומנויות שבחרת.
          העוזר הפדגוגי סידר את החלקים בסדר לוגי (למשל: ידע לפני יישום, או יצירה לפני הגנה), אך יש לך שליטה מלאה לשנות את השיטות והסדר.
        </InfoBox>

        <div className="flex justify-between items-center mb-6">
          <div>
            <h3 className="text-2xl font-bold text-indigo-900">רצף ההערכה המוצע</h3>
            <p className="text-gray-600">התאם את הקבוצות לפי שיקול דעתך. העוזר מתחשב ב-{numStudents} סטודנטים.</p>
          </div>
          <button onClick={() => addNewGroup('מיומנות חדשה')} className="bg-green-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-green-700 transition-all shadow-md">+ הוסף חלק</button>
        </div>
        <div className="space-y-8">
          {strategies.map((strat, idx) => (
            <div key={strat.id} className="p-6 rounded-2xl bg-gray-50 border-2 border-indigo-100 shadow-sm relative overflow-hidden">
              <div className="absolute top-0 right-0 bg-indigo-100 text-indigo-800 px-4 py-1 rounded-bl-xl font-bold text-sm">
                 חלק {idx + 1} בתהליך
              </div>
              <h4 className="text-sm font-bold text-indigo-400 mb-3 mt-4 uppercase">קבוצת מיומנויות</h4>
              <div className="flex flex-wrap gap-3 mb-6">
                {strat.skills.map((s, i) => (
                  <button key={i} onClick={() => setInspectedSkill({name: s, groupIdx: idx})} className={`skill-btn flex items-center bg-white text-indigo-900 border-2 border-indigo-200 text-sm px-4 py-2 rounded-xl font-bold shadow-sm ${inspectedSkill?.name === s ? 'ring-4 ring-indigo-400' : ''}`}>{s}</button>
                ))}
              </div>
              {inspectedSkill && inspectedSkill.groupIdx === idx && (
                <div className="mb-6 p-5 bg-white rounded-xl border-2 border-indigo-500 shadow-lg animate-fade-in">
                  <div className="flex justify-between items-start mb-4">
                    <h5 className="font-bold text-lg text-indigo-900">{inspectedSkill.name}</h5>
                    <button onClick={() => setInspectedSkill(null)} className="text-gray-400 hover:text-gray-600">✕</button>
                  </div>
                  <div className="flex flex-wrap gap-2 pt-4 border-t">
                    <span className="text-xs font-bold text-gray-400 w-full mb-1">העבר לחלק:</span>
                    {strategies.map((target, tIdx) => target.id !== strat.id && <button key={target.id} onClick={() => { moveSkillToGroup(inspectedSkill.name, target.id); setInspectedSkill(null); }} className="bg-indigo-50 text-indigo-700 text-xs px-3 py-1.5 rounded-lg hover:bg-indigo-600 hover:text-white">חלק {tIdx + 1}</button>)}
                    <button onClick={() => { addNewGroup(inspectedSkill.name); setInspectedSkill(null); }} className="bg-green-50 text-green-700 text-xs px-3 py-1.5 rounded-lg hover:bg-green-600 hover:text-white">+ חלק חדש</button>
                  </div>
                </div>
              )}
              <div className="grid md:grid-cols-2 gap-8 pt-4 border-t">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3">סוג הערכה:</label>
                  <div className="flex gap-4">
                    <button onClick={() => updateStrategySelection(idx, 'FaceToFace')} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all ${strat.userSelectedCategory === 'FaceToFace' ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border-gray-100 hover:border-indigo-200'}`}>הערכה בסביבה מבוקרת</button>
                    <button onClick={() => updateStrategySelection(idx, 'Submission')} className={`flex-1 py-4 rounded-xl font-bold border-2 transition-all ${strat.userSelectedCategory === 'Submission' ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border-gray-100 hover:border-indigo-200'}`}>הערכה בסביבה פתוחה</button>
                  </div>
                </div>
                {strat.userSelectedCategory && (
                  <div className="animate-fade-in">
                    <label className="block text-sm font-bold text-gray-700 mb-3">בחירת שיטה:</label>
                    <select 
                      value={strat.userSelectedMethod} 
                      onChange={(e) => updateStrategySelection(idx, strat.userSelectedCategory!, e.target.value)} 
                      className="w-full p-4 border-2 border-indigo-200 rounded-xl bg-white outline-none focus:border-indigo-500 font-medium text-gray-800 shadow-sm appearance-none"
                    >
                      <option value="">-- בחר שיטה --</option>
                      {(() => {
                        const baseOptions = CATEGORIZED_OPTIONS[strat.userSelectedCategory];
                        const defenseOptions = strat.userSelectedCategory === 'FaceToFace' ? CATEGORIZED_OPTIONS.Defense : [];
                        const combined = Array.from(new Set([...baseOptions, ...defenseOptions]));
                        return combined.map(opt => (
                          <option key={opt} value={opt}>
                            {opt === strat.method ? `${opt} (מומלץ)` : opt}
                          </option>
                        ));
                      })()}
                    </select>
                    <div className="mt-3 bg-blue-50 border border-blue-100 p-3 rounded-lg">
                        <p className="text-xs font-bold text-blue-800 mb-1">רציונל פדגוגי לשיטה ולמיקום ברצף:</p>
                        <p className="text-sm text-blue-900 leading-relaxed">{strat.explanation}</p>
                    </div>
                    {shouldShowDefenseSuggestion(idx, strat) && (
                      <button onClick={() => addNewGroup('כללי', true)} className="mt-3 w-full text-xs bg-amber-50 text-amber-700 border border-amber-200 p-2 rounded-lg font-bold hover:bg-amber-100 shadow-sm transition-colors">+ הצעה: הוספת שלב הגנה (Defense) בסיום התהליך</button>
                    )}
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
        <div className="flex gap-4 mt-12 pt-8 border-t">
          <button onClick={onBack} className="px-10 py-4 border-2 rounded-xl font-bold hover:bg-gray-50 transition-all">חזור</button>
          <button onClick={onNext} disabled={loading} className="flex-1 bg-green-600 text-white py-4 rounded-xl font-bold text-xl shadow-xl hover:bg-green-700 transition-all">צור מטלה וסיכום למידה</button>
        </div>
      </div>
    </div>
  );
};

export default StepStrategyBuilder;
